import { getCurrentUser } from '@/lib/auth'

const HTML = "<!DOCTYPE html><html lang=\"ja\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"><title>NULE - 配車管理</title>  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    :root {\n      --nav-bg: #1e2433;\n      --accent: #4f7ef8;\n      --accent-hover: #3a67e0;\n      --success: #27ae60;\n      --danger: #e74c3c;\n      --warning: #e67e22;\n      --body-bg: #f2f4f8;\n      --card-bg: #ffffff;\n      --text: #1a1d27;\n      --text-sub: #6b7280;\n      --border: #e5e8ef;\n      --radius: 10px;\n    }\n\n    body {\n      font-family: -apple-system, 'Helvetica Neue', Arial, sans-serif;\n      background: var(--body-bg);\n      color: var(--text);\n      display: flex;\n      flex-direction: column;\n      height: 100vh;\n      overflow: hidden;\n    }\n\n    /* ===== トップナビ ===== */\n    .topnav {\n      background: var(--nav-bg);\n      display: flex;\n      align-items: center;\n      gap: 0;\n      padding: 0 12px;\n      height: 52px;\n      flex-shrink: 0;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.18);\n      overflow-x: auto;\n    }\n    .topnav::-webkit-scrollbar { display: none; }\n\n    .topnav-logo {\n      display: flex;\n      align-items: center;\n      gap: 6px;\n      margin-right: 16px;\n      white-space: nowrap;\n      flex-shrink: 0;\n    }\n    .topnav-logo .icon { font-size: 18px; }\n    .topnav-logo .name { font-size: 13px; font-weight: 700; color: #fff; letter-spacing: 0.3px; }\n\n    .nav-item {\n      display: flex;\n      align-items: center;\n      gap: 5px;\n      padding: 0 10px;\n      height: 52px;\n      cursor: pointer;\n      color: #8fa0b8;\n      font-size: 12.5px;\n      font-weight: 500;\n      transition: background 0.15s, color 0.15s;\n      border: none;\n      background: none;\n      white-space: nowrap;\n      border-bottom: 3px solid transparent;\n      flex-shrink: 0;\n    }\n    .nav-item:hover { color: #c8d4e8; background: rgba(255,255,255,0.05); }\n    .nav-item.active { color: #fff; border-bottom-color: var(--accent); }\n    .nav-item .nav-icon { font-size: 14px; }\n\n    /* ===== メインエリア ===== */\n    .main {\n      flex: 1;\n      overflow-y: auto;\n      padding: 28px 32px;\n    }\n\n    .page { display: none; }\n    .page.active { display: block; }\n\n    .page-header {\n      margin-bottom: 24px;\n    }\n    .page-header h1 {\n      font-size: 22px;\n      font-weight: 700;\n      color: var(--text);\n    }\n    .page-header p {\n      font-size: 13px;\n      color: var(--text-sub);\n      margin-top: 4px;\n    }\n\n    /* ===== カード ===== */\n    .card {\n      background: var(--card-bg);\n      border-radius: var(--radius);\n      border: 1px solid var(--border);\n      padding: 24px;\n      margin-bottom: 20px;\n    }\n    .card-header {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      margin-bottom: 18px;\n    }\n    .card-title {\n      font-size: 15px;\n      font-weight: 600;\n      color: var(--text);\n    }\n\n    /* ===== 統計 ===== */\n    .stats-grid {\n      display: grid;\n      grid-template-columns: repeat(5, 1fr);\n      gap: 16px;\n      margin-bottom: 20px;\n    }\n    .stat-card {\n      background: var(--card-bg);\n      border: 1px solid var(--border);\n      border-radius: var(--radius);\n      padding: 20px;\n    }\n    .stat-label { font-size: 12px; color: var(--text-sub); font-weight: 500; margin-bottom: 8px; }\n    .stat-value { font-size: 28px; font-weight: 700; color: var(--text); }\n    .stat-sub { font-size: 12px; color: var(--text-sub); margin-top: 4px; }\n    .stat-dot {\n      display: inline-block;\n      width: 8px; height: 8px;\n      border-radius: 50%;\n      margin-right: 4px;\n    }\n\n    /* ===== テーブル ===== */\n    .table-wrap { overflow-x: auto; }\n    table { width: 100%; border-collapse: collapse; font-size: 13.5px; }\n    thead tr { border-bottom: 1px solid var(--border); }\n    th {\n      text-align: left;\n      padding: 9px 14px;\n      font-size: 11px;\n      font-weight: 700;\n      color: var(--text-sub);\n      text-transform: uppercase;\n      letter-spacing: 0.5px;\n      white-space: nowrap;\n    }\n    td {\n      padding: 13px 14px;\n      border-bottom: 1px solid #f2f4f8;\n      vertical-align: middle;\n      color: var(--text);\n    }\n    tbody tr:last-child td { border-bottom: none; }\n    tbody tr:hover td { background: #f9fafc; }\n    .col-actions { display: flex; gap: 6px; }\n    .empty-row td { text-align: center; color: var(--text-sub); padding: 48px; font-size: 13px; }\n\n    /* ===== バッジ ===== */\n    .badge {\n      display: inline-flex;\n      align-items: center;\n      gap: 4px;\n      padding: 3px 9px;\n      border-radius: 20px;\n      font-size: 12px;\n      font-weight: 600;\n    }\n    .badge-blue   { background: #eff4ff; color: #2563eb; }\n    .badge-gray   { background: #f3f4f6; color: #6b7280; }\n    .badge-green  { background: #ecfdf5; color: #059669; }\n    .badge-red    { background: #fef2f2; color: #dc2626; }\n    .badge-orange { background: #fff7ed; color: #ea580c; }\n\n    /* ===== ボタン ===== */\n    .btn {\n      display: inline-flex;\n      align-items: center;\n      gap: 6px;\n      padding: 8px 16px;\n      border: none;\n      border-radius: 7px;\n      font-size: 13px;\n      font-weight: 600;\n      cursor: pointer;\n      transition: background 0.15s, transform 0.1s;\n      white-space: nowrap;\n    }\n    .btn:active { transform: scale(0.97); }\n    .btn-primary { background: var(--accent); color: #fff; }\n    .btn-primary:hover { background: var(--accent-hover); }\n    .btn-success { background: var(--success); color: #fff; }\n    .btn-success:hover { background: #1e9450; }\n    .btn-danger  { background: var(--danger); color: #fff; }\n    .btn-danger:hover  { background: #c0392b; }\n    .btn-ghost {\n      background: none;\n      color: var(--text-sub);\n      border: 1px solid var(--border);\n    }\n    .btn-ghost:hover { background: #f2f4f8; color: var(--text); }\n    .btn-sm { padding: 5px 11px; font-size: 12px; }\n    .btn-group { display: flex; gap: 10px; flex-wrap: wrap; }\n\n    /* ===== フォーム ===== */\n    .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }\n    .form-full { grid-column: 1 / -1; }\n    .form-group { display: flex; flex-direction: column; gap: 5px; }\n    .form-group label { font-size: 12px; font-weight: 600; color: var(--text-sub); }\n    .form-group input,\n    .form-group select {\n      border: 1px solid var(--border);\n      border-radius: 7px;\n      padding: 9px 12px;\n      font-size: 14px;\n      color: var(--text);\n      outline: none;\n      background: #fff;\n      transition: border-color 0.15s, box-shadow 0.15s;\n    }\n    .form-group input:focus,\n    .form-group select:focus {\n      border-color: var(--accent);\n      box-shadow: 0 0 0 3px rgba(79,126,248,0.12);\n    }\n    .form-sep { grid-column: 1 / -1; border: none; border-top: 1px solid var(--border); margin: 4px 0; }\n\n    /* ===== モーダル ===== */\n    .modal-overlay {\n      display: none;\n      position: fixed; inset: 0;\n      background: rgba(10,15,30,0.5);\n      z-index: 200;\n      align-items: center;\n      justify-content: center;\n      backdrop-filter: blur(2px);\n    }\n    .modal-overlay.open { display: flex; }\n    .modal {\n      background: #fff;\n      border-radius: 14px;\n      padding: 28px;\n      width: 560px;\n      max-width: 95vw;\n      max-height: 90vh;\n      overflow-y: auto;\n      box-shadow: 0 20px 60px rgba(0,0,0,0.18);\n    }\n    .modal-head {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      margin-bottom: 22px;\n    }\n    .modal-head h3 { font-size: 17px; font-weight: 700; }\n    .modal-close {\n      background: none; border: none; cursor: pointer;\n      font-size: 20px; color: var(--text-sub); line-height: 1;\n      padding: 2px 6px; border-radius: 5px;\n    }\n    .modal-close:hover { background: var(--border); }\n    .modal-footer {\n      display: flex;\n      justify-content: flex-end;\n      gap: 10px;\n      margin-top: 24px;\n      padding-top: 18px;\n      border-top: 1px solid var(--border);\n    }\n\n    /* ===== 荷物リスト ===== */\n    .cargo-section { grid-column: 1 / -1; }\n    .cargo-type-row { display: flex; gap: 10px; align-items: center; margin-bottom: 10px; }\n    .cargo-type-row label { font-size: 12px; font-weight: 600; color: var(--text-sub); white-space: nowrap; }\n    .cargo-list { display: flex; flex-direction: column; gap: 6px; margin-bottom: 8px; }\n    .cargo-item {\n      display: flex; align-items: center; gap: 8px;\n      background: #f8faff; border: 1px solid #dce7fd;\n      border-radius: 7px; padding: 8px 10px;\n    }\n    .cargo-item .cargo-num { font-size: 12px; color: var(--text-sub); min-width: 28px; }\n    .cargo-item input {\n      border: 1px solid var(--border); border-radius: 5px;\n      padding: 6px 8px; font-size: 13px; outline: none;\n      transition: border-color 0.15s;\n    }\n    .cargo-item input:focus { border-color: var(--accent); }\n    .cargo-item .inp-name { flex: 2; }\n    .cargo-item .inp-weight { width: 90px; text-align: right; }\n    .cargo-item .cargo-del { background: none; border: none; color: #cbd5e1; cursor: pointer; font-size: 16px; padding: 0 2px; line-height: 1; }\n    .cargo-item .cargo-del:hover { color: var(--danger); }\n    .cargo-total { display: flex; justify-content: flex-end; align-items: center; gap: 8px; font-size: 13px; color: var(--text-sub); padding-right: 4px; }\n    .cargo-total strong { font-size: 16px; color: var(--accent); }\n    .btn-add-cargo { display: inline-flex; align-items: center; gap: 4px; font-size: 13px; padding: 6px 12px; }\n\n    /* ===== パターン提案 ===== */\n    .suggest-box {\n      display: none;\n      background: #fffbeb;\n      border: 1px solid #fcd34d;\n      border-radius: 8px;\n      padding: 12px 14px;\n      font-size: 13px;\n      grid-column: 1 / -1;\n    }\n    .suggest-box.show { display: block; }\n    .suggest-box .suggest-title {\n      font-size: 11px; font-weight: 700; color: #92400e;\n      text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px;\n    }\n    .suggest-list { display: flex; flex-direction: column; gap: 6px; }\n    .suggest-item {\n      display: flex; align-items: center; justify-content: space-between;\n      padding: 8px 10px; border-radius: 6px;\n      background: #fff; border: 1px solid #fde68a; cursor: pointer;\n      transition: background 0.15s;\n    }\n    .suggest-item:hover { background: #fef3c7; }\n    .suggest-item .s-info { font-size: 13px; font-weight: 600; }\n    .suggest-item .s-count { font-size: 11px; color: #92400e; background: #fde68a; padding: 2px 7px; border-radius: 10px; }\n\n    /* ===== 空き候補 ===== */\n    .avail-section { margin-top: 8px; }\n    .avail-section h4 { font-size: 12px; font-weight: 700; color: var(--text-sub); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px; }\n    .candidate-list { display: flex; flex-direction: column; gap: 6px; }\n    .candidate-item {\n      display: flex; align-items: center;\n      padding: 10px 12px; border-radius: 8px;\n      border: 1px solid var(--border); background: #fafbfc;\n      cursor: pointer; transition: border-color 0.15s, background 0.15s;\n    }\n    .candidate-item:hover { border-color: var(--accent); background: #eff4ff; }\n    .candidate-item.selected { border-color: var(--accent); background: #eff4ff; }\n    .candidate-item input[type=radio],\n    .candidate-item input[type=checkbox] { width: 15px; height: 15px; margin-right: 10px; cursor: pointer; accent-color: var(--accent); }\n    .c-name { font-size: 13.5px; font-weight: 600; }\n    .c-sub  { font-size: 12px; color: var(--text-sub); margin-top: 1px; }\n    .no-candidate { font-size: 13px; color: var(--text-sub); padding: 12px; text-align: center; background: #fafbfc; border-radius: 8px; border: 1px dashed var(--border); }\n\n    /* ===== 割り振りプレビュー ===== */\n    .alloc-list { display: flex; flex-direction: column; gap: 8px; margin-top: 12px; }\n    .alloc-item {\n      display: flex; align-items: center; gap: 12px;\n      padding: 11px 14px; border-radius: 8px;\n      background: #f7f9ff; border: 1px solid #dce7fd;\n    }\n    .alloc-name { flex: 1; font-size: 13.5px; font-weight: 600; }\n    .alloc-bar-wrap { flex: 2; background: #dce8fb; border-radius: 6px; height: 7px; overflow: hidden; }\n    .alloc-bar { background: var(--accent); height: 7px; border-radius: 6px; transition: width 0.35s; }\n    .alloc-weight { font-size: 13px; font-weight: 700; color: var(--accent); min-width: 48px; text-align: right; }\n    .alloc-warn { color: var(--danger) !important; }\n\n    .section-label {\n      font-size: 11px; font-weight: 700; color: var(--text-sub);\n      text-transform: uppercase; letter-spacing: 0.6px;\n    }\n\n    /* ===== 注意事項 ===== */\n    .caution-box {\n      display: none; grid-column: 1 / -1;\n      background: #fff8f0; border: 1px solid #fed7aa;\n      border-radius: 8px; padding: 10px 14px;\n    }\n    .caution-box.show { display: flex; align-items: flex-start; gap: 10px; }\n    .caution-icon { font-size: 16px; flex-shrink: 0; margin-top: 1px; }\n    .caution-content { flex: 1; }\n    .caution-label { font-size: 11px; font-weight: 700; color: #c2410c; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }\n    .caution-text { font-size: 13px; color: #7c2d12; white-space: pre-wrap; }\n    .caution-edit { font-size: 12px; color: #c2410c; background: none; border: none; cursor: pointer; text-decoration: underline; margin-top: 4px; padding: 0; }\n    /* テーブルの注意アイコン */\n    .caution-badge { display:inline-flex; align-items:center; gap:3px; background:#fff8f0; border:1px solid #fed7aa; border-radius:5px; padding:2px 7px; font-size:11px; color:#c2410c; font-weight:600; cursor:pointer; margin-left:6px; }\n\n    /* ===== 完了トグル ===== */\n    .done-toggle {\n      display: inline-flex; align-items: center; gap: 5px;\n      padding: 4px 10px; border-radius: 20px; font-size: 12px; font-weight: 600;\n      border: none; cursor: pointer; transition: all 0.15s; white-space: nowrap;\n    }\n    .done-toggle.undone { background: #f1f5f9; color: #94a3b8; }\n    .done-toggle.undone:hover { background: #e2e8f0; color: #64748b; }\n    .done-toggle.done { background: #dcfce7; color: #16a34a; }\n    .done-toggle.done:hover { background: #bbf7d0; }\n    tr.done-row td { opacity: 0.5; text-decoration: none; }\n    tr.done-row td strong { font-weight: 500; }\n\n    /* ===== 完了済みセクション ===== */\n    .completed-section { margin-top: 24px; }\n    .completed-header {\n      display: flex; align-items: center; gap: 10px;\n      cursor: pointer; padding: 12px 0; user-select: none;\n    }\n    .completed-header h3 { font-size: 14px; font-weight: 600; color: var(--text-sub); }\n    .completed-header .toggle-icon { color: var(--text-sub); font-size: 12px; transition: transform 0.2s; }\n    .completed-header.open .toggle-icon { transform: rotate(90deg); }\n\n    /* ===== インライン割り当てセル ===== */\n    .assign-cell { min-width: 140px; }\n    .assign-select {\n      width: 100%;\n      border: 1px solid var(--border);\n      border-radius: 6px;\n      padding: 5px 8px;\n      font-size: 13px;\n      color: var(--text);\n      background: #fff;\n      cursor: pointer;\n      outline: none;\n      transition: border-color 0.15s;\n    }\n    .assign-select:focus { border-color: var(--accent); }\n    .assign-select.unassigned {\n      color: #aab0be;\n      background: #fafbfc;\n      border-style: dashed;\n    }\n    .badge-unassigned { background: #fff3cd; color: #856404; }\n\n    /* ===== 配車予定表 ===== */\n    .haisha-table { width:100%; border-collapse:collapse; font-size:13px; }\n    .haisha-table th {\n      padding:10px 12px; font-size:11px; font-weight:700; color:var(--text-sub);\n      letter-spacing:0.5px; border-bottom:2px solid var(--border);\n      white-space:nowrap; background:#f9fafc; text-align:left;\n    }\n    .haisha-table td {\n      padding:6px 8px; border-bottom:1px solid var(--border); vertical-align:top;\n    }\n    .haisha-table tbody tr:last-child td { border-bottom:none; }\n    .haisha-table tbody tr:hover td { background:#fafcff; }\n    .haisha-driver-name { font-weight:700; font-size:13px; white-space:nowrap; min-width:70px; }\n    .haisha-vnum { font-size:11px; color:var(--text-sub); white-space:nowrap; min-width:80px; }\n    .haisha-payload { font-weight:600; white-space:nowrap; text-align:right; }\n\n    /* 配達カード */\n    .haisha-card {\n      display:inline-flex; align-items:center; gap:6px;\n      background:#eff4ff; border:1.5px solid #c7d9fd; border-radius:7px;\n      padding:5px 10px; cursor:grab; user-select:none;\n      transition:box-shadow 0.15s, opacity 0.15s, background 0.2s, border-color 0.2s;\n      margin:2px 0; min-width:80px;\n    }\n    .haisha-card:hover { box-shadow:0 2px 8px rgba(79,126,248,0.25); }\n    .haisha-card.dragging { opacity:0.35; cursor:grabbing; }\n    .haisha-card.preloaded { background:#fff3cd; border-color:#ffc107; }\n    /* ステータス別色 */\n    .haisha-card.st-loaded   { background:#dcf5e4; border-color:#4caf82; }\n    .haisha-card.st-delivered{ background:#e0e0e0; border-color:#9e9e9e; opacity:0.72; }\n    /* スケジュール一覧の行背景 */\n    tr.sched-row-loaded   { background:#f0faf4; }\n    tr.sched-row-delivered{ background:#f5f5f5; opacity:0.8; }\n    .haisha-card .c-place { font-weight:600; font-size:13px; }\n    .haisha-card .c-weight { font-size:11px; color:var(--text-sub); margin-left:2px; }\n    .haisha-card .c-status {\n      font-size:10px; font-weight:700; letter-spacing:0.2px;\n      padding:1px 5px; border-radius:4px; white-space:nowrap;\n      cursor:pointer; user-select:none; flex-shrink:0;\n    }\n    .c-status.st-none     { background:#dce9ff; color:#3b62c9; }\n    .c-status.st-loaded   { background:#b7ecd0; color:#1a7a4c; }\n    .c-status.st-delivered{ background:#d0d0d0; color:#555; }\n\n    /* ドロップセル */\n    .haisha-drop-cell {\n      min-width:110px; min-height:36px; border-radius:6px;\n      transition:background 0.12s, border 0.12s;\n      padding:4px 6px;\n    }\n    .haisha-drop-cell.drag-over {\n      background:#e8f0fe !important;\n      outline:2px dashed var(--accent);\n    }\n\n    /* 未割当プール */\n    .haisha-pool {\n      display:flex; flex-wrap:wrap; gap:8px;\n      min-height:48px; padding:10px; border-radius:8px;\n      border:2px dashed var(--border);\n    }\n    .haisha-pool.drag-over { border-color:var(--accent); background:#e8f0fe; }\n    .haisha-pool-empty { font-size:13px; color:var(--text-sub); padding:4px; }\n\n    /* 車両セレクト */\n    .haisha-vsel {\n      width:100%; border:1px solid var(--border); border-radius:6px;\n      padding:5px 8px; font-size:12px; color:var(--text);\n      background:#fff; cursor:pointer; outline:none;\n      transition:border-color 0.15s;\n    }\n    .haisha-vsel:focus { border-color:var(--accent); }\n    .haisha-vsel option[value=\"\"] { color:#aaa; }\n\n    /* ✂️ 分割モーダル */\n    .split-pool {\n      min-height:44px; display:flex; flex-wrap:wrap; gap:6px;\n      padding:10px; border:2px dashed var(--border); border-radius:8px;\n      background:#fafbfc;\n    }\n    .split-pool.split-drag-over { border-color:var(--accent); background:#eff4ff; }\n    .split-group-box {\n      border:1.5px solid var(--border); border-radius:8px;\n      padding:10px; margin-bottom:10px; background:#fff;\n    }\n    .split-group-header {\n      display:flex; align-items:center; gap:8px; margin-bottom:8px;\n    }\n    .split-group-label { font-size:12px; font-weight:700; color:var(--accent); }\n    .split-group-total { font-size:12px; color:var(--text-sub); }\n    .split-group-drop {\n      min-height:36px; display:flex; flex-wrap:wrap; gap:6px;\n      padding:8px; border:2px dashed #dce7fd; border-radius:6px;\n      background:#f8fbff;\n    }\n    .split-group-drop.split-drag-over { border-color:var(--accent); background:#eff4ff; }\n    .split-chip {\n      display:inline-flex; align-items:center; gap:5px;\n      background:#eff4ff; border:1.5px solid #c7d9fd; border-radius:6px;\n      padding:4px 10px; cursor:grab; user-select:none; font-size:13px;\n    }\n    .split-chip:hover { box-shadow:0 2px 6px rgba(79,126,248,0.2); }\n    .split-chip.dragging { opacity:0.35; }\n    .split-chip .chip-name { font-weight:600; }\n    .split-chip .chip-weight { color:var(--text-sub); font-size:11px; }\n    .split-chip .chip-del { background:none;border:none;color:#aaa;cursor:pointer;font-size:14px;line-height:1;padding:0 0 0 2px; }\n    .split-chip .chip-del:hover { color:var(--danger); }\n\n    /* スロット番号ラベル */\n    .slot-label {\n      display:block; font-size:10px; font-weight:700; color:#c0c8d8;\n      letter-spacing:0.3px; margin-bottom:2px; user-select:none;\n    }\n    .haisha-drop-cell.drag-over .slot-label { color:var(--accent); }\n\n    /* インライン入力（空き行用） */\n    .haisha-inp {\n      border:none; border-bottom:1.5px dashed #d0d5e0;\n      outline:none; background:transparent;\n      font-size:13px; font-family:inherit;\n      width:100%; padding:2px 4px; color:var(--text);\n    }\n    .haisha-inp:focus { border-bottom-color:var(--accent); background:#f5f8ff; border-radius:3px 3px 0 0; }\n    .haisha-inp::placeholder { color:#bbb; font-size:12px; }\n\n    /* 履歴編集カード・入力フィールド */\n    .hd-inp {\n      border:none; border-bottom:1.5px dashed #d0d5e0;\n      outline:none; background:transparent;\n      font-size:13px; font-family:inherit;\n      width:100%; padding:2px 4px; color:var(--text);\n    }\n    .hd-inp:focus { border-bottom-color:var(--accent); background:#f5f8ff; border-radius:3px 3px 0 0; }\n    .hd-card {\n      display:flex; align-items:center; gap:4px;\n      background:#fff; border:1.5px solid #d0d5e0; border-radius:8px;\n      padding:4px 8px; margin-bottom:4px; cursor:grab; font-size:12px;\n    }\n    .hd-card:hover { border-color:var(--accent); box-shadow:0 1px 4px rgba(79,126,248,0.2); }\n    .hd-card.dragging { opacity:0.35; cursor:grabbing; }\n    .hd-card-inp {\n      border:none; outline:none; background:transparent;\n      font-size:12px; font-family:inherit; color:var(--text);\n      flex:1; min-width:0;\n    }\n    .hd-card-inp:focus { background:#f5f8ff; border-radius:3px; }\n\n    /* 配車予定表コントロール */\n    .haisha-controls {\n      display:flex; align-items:center; gap:16px; flex-wrap:wrap;\n    }\n    .haisha-controls .form-group { margin:0; }\n    /* NULE Dark Theme */\n    :root { --nav-bg:#0f0f0f!important;--body-bg:#0a0a0a!important;--card-bg:#111!important;--text:#f5f5f5!important;--text-sub:#888!important;--border:#333!important;--success:#22c55e!important;--danger:#ef4444!important;--warning:#f59e0b!important; }\n    body{background:#0a0a0a!important;color:#f5f5f5!important}.topnav{background:#0f0f0f!important}\n    .card,.stat-card{background:#111!important;border-color:#333!important}.modal{background:#1a1a1a!important;color:#f5f5f5!important}\n    .form-group input,.form-group select,.form-group textarea{background:#1a1a1a!important;color:#f5f5f5!important;border-color:#444!important}\n    table td{border-bottom-color:#333!important}tbody tr:hover td{background:#1a1a1a!important}\n    .haisha-table th{background:#111!important}.haisha-table tbody tr:hover td{background:#1a1a1a!important}\n    .badge-blue{background:rgba(79,126,248,.15)!important;color:#6d9fff!important}.badge-green{background:rgba(34,197,94,.15)!important;color:#4ade80!important}\n    .badge-red{background:rgba(239,68,68,.15)!important;color:#f87171!important}.badge-orange{background:rgba(245,158,11,.15)!important;color:#fbbf24!important}\n    .badge-gray{background:rgba(136,136,136,.15)!important;color:#aaa!important}\n    .btn-ghost{border-color:#444!important}.btn-ghost:hover{background:#2a2a2a!important}\n    .haisha-pool{border-color:#444!important}.haisha-drop-cell.drag-over{background:rgba(79,126,248,.1)!important}\n    .empty-row td{color:#888!important}.modal-overlay{background:rgba(0,0,0,.6)!important}\n    .haisha-card{background:rgba(79,126,248,.12)!important;border-color:rgba(79,126,248,.3)!important}\n    .haisha-card.preloaded{background:rgba(245,158,11,.12)!important;border-color:rgba(245,158,11,.4)!important}\n    .haisha-card.st-loaded{background:rgba(34,197,94,.12)!important;border-color:rgba(34,197,94,.4)!important}\n    .haisha-card.st-delivered{background:rgba(136,136,136,.12)!important;border-color:rgba(136,136,136,.3)!important}\n    .candidate-item{background:#1a1a1a!important;border-color:#444!important}\n    .split-pool,.split-group-drop{background:#1a1a1a!important;border-color:#444!important}\n    .haisha-inp{color:#f5f5f5!important;border-bottom-color:#555!important}.haisha-inp:focus{background:#222!important}\n    .suggest-box{background:rgba(245,158,11,.08)!important;border-color:rgba(245,158,11,.3)!important}\n    .caution-box{background:rgba(245,158,11,.08)!important;border-color:rgba(245,158,11,.25)!important}\n    .no-candidate{background:#1a1a1a!important;border-color:#444!important}\n    .haisha-inp::placeholder{color:#555!important}\n    .hd-inp{border-bottom-color:#555!important;color:#f5f5f5!important}\n    .hd-inp:focus{background:#222!important}\n    .hd-card{background:#1a1a1a!important;border-color:#555!important}\n    .assign-select{background:#1a1a1a!important;color:#f5f5f5!important;border-color:#444!important}\n    .assign-select.unassigned{background:#111!important;color:#666!important}\n    .haisha-vsel{background:#1a1a1a!important;color:#f5f5f5!important;border-color:#444!important}\n    .split-chip{background:rgba(79,126,248,.12)!important;border-color:rgba(79,126,248,.3)!important;color:#f5f5f5!important}\n    .badge-unassigned{background:rgba(245,158,11,.15)!important;color:#fbbf24!important}\n    .done-toggle.undone{background:#333!important;color:#888!important}\n    .done-toggle.done{background:rgba(34,197,94,.15)!important;color:#4ade80!important}\n    .alloc-item{background:rgba(79,126,248,.05)!important;border-color:rgba(79,126,248,.2)!important}\n    .alloc-bar-wrap{background:#333!important}\n    .cargo-item{background:#1a1a1a!important;border-color:#444!important}\n    .cargo-item input{background:#222!important;color:#f5f5f5!important;border-color:#444!important}\n    select option{background:#1a1a1a;color:#f5f5f5}\n    .completed-header h3{color:#888!important}\n    tr.sched-row-loaded{background:rgba(34,197,94,.05)!important}\n    tr.sched-row-delivered{background:rgba(136,136,136,.05)!important}\n    .haisha-card .c-place{color:#f5f5f5!important}\n    .haisha-card .c-weight{color:#aaa!important}\n    .c-status.st-none{background:rgba(79,126,248,.2)!important;color:#93b5ff!important}\n    .c-status.st-loaded{background:rgba(34,197,94,.2)!important;color:#4ade80!important}\n    .c-status.st-delivered{background:rgba(136,136,136,.2)!important;color:#aaa!important}\n    .suggest-item{background:#1a1a1a!important;border-color:#555!important;color:#f5f5f5!important}\n    .suggest-item:hover{background:#2a2a2a!important}\n    .suggest-item .s-info{color:#f5f5f5!important}\n    .suggest-item .s-count{background:rgba(245,158,11,.2)!important;color:#fbbf24!important}\n    .suggest-box .suggest-title{color:#fbbf24!important}\n    .candidate-item:hover{background:rgba(79,126,248,.1)!important}\n    .candidate-item.selected{background:rgba(79,126,248,.1)!important}\n  </style>\n</head><body>\n\n<!-- ===== トップナビ ===== -->\n<nav class=\"topnav\">\n  <div class=\"topnav-logo\">\n    <span class=\"icon\">🚛</span>\n    <span class=\"name\">配車管理</span>\n  </div>\n  <button class=\"nav-item active\" onclick=\"switchPage('dashboard')\">\n    <span class=\"nav-icon\">📊</span> ダッシュボード\n  </button>\n  <button class=\"nav-item\" onclick=\"switchPage('schedules')\">\n    <span class=\"nav-icon\">📅</span> 配車スケジュール\n  </button>\n  <button class=\"nav-item\" onclick=\"switchPage('vehicles')\">\n    <span class=\"nav-icon\">🚛</span> 車両管理\n  </button>\n  <button class=\"nav-item\" onclick=\"switchPage('drivers')\">\n    <span class=\"nav-icon\">👤</span> ドライバー管理\n  </button>\n  <button class=\"nav-item\" onclick=\"switchPage('places')\">\n    <span class=\"nav-icon\">📍</span> 場所・注意事項\n  </button>\n  <button class=\"nav-item\" onclick=\"switchPage('haisha')\">\n    <span class=\"nav-icon\">📋</span> 配車予定表\n  </button>\n</nav>\n\n<!-- ===== メインコンテンツ ===== -->\n<main class=\"main\" style=\"width:100%\">\n\n  <!-- ダッシュボード -->\n  <div id=\"page-dashboard\" class=\"page active\">\n    <div class=\"page-header\" style=\"display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px\">\n      <div>\n        <h1>週間カレンダー</h1>\n        <p>配達予定の一週間ビュー</p>\n      </div>\n      <div style=\"display:flex;align-items:center;gap:8px\">\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"dashWeekOffset--;renderDashboard()\">◀ 前週</button>\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"dashWeekOffset=0;renderDashboard()\">今週</button>\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"dashWeekOffset++;renderDashboard()\">次週 ▶</button>\n      </div>\n    </div>\n    <div id=\"dash-week-label\" style=\"text-align:center;font-size:13px;color:var(--text-sub);margin-bottom:12px\"></div>\n    <div id=\"dash-calendar\" style=\"display:grid;grid-template-columns:repeat(7,1fr);gap:8px\"></div>\n  </div>\n\n  <!-- 配車スケジュール -->\n  <div id=\"page-schedules\" class=\"page\">\n    <div class=\"page-header\">\n      <h1>配車スケジュール</h1>\n    </div>\n    <div class=\"card\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">スケジュール一覧</span>\n        <div class=\"btn-group\">\n          <button class=\"btn btn-ghost btn-sm\" onclick=\"openModal('schedule')\">＋ 1件追加</button>\n          <button class=\"btn btn-primary btn-sm\" onclick=\"openModal('bulk')\">📦 まとめて配車</button>\n        </div>\n      </div>\n      <!-- 日付フィルター -->\n      <div style=\"display:flex;align-items:center;gap:10px;padding:10px 16px;border-bottom:1px solid var(--border);background:#f8fafc;flex-wrap:wrap\">\n        <span style=\"font-size:13px;font-weight:600;color:var(--text-sub)\">📅 日付で絞り込み</span>\n        <input type=\"date\" id=\"filter-date\"\n          oninput=\"renderSchedules()\"\n          style=\"border:1px solid var(--border);border-radius:6px;padding:5px 10px;font-size:13px;outline:none\">\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"document.getElementById('filter-date').value='';renderSchedules()\">クリア</button>\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"document.getElementById('filter-date').value=new Date().toISOString().slice(0,10);renderSchedules()\">今日</button>\n      </div>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>状態</th><th>荷主</th><th>積み込み日</th><th>積み込み場所</th><th>下ろし日</th><th>下ろし場所</th><th>重量</th><th>車両</th><th>ドライバー</th><th>メモ</th><th></th></tr></thead>\n          <tbody id=\"sched-tbody\"><tr class=\"empty-row\"><td colspan=\"10\">データがありません</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n\n    <!-- 完了済みセクション -->\n    <div class=\"completed-section\">\n      <div class=\"completed-header\" onclick=\"toggleCompleted(this)\">\n        <span class=\"toggle-icon\">▶</span>\n        <h3>✅ 完了済み <span id=\"completed-count\" style=\"font-weight:400;font-size:13px\"></span></h3>\n      </div>\n      <div id=\"completed-body\" style=\"display:none\">\n        <div class=\"card\" style=\"margin-top:0\">\n          <div class=\"table-wrap\">\n            <table>\n              <thead><tr><th>状態</th><th>荷主</th><th>積み込み日</th><th>積み込み場所</th><th>下ろし日</th><th>下ろし場所</th><th>重量</th><th>車両</th><th>ドライバー</th><th>メモ</th><th></th></tr></thead>\n              <tbody id=\"completed-tbody\"><tr class=\"empty-row\"><td colspan=\"10\">データがありません</td></tr></tbody>\n            </table>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- 車両管理 -->\n  <div id=\"page-vehicles\" class=\"page\">\n    <div class=\"page-header\">\n      <h1>車両管理</h1>\n    </div>\n    <div class=\"card\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">車両一覧</span>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"openModal('vehicle')\">＋ 車両を追加</button>\n      </div>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>種別</th><th>ナンバー（ヘッド）</th><th>台車ナンバー</th><th>最大積載量</th><th>メモ</th><th></th></tr></thead>\n          <tbody id=\"vehicle-tbody\"><tr class=\"empty-row\"><td colspan=\"6\">データがありません</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n  </div>\n\n  <!-- ドライバー管理 -->\n  <div id=\"page-drivers\" class=\"page\">\n    <div class=\"page-header\">\n      <h1>ドライバー管理</h1>\n    </div>\n    <div class=\"card\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">ドライバー一覧</span>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"openModal('driver')\">＋ ドライバーを追加</button>\n      </div>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>氏名</th><th>連絡先</th><th>稼働状況</th><th>配車表示</th><th>メモ</th><th></th></tr></thead>\n          <tbody id=\"driver-tbody\"><tr class=\"empty-row\"><td colspan=\"7\">データがありません</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n  </div>\n\n  <!-- 場所・注意事項管理 -->\n  <div id=\"page-places\" class=\"page\">\n    <div class=\"page-header\">\n      <h1>場所・注意事項</h1>\n    </div>\n    <!-- 積み地一覧 -->\n    <div class=\"card\" style=\"margin-bottom:16px\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">積み地一覧</span>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"openAddLoadPlace()\">＋ 積み地を追加</button>\n      </div>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>場所名</th><th></th></tr></thead>\n          <tbody id=\"load-places-tbody\"><tr class=\"empty-row\"><td colspan=\"2\">登録された積み地がありません</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n    <div class=\"card\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">下ろし先一覧</span>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"openNewPlaceModal()\">＋ 場所を追加</button>\n      </div>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>場所名</th><th>注意事項</th><th></th></tr></thead>\n          <tbody id=\"places-tbody\"><tr class=\"empty-row\"><td colspan=\"3\">データがありません</td></tr></tbody>\n        </table>\n      </div>\n    </div>\n    <!-- スケジュールに登録されている場所（まだ注意事項なし）-->\n    <div class=\"card\" style=\"margin-top:16px\">\n      <div class=\"card-header\">\n        <span class=\"card-title\">スケジュール登録済みの場所（注意事項なし）</span>\n        <span style=\"font-size:12px;color:var(--text-sub)\">クリックで注意事項を追加できます</span>\n      </div>\n      <div id=\"places-from-schedules\" style=\"display:flex;flex-wrap:wrap;gap:8px;padding:14px 16px\"></div>\n    </div>\n  </div>\n\n  <!-- 配車履歴モーダル -->\n  <div id=\"plan-history-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:400;align-items:flex-start;justify-content:center;padding-top:60px\"\n       onclick=\"if(event.target===this)closePlanHistory()\">\n    <div style=\"background:#1a1a1a;color:#f5f5f5;border-radius:14px;padding:28px;width:700px;max-width:95vw;max-height:80vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,0.2)\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:20px\">\n        <strong style=\"font-size:17px\">📂 配車予定表 履歴</strong>\n        <button onclick=\"closePlanHistory()\" style=\"background:none;border:none;font-size:22px;cursor:pointer;color:#666\">×</button>\n      </div>\n      <div id=\"plan-history-list\"></div>\n    </div>\n  </div>\n\n  <!-- 分割モーダル -->\n  <div id=\"split-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:600;align-items:center;justify-content:center\"\n       onclick=\"if(event.target===this)closeSplit()\">\n    <div style=\"background:#1a1a1a;color:#f5f5f5;border-radius:14px;padding:28px;width:520px;max-width:96vw;max-height:88vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,0.2)\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:6px\">\n        <strong style=\"font-size:16px\">✂️ 配達分割</strong>\n        <button onclick=\"closeSplit()\" style=\"background:none;border:none;font-size:22px;cursor:pointer;color:#666\">×</button>\n      </div>\n      <p style=\"font-size:13px;color:var(--text-sub);margin-bottom:18px\">荷物をグループ分けして、それぞれ別の配達スケジュールに分割します</p>\n\n      <!-- 元スケジュール情報 -->\n      <div id=\"split-origin-info\" style=\"background:#f5f7fa;border-radius:8px;padding:12px 14px;margin-bottom:18px;font-size:13px\"></div>\n\n      <!-- 荷物リスト（ドラッグ可能） -->\n      <div style=\"margin-bottom:16px\">\n        <div style=\"font-size:11px;font-weight:700;color:var(--text-sub);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px\">荷物一覧（ドラッグでグループ移動）</div>\n        <div id=\"split-items-pool\" class=\"split-pool\"\n             ondragover=\"event.preventDefault();this.classList.add('split-drag-over')\"\n             ondragleave=\"this.classList.remove('split-drag-over')\"\n             ondrop=\"splitDropToPool(event)\"></div>\n      </div>\n\n      <!-- グループ（配達①②③…） -->\n      <div style=\"font-size:11px;font-weight:700;color:var(--text-sub);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px\">配達グループ</div>\n      <div id=\"split-groups\"></div>\n      <button class=\"btn btn-ghost btn-sm\" onclick=\"addSplitGroup()\" style=\"margin-top:8px\">＋ グループを追加</button>\n\n      <div style=\"display:flex;justify-content:flex-end;gap:10px;margin-top:24px;padding-top:18px;border-top:1px solid var(--border)\">\n        <button class=\"btn btn-ghost\" onclick=\"closeSplit()\">キャンセル</button>\n        <button class=\"btn btn-primary\" onclick=\"confirmSplit()\">✅ この分割で登録</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- 配車履歴 詳細モーダル -->\n  <div id=\"plan-detail-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:500;align-items:flex-start;justify-content:center;padding-top:40px\"\n       onclick=\"if(event.target===this)closePlanDetail()\">\n    <div style=\"background:#1a1a1a;color:#f5f5f5;border-radius:14px;padding:28px;width:1100px;max-width:97vw;max-height:88vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,0.25)\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:20px\">\n        <strong id=\"plan-detail-title\" style=\"font-size:17px\"></strong>\n        <button onclick=\"closePlanDetail()\" style=\"background:none;border:none;font-size:22px;cursor:pointer;color:#666\">×</button>\n      </div>\n      <div id=\"plan-detail-content\"></div>\n    </div>\n  </div>\n\n  <!-- 荷物詳細ポップアップ -->\n  <div id=\"card-detail-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:600;align-items:center;justify-content:center\"\n       onclick=\"if(event.target===this)closeCardDetail()\">\n    <div id=\"card-detail-box\" style=\"background:#1a1a1a;color:#f5f5f5;border-radius:14px;padding:28px 32px;width:420px;max-width:95vw;box-shadow:0 20px 60px rgba(0,0,0,0.25);position:relative\">\n      <button onclick=\"closeCardDetail()\" style=\"position:absolute;top:14px;right:16px;background:none;border:none;font-size:22px;cursor:pointer;color:#aaa\">×</button>\n      <div id=\"card-detail-content\"></div>\n    </div>\n  </div>\n\n  <!-- ドライバーピッカー（配車予定表用） -->\n  <div id=\"dpicker-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:300;align-items:center;justify-content:center\"\n       onclick=\"if(event.target===this)closeDriverPicker()\">\n    <div style=\"background:#1a1a1a;border-radius:12px;padding:20px 24px;width:320px;color:#f5f5f5;box-shadow:0 12px 40px rgba(0,0,0,0.18)\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:16px\">\n        <strong style=\"font-size:15px\">ドライバーを選択</strong>\n        <button onclick=\"closeDriverPicker()\" style=\"background:none;border:none;font-size:20px;cursor:pointer;color:#666\">×</button>\n      </div>\n      <select id=\"dpicker-select\" style=\"width:100%;border:1px solid #444;border-radius:7px;padding:10px 12px;font-size:14px;outline:none;background:#1a1a1a;color:#f5f5f5\">\n        <option value=\"\">— 未選択 —</option>\n      </select>\n      <div style=\"display:flex;justify-content:flex-end;gap:10px;margin-top:16px\">\n        <button class=\"btn btn-ghost\" onclick=\"closeDriverPicker()\">キャンセル</button>\n        <button class=\"btn btn-primary\" onclick=\"applyDriverPicker()\">決定</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- 車両ピッカー（配車予定表用） -->\n  <div id=\"vpicker-overlay\" style=\"display:none;position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:300;align-items:center;justify-content:center\"\n       onclick=\"if(event.target===this)closeVehiclePicker()\">\n    <div style=\"background:#1a1a1a;border-radius:12px;padding:20px 24px;width:320px;color:#f5f5f5;box-shadow:0 12px 40px rgba(0,0,0,0.18)\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:16px\">\n        <strong style=\"font-size:15px\">車両を選択</strong>\n        <button onclick=\"closeVehiclePicker()\" style=\"background:none;border:none;font-size:20px;cursor:pointer;color:#666\">×</button>\n      </div>\n      <select id=\"vpicker-select\" style=\"width:100%;border:1px solid #444;border-radius:7px;padding:10px 12px;font-size:14px;outline:none;background:#1a1a1a;color:#f5f5f5\">\n        <option value=\"\">— 未選択 —</option>\n      </select>\n      <div style=\"display:flex;justify-content:flex-end;gap:10px;margin-top:16px\">\n        <button class=\"btn btn-ghost\" onclick=\"closeVehiclePicker()\">キャンセル</button>\n        <button class=\"btn btn-primary\" onclick=\"applyVehiclePicker()\">決定</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- ===== 配車予定表 ===== -->\n  <div id=\"page-haisha\" class=\"page\">\n    <div class=\"page-header\">\n      <h1>📋 配車予定表</h1>\n      <p>日付を選んで自動振り分け・ドラッグ&amp;ドロップで調整</p>\n    </div>\n\n    <!-- コントロール -->\n    <div class=\"card\" style=\"padding:16px 24px;margin-bottom:16px\">\n      <div class=\"haisha-controls\">\n        <div class=\"form-group\" style=\"flex-direction:row;align-items:center;gap:10px\">\n          <label style=\"font-size:12px;font-weight:600;color:var(--text-sub);white-space:nowrap\">対象日</label>\n          <input type=\"date\" id=\"haisha-date\" style=\"border:1px solid var(--border);border-radius:7px;padding:8px 12px;font-size:14px;outline:none;\" onchange=\"renderHaisha()\">\n        </div>\n        <button class=\"btn btn-primary\" onclick=\"autoAssignHaisha()\">⚡ 自動振り分け</button>\n        <button class=\"btn btn-ghost\" onclick=\"openSpotModal()\" title=\"非表示ドライバーをこの日だけ一時表示\">👤 スポット追加</button>\n        <button class=\"btn btn-success\" onclick=\"saveDispatchPlan()\">💾 この日の配車を保存</button>\n        <button class=\"btn btn-ghost\" onclick=\"openPlanHistory()\">📂 履歴</button>\n      </div>\n    </div>\n\n    <!-- 未割当プール -->\n    <div id=\"haisha-unassigned-wrap\" class=\"card\" style=\"display:none;margin-bottom:16px\">\n      <div class=\"card-header\" style=\"margin-bottom:12px\">\n        <span class=\"card-title\">⚠️ 未割当の仕事</span>\n        <span style=\"font-size:12px;color:var(--text-sub)\">ドライバー行にドロップして割り当て</span>\n      </div>\n      <div id=\"haisha-pool\"\n           class=\"haisha-pool\"\n           ondragover=\"event.preventDefault();this.classList.add('drag-over')\"\n           ondragleave=\"this.classList.remove('drag-over')\"\n           ondrop=\"dropToPool(event)\">\n        <span class=\"haisha-pool-empty\">なし</span>\n      </div>\n    </div>\n\n    <!-- 配車テーブル -->\n    <div class=\"card\" style=\"padding:0;overflow:hidden\">\n      <div class=\"table-wrap\">\n        <table class=\"haisha-table\">\n          <thead>\n            <tr>\n              <th>運転手</th>\n              <th>車番</th>\n              <th style=\"text-align:right\">積載量</th>\n              <th>積置き分</th>\n              <th>配達①</th>\n              <th>配達②</th>\n              <th>配達③</th>\n              <th>配達④</th>\n              <th>配達⑤</th>\n              <th>備考</th>\n            </tr>\n          </thead>\n          <tbody id=\"haisha-tbody\">\n            <tr class=\"empty-row\"><td colspan=\"9\">日付を選択してください</td></tr>\n          </tbody>\n        </table>\n      </div>\n    </div>\n  </div>\n\n</main>\n\n<!-- ===== 注意事項編集モーダル ===== -->\n<div class=\"modal-overlay\" id=\"modal-place\">\n  <div class=\"modal\" style=\"width:480px\">\n    <div class=\"modal-head\">\n      <h3>⚠️ 注意事項の編集</h3>\n      <button class=\"modal-close\" onclick=\"closeModal('place')\">×</button>\n    </div>\n    <div class=\"form-grid\">\n      <div class=\"form-group form-full\">\n        <label>場所名</label>\n        <input id=\"place-name\" readonly style=\"background:#f8fafc;color:#888\">\n      </div>\n      <div class=\"form-group form-full\">\n        <label>注意事項</label>\n        <textarea id=\"place-caution\" rows=\"5\"\n          style=\"border:1px solid var(--border);border-radius:7px;padding:9px 12px;font-size:14px;outline:none;resize:vertical;font-family:inherit;transition:border-color 0.15s\"\n          placeholder=\"例：8時以降入場不可、要事前連絡など\"></textarea>\n      </div>\n    </div>\n    <div class=\"modal-footer\">\n      <button class=\"btn btn-ghost\" onclick=\"closeModal('place')\">キャンセル</button>\n      <button class=\"btn btn-primary\" onclick=\"savePlace()\">保存する</button>\n    </div>\n  </div>\n</div>\n\n<!-- ===== 車両モーダル ===== -->\n<div class=\"modal-overlay\" id=\"modal-vehicle\">\n  <div class=\"modal\">\n    <div class=\"modal-head\">\n      <h3 id=\"v-modal-title\">車両を追加</h3>\n      <button class=\"modal-close\" onclick=\"closeModal('vehicle')\">×</button>\n    </div>\n    <div class=\"form-grid\">\n      <div class=\"form-group form-full\">\n        <label>種別</label>\n        <select id=\"v-kind\" onchange=\"onVehicleKindChange()\">\n          <option value=\"トラック\">トラック</option>\n          <option value=\"トレーラー\">トレーラー</option>\n        </select>\n      </div>\n      <div class=\"form-group form-full\" id=\"v-number-group\">\n        <label>ナンバープレート</label>\n        <input id=\"v-number\" placeholder=\"品川 100 あ 1234\">\n      </div>\n      <div class=\"form-group\" id=\"v-head-group\" style=\"display:none\">\n        <label>ヘッドナンバー</label>\n        <input id=\"v-head\" placeholder=\"品川 100 あ 1234\">\n      </div>\n      <div class=\"form-group\" id=\"v-trailer-group\" style=\"display:none\">\n        <label>台車ナンバー</label>\n        <input id=\"v-trailer\" placeholder=\"品川 800 あ 1234\">\n      </div>\n      <div class=\"form-group\">\n        <label>最大積載量（kg）</label>\n        <input id=\"v-payload\" type=\"number\" step=\"1\" min=\"0\" placeholder=\"10000\">\n      </div>\n      <div class=\"form-group\">\n        <label>メモ</label>\n        <input id=\"v-note\" placeholder=\"任意のメモ\">\n      </div>\n    </div>\n    <div class=\"modal-footer\">\n      <button class=\"btn btn-ghost\" onclick=\"closeModal('vehicle')\">キャンセル</button>\n      <button class=\"btn btn-primary\" onclick=\"saveVehicle()\">保存する</button>\n    </div>\n  </div>\n</div>\n\n<!-- ===== ドライバーモーダル ===== -->\n<div class=\"modal-overlay\" id=\"modal-driver\">\n  <div class=\"modal\">\n    <div class=\"modal-head\">\n      <h3 id=\"d-modal-title\">ドライバーを追加</h3>\n      <button class=\"modal-close\" onclick=\"closeModal('driver')\">×</button>\n    </div>\n    <div class=\"form-grid\">\n      <div class=\"form-group\"><label>氏名</label><input id=\"d-name\" placeholder=\"山田 太郎\"></div>\n      <div class=\"form-group\"><label>連絡先</label><input id=\"d-phone\" placeholder=\"090-0000-0000\"></div>\n      <div class=\"form-group\">\n        <label>稼働状況</label>\n        <select id=\"d-status\">\n          <option value=\"稼働中\">稼働中</option>\n          <option value=\"休暇中\">休暇中</option>\n          <option value=\"退職\">退職</option>\n        </select>\n      </div>\n      <div class=\"form-group form-full\"><label>メモ</label><input id=\"d-note\" placeholder=\"任意のメモ\"></div>\n    </div>\n    <div class=\"modal-footer\">\n      <button class=\"btn btn-ghost\" onclick=\"closeModal('driver')\">キャンセル</button>\n      <button class=\"btn btn-primary\" onclick=\"saveDriver()\">保存する</button>\n    </div>\n  </div>\n</div>\n\n<!-- ===== スケジュール（1件）モーダル ===== -->\n<div class=\"modal-overlay\" id=\"modal-schedule\">\n  <div class=\"modal\">\n    <div class=\"modal-head\">\n      <h3 id=\"s-modal-title\">配車を追加</h3>\n      <div style=\"display:flex;align-items:center;gap:8px\">\n        <button id=\"aitsu-toggle-btn\" type=\"button\"\n          onclick=\"toggleAitsumi()\"\n          style=\"font-size:12px;font-weight:700;padding:4px 12px;border-radius:20px;border:1.5px solid #555;background:#1a1a1a;color:#888;cursor:pointer\">\n          🔀 相積み\n        </button>\n        <button class=\"modal-close\" onclick=\"closeModal('schedule')\">×</button>\n      </div>\n    </div>\n    <datalist id=\"dl-load-places\"></datalist>\n    <datalist id=\"dl-unload-places\"></datalist>\n    <datalist id=\"dl-cargo-types\">\n      <option value=\"コイル\">\n      <option value=\"亜鉛コイル\">\n      <option value=\"矢板\">\n      <option value=\"特丸\">\n      <option value=\"SC\">\n      <option value=\"H鋼\">\n      <option value=\"タルク\">\n    </datalist>\n\n    <!-- 通常モード -->\n    <div id=\"s-normal-mode\">\n    <div class=\"form-grid\">\n      <div class=\"form-group form-full\"><label>荷主</label>\n        <input id=\"s-client-name\" placeholder=\"荷主名\" autocomplete=\"off\"\n               oninput=\"onClientInput()\">\n      </div>\n      <div class=\"form-group\"><label>積み込み日</label><input id=\"s-load-date\" type=\"date\"></div>\n      <div class=\"form-group\"><label>積み込み場所</label>\n        <input id=\"s-load-place\" placeholder=\"〇〇倉庫\" list=\"dl-load-places\" autocomplete=\"off\"\n               oninput=\"onRouteInput(); filterUnloadByLoadPlace(this.value)\">\n      </div>\n      <div class=\"form-group\"><label>下ろし日</label><input id=\"s-unload-date\" type=\"date\"></div>\n      <div class=\"form-group\"><label>下ろし場所</label>\n        <input id=\"s-unload-place\" placeholder=\"〇〇工場\" list=\"dl-unload-places\" autocomplete=\"off\"\n               oninput=\"onRouteInput(); onUnloadPlaceInput()\">\n      </div>\n\n      <!-- 注意事項ボックス -->\n      <div class=\"caution-box\" id=\"s-caution-box\">\n        <div class=\"caution-icon\">⚠️</div>\n        <div class=\"caution-content\">\n          <div class=\"caution-label\">注意事項</div>\n          <div class=\"caution-text\" id=\"s-caution-text\"></div>\n          <button class=\"caution-edit\" onclick=\"openPlaceEdit()\">編集する</button>\n        </div>\n      </div>\n\n      <!-- 荷物の種類 -->\n      <div class=\"cargo-section\">\n        <div class=\"cargo-type-row\">\n          <label>荷物の種類</label>\n          <input id=\"s-cargo-type\" type=\"text\" list=\"dl-cargo-types\" placeholder=\"コイル・自由入力も可\"\n            oninput=\"onSCargoTypeChange()\"\n            style=\"border:1px solid var(--border);border-radius:7px;padding:7px 10px;font-size:13px;outline:none;flex:1\">\n        </div>\n        <div id=\"s-coil-section\" style=\"display:none\">\n          <div class=\"cargo-list\" id=\"s-coil-list\"></div>\n          <div style=\"display:flex;align-items:center;justify-content:space-between;margin-top:4px\">\n            <button type=\"button\" class=\"btn btn-ghost btn-sm btn-add-cargo\" onclick=\"addSCoil()\">＋ コイルを追加</button>\n            <div class=\"cargo-total\">合計：<strong id=\"s-coil-total\">0</strong> t</div>\n          </div>\n        </div>\n        <div id=\"s-other-cargo-section\" style=\"display:none\">\n          <div class=\"cargo-list\" id=\"s-other-cargo-list\"></div>\n          <div style=\"display:flex;align-items:center;justify-content:space-between;margin-top:4px\">\n            <button type=\"button\" class=\"btn btn-ghost btn-sm btn-add-cargo\" onclick=\"addSOtherCargo()\">＋ 荷物を追加</button>\n            <div class=\"cargo-total\">合計：<strong id=\"s-other-cargo-total\">0</strong> t</div>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"form-group\"><label>重量（kg）<span style=\"font-size:11px;color:var(--accent);margin-left:4px\">↑荷物を入力すると自動入力</span></label><input id=\"s-weight\" type=\"number\" step=\"1\" min=\"0\" placeholder=\"8000\"></div>\n      <div class=\"form-group\"><label>メモ</label><input id=\"s-note\" placeholder=\"任意のメモ\"></div>\n\n      <!-- パターン提案ボックス -->\n      <div class=\"suggest-box\" id=\"suggest-box\">\n        <div class=\"suggest-title\">💡 過去の配車実績から提案</div>\n        <div class=\"suggest-list\" id=\"suggest-list\"></div>\n      </div>\n\n      <hr class=\"form-sep\">\n\n      <div class=\"form-group form-full\" style=\"flex-direction:row; align-items:center; justify-content:space-between;\">\n        <span class=\"section-label\">空き確認</span>\n        <button type=\"button\" class=\"btn btn-ghost btn-sm\" onclick=\"checkAvail()\">🔍 空き確認</button>\n      </div>\n\n      <div id=\"avail-wrap\" class=\"form-full\" style=\"display:none\">\n        <div class=\"avail-section\">\n          <h4>空き車両</h4>\n          <div class=\"candidate-list\" id=\"avail-v-list\"></div>\n        </div>\n        <div class=\"avail-section\" style=\"margin-top:12px\">\n          <h4>空きドライバー</h4>\n          <div class=\"candidate-list\" id=\"avail-d-list\"></div>\n        </div>\n      </div>\n\n      <hr class=\"form-sep\">\n\n      <div class=\"form-group\"><label>車両（任意）</label><select id=\"s-vehicle\"><option value=\"\">-- 選択 --</option></select></div>\n      <div class=\"form-group\"><label>ドライバー（任意）</label><select id=\"s-driver\"><option value=\"\">-- 選択 --</option></select></div>\n    </div>\n    </div><!-- /s-normal-mode -->\n\n    <!-- 相積みモード -->\n    <div id=\"s-aitsu-mode\" style=\"display:none\">\n      <div class=\"form-grid\">\n        <div class=\"form-group form-full\"><label>荷主</label>\n          <input id=\"at-client-name\" placeholder=\"荷主名\" autocomplete=\"off\">\n        </div>\n        <div class=\"form-group\"><label>積み込み日（共通）</label><input id=\"at-load-date\" type=\"date\"></div>\n        <div class=\"form-group\"><label>下ろし日（共通）</label><input id=\"at-unload-date\" type=\"date\"></div>\n        <div class=\"form-group\"><label>車両（任意）</label><select id=\"at-vehicle\"><option value=\"\">-- 選択 --</option></select></div>\n        <div class=\"form-group\"><label>ドライバー（任意）</label><select id=\"at-driver\"><option value=\"\">-- 選択 --</option></select></div>\n      </div>\n      <div style=\"font-size:12px;font-weight:700;color:var(--text-sub);margin:16px 0 8px;text-transform:uppercase;letter-spacing:0.5px\">\n        積み込み・下ろし場所\n      </div>\n      <div id=\"at-rows\"></div>\n      <button type=\"button\" onclick=\"addAitsuRow()\"\n        style=\"width:100%;margin-top:8px;padding:8px;border:1.5px dashed #555;border-radius:8px;background:#1a1a1a;color:#888;font-size:13px;cursor:pointer\">\n        ＋ 行を追加\n      </button>\n    </div><!-- /s-aitsu-mode -->\n\n    <div class=\"modal-footer\">\n      <button class=\"btn btn-ghost\" onclick=\"closeModal('schedule')\">キャンセル</button>\n      <button class=\"btn btn-primary\" id=\"s-save-btn\" onclick=\"saveSchedule()\">保存する</button>\n    </div>\n  </div>\n</div>\n\n<!-- ===== まとめて配車モーダル ===== -->\n<div class=\"modal-overlay\" id=\"modal-bulk\">\n  <div class=\"modal\">\n    <div class=\"modal-head\">\n      <h3>📦 まとめて配車</h3>\n      <button class=\"modal-close\" onclick=\"closeModal('bulk')\">×</button>\n    </div>\n    <div class=\"form-grid\">\n      <div class=\"form-group form-full\"><label>荷主</label>\n        <input id=\"b-client-name\" placeholder=\"荷主名\" autocomplete=\"off\"\n               oninput=\"onClientInputBulk()\">\n      </div>\n      <div class=\"form-group\"><label>積み込み日</label><input id=\"b-load-date\" type=\"date\"></div>\n      <div class=\"form-group\"><label>積み込み場所</label><input id=\"b-load-place\" placeholder=\"〇〇倉庫\" list=\"dl-load-places\" autocomplete=\"off\" oninput=\"filterUnloadByLoadPlace(this.value)\"></div>\n      <div class=\"form-group\"><label>下ろし日</label><input id=\"b-unload-date\" type=\"date\"></div>\n      <div class=\"form-group\"><label>下ろし場所</label><input id=\"b-unload-place\" placeholder=\"〇〇工場\" list=\"dl-unload-places\" autocomplete=\"off\"></div>\n      <!-- 荷物リスト -->\n      <div class=\"cargo-section\">\n        <div class=\"cargo-type-row\">\n          <label>荷物の種類</label>\n          <input id=\"b-cargo-type\" type=\"text\" list=\"dl-cargo-types\" placeholder=\"コイル・自由入力も可\"\n            oninput=\"onCargoTypeChange()\"\n            style=\"border:1px solid var(--border);border-radius:7px;padding:7px 10px;font-size:13px;outline:none;flex:1\">\n        </div>\n\n        <!-- コイル入力リスト -->\n        <div id=\"coil-section\" style=\"display:none\">\n          <div class=\"cargo-list\" id=\"coil-list\"></div>\n          <div style=\"display:flex;align-items:center;justify-content:space-between;margin-top:4px\">\n            <button type=\"button\" class=\"btn btn-ghost btn-sm btn-add-cargo\" onclick=\"addCoil()\">＋ コイルを追加</button>\n            <div class=\"cargo-total\">合計：<strong id=\"coil-total\">0</strong> t</div>\n          </div>\n        </div>\n\n        <!-- その他 -->\n        <div id=\"other-cargo-section\" style=\"display:none\">\n          <div class=\"cargo-list\" id=\"other-cargo-list\"></div>\n          <div style=\"display:flex;align-items:center;justify-content:space-between;margin-top:4px\">\n            <button type=\"button\" class=\"btn btn-ghost btn-sm btn-add-cargo\" onclick=\"addOtherCargo()\">＋ 荷物を追加</button>\n            <div class=\"cargo-total\">合計：<strong id=\"other-cargo-total\">0</strong> t</div>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"form-group\">\n        <label>合計重量（kg）<span style=\"font-size:11px;color:var(--accent);margin-left:4px\">↑荷物を入力すると自動入力</span></label>\n        <input id=\"b-total\" type=\"number\" step=\"1\" min=\"0\" placeholder=\"30000\" oninput=\"updateBulkPreview()\">\n      </div>\n      <div class=\"form-group\"><label>メモ</label><input id=\"b-note\" placeholder=\"任意のメモ\"></div>\n\n      <hr class=\"form-sep\">\n\n      <div class=\"form-group form-full\" style=\"flex-direction:row; align-items:center; justify-content:space-between;\">\n        <span class=\"section-label\">空き車両を選んで割り振る</span>\n        <button type=\"button\" class=\"btn btn-ghost btn-sm\" onclick=\"checkBulkAvail()\">🔍 空き確認</button>\n      </div>\n\n      <div id=\"bulk-v-wrap\" class=\"form-full\" style=\"display:none\">\n        <div class=\"candidate-list\" id=\"bulk-v-list\"></div>\n      </div>\n\n      <div id=\"bulk-preview-wrap\" class=\"form-full\" style=\"display:none\">\n        <div class=\"section-label\" style=\"margin-bottom:8px\">割り振り結果</div>\n        <div class=\"alloc-list\" id=\"bulk-preview\"></div>\n        <p id=\"bulk-warn\" style=\"font-size:12px; color:var(--danger); margin-top:8px;\"></p>\n      </div>\n    </div>\n    <div class=\"modal-footer\">\n      <button class=\"btn btn-ghost\" onclick=\"closeModal('bulk')\">キャンセル</button>\n      <button class=\"btn btn-ghost\" onclick=\"saveBulk(true)\">📋 荷物だけ登録</button>\n      <button class=\"btn btn-success\" onclick=\"saveBulk(false)\">✅ 車両も割り当てて登録</button>\n    </div>\n  </div>\n</div>\n\n<script>let vehicles = [], drivers = [], schedules = [], places = [], youshas = [], loadPlaces = [];\nlet dayOffData = {}; // { \"2026-06-17\": [\"1\",\"3\"], ... }\nlet spotVisibleData = {}; // { \"2026-06-18\": [\"5\"], ... } — 非表示ドライバーの当日スポット表示\nlet editId = { vehicle: null, driver: null, schedule: null };\nlet bulkSelected = new Set();\nlet bulkAlloc = [];\n\n// ── カスタムオートコンプリート ────────────────────────────\nfunction setupAutocomplete(inputId, datalistId, getOptsOverride) {\n  const inputEl = document.getElementById(inputId);\n  if (!inputEl || inputEl.dataset.acInit) return;\n  inputEl.dataset.acInit = '1';\n  inputEl.removeAttribute('list');\n\n  const drop = document.createElement('ul');\n  drop.style.cssText = [\n    'position:fixed','z-index:99999',\n    'background:#1a1a1a','border:1px solid #444','border-radius:8px',\n    'box-shadow:0 6px 20px rgba(0,0,0,.15)','margin:0','padding:4px 0',\n    'max-height:220px','overflow-y:auto','list-style:none','display:none'\n  ].join(';');\n  document.body.appendChild(drop);\n\n  let skipRender = false; // 選択直後の再描画を防ぐフラグ\n\n  function reposition() {\n    const r = inputEl.getBoundingClientRect();\n    drop.style.top   = (r.bottom + 2) + 'px';\n    drop.style.left  = r.left + 'px';\n    drop.style.width = r.width + 'px';\n  }\n\n  function getOpts() {\n    return getOptsOverride ? getOptsOverride() : [];\n  }\n\n  function render(q) {\n    if (skipRender) { skipRender = false; return; }\n    const opts = getOpts();\n    const filtered = q ? opts.filter(v => v.toLowerCase().includes(q.toLowerCase())) : opts;\n    if (!filtered.length) { drop.style.display = 'none'; return; }\n    drop.innerHTML = filtered.map((v, i) => {\n      const sep = i > 0 && filtered[i-1]._group !== v._group && v._group === 'other'\n        ? '<li style=\"height:1px;background:#444;margin:4px 0;pointer-events:none\"></li>' : '';\n      const label = typeof v === 'object' ? v.val : v;\n      return `${sep}<li style=\"padding:9px 14px;cursor:pointer;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis\"\n               data-val=\"${label.replace(/\"/g,'&quot;')}\">${label}</li>`;\n    }).join('');\n    drop.querySelectorAll('li[data-val]').forEach(li => {\n      li.addEventListener('mouseenter', () => li.style.background = '#2a2a2a');\n      li.addEventListener('mouseleave', () => li.style.background = '');\n    });\n    reposition();\n    drop.style.display = 'block';\n  }\n\n  inputEl.addEventListener('focus', () => render(''));\n  inputEl.addEventListener('input', () => render(inputEl.value));\n  inputEl.addEventListener('blur',  () => setTimeout(() => { drop.style.display = 'none'; }, 160));\n  window.addEventListener('scroll', () => { if (drop.style.display !== 'none') reposition(); }, true);\n\n  drop.addEventListener('mousedown', e => {\n    const li = e.target.closest('li[data-val]');\n    if (!li) return;\n    e.preventDefault();\n    skipRender = true; // 選択後に再描画しない\n    inputEl.value = li.dataset.val;\n    drop.style.display = 'none';\n    inputEl.dispatchEvent(new Event('input', { bubbles: true })); // filterUnloadByLoadPlace等を発火\n  });\n}\n\n// 積み地の全件リスト（重複排除・ソート）\nfunction getAllLoadOpts() {\n  const all = new Set();\n  (loadPlaces || []).forEach(p => { if (p.name && p.name.trim()) all.add(p.name.trim()); });\n  (schedules || []).forEach(s => { if (s.load_place && s.load_place.trim()) all.add(s.load_place.trim()); });\n  return Array.from(all).sort();\n}\n\n// 下ろし先の全件リスト（重複排除・ソート）\nfunction getAllUnloadOpts() {\n  const all = new Set();\n  (places || []).forEach(p => { if (p.name && p.name.trim()) all.add(p.name.trim()); });\n  (schedules || []).forEach(s => { if (s.unload_place && s.unload_place.trim()) all.add(s.unload_place.trim()); });\n  return Array.from(all).sort();\n}\n\n// 積み地に紐づく下ろし先のみ返す（積み地未選択時は全件）\nfunction getUnloadOptsForLoad(loadInputId) {\n  return () => {\n    const lp = (document.getElementById(loadInputId)?.value || '').trim();\n    if (!lp) return getAllUnloadOpts();\n    // その積み地で過去に使った下ろし先だけ\n    const linked = new Set(\n      (schedules || [])\n        .filter(s => s.load_place === lp && s.unload_place && s.unload_place.trim())\n        .map(s => s.unload_place.trim())\n    );\n    return Array.from(linked).sort();\n  };\n}\n\nfunction initPlaceAutocompletes() {\n  setupAutocomplete('s-client-name', null, getAllClientOpts);\n  setupAutocomplete('s-load-place',  'dl-load-places',  () => getLoadOptsForClient('s-client-name'));\n  setupAutocomplete('s-unload-place','dl-unload-places', () => getUnloadOptsForClientAndLoad('s-client-name','s-load-place'));\n  setupAutocomplete('at-client-name', null, getAllClientOpts);\n  setupAutocomplete('b-client-name', null, getAllClientOpts);\n  setupAutocomplete('b-load-place',  'dl-load-places',  () => getLoadOptsForClient('b-client-name'));\n  setupAutocomplete('b-unload-place','dl-unload-places', () => getUnloadOptsForClientAndLoad('b-client-name','b-load-place'));\n}\n\n// 荷主の全件リスト\nfunction getAllClientOpts() {\n  const all = new Set();\n  (schedules || []).forEach(s => { if (s.client_name && s.client_name.trim()) all.add(s.client_name.trim()); });\n  return Array.from(all).sort();\n}\n\n// 荷主に紐づく積み地（荷主未選択時は全件）\nfunction getLoadOptsForClient(clientInputId) {\n  const cn = (document.getElementById(clientInputId)?.value || '').trim();\n  if (!cn) return getAllLoadOpts();\n  const linked = new Set(\n    (schedules || []).filter(s => s.client_name === cn && s.load_place && s.load_place.trim()).map(s => s.load_place.trim())\n  );\n  return Array.from(linked).sort();\n}\n\n// 荷主＋積み地に紐づく下ろし先\nfunction getUnloadOptsForClientAndLoad(clientInputId, loadInputId) {\n  const cn = (document.getElementById(clientInputId)?.value || '').trim();\n  const lp = (document.getElementById(loadInputId)?.value || '').trim();\n  if (!cn && !lp) return getAllUnloadOpts();\n  let filtered = schedules || [];\n  if (cn) filtered = filtered.filter(s => s.client_name === cn);\n  if (lp) filtered = filtered.filter(s => s.load_place === lp);\n  const linked = new Set(filtered.filter(s => s.unload_place && s.unload_place.trim()).map(s => s.unload_place.trim()));\n  return Array.from(linked).sort();\n}\n\n// 荷主選択時のコールバック（積み地・下ろし先はそのまま保持）\nfunction onClientInput() {}\nfunction onClientInputBulk() {}\n\n// ── 場所の記憶・datalist更新 ──────────────────────────────\nfunction updatePlaceDatalist() {\n  // 積み地：load_places.json に登録されたもの（なければスケジュール実績）\n  const savedLoadNames = new Set(loadPlaces.map(p => p.name));\n  const loadNames = [...savedLoadNames, ...schedules.map(s => s.load_place).filter(p => p && p.trim() && !savedLoadNames.has(p))];\n  const dlLoad = document.getElementById('dl-load-places');\n  if (dlLoad) dlLoad.innerHTML = [...new Set(loadNames)].sort().map(p => `<option value=\"${p}\">`).join('');\n\n  // 荷下ろし先：places.json に登録されたもの（なければスケジュール実績）\n  const savedUnloadNames = new Set(places.map(p => p.name));\n  const unloadNames = [...savedUnloadNames, ...schedules.map(s => s.unload_place).filter(p => p && p.trim() && !savedUnloadNames.has(p))];\n  const dlUnload = document.getElementById('dl-unload-places');\n  if (dlUnload) dlUnload.innerHTML = [...new Set(unloadNames)].sort().map(p => `<option value=\"${p}\">`).join('');\n}\n\n// ── 積み地選択 → 荷下ろし先を絞り込み ─────────────────────────\nfunction filterUnloadByLoadPlace(loadPlace) {\n  const dl = document.getElementById('dl-unload-places');\n  if (!dl) return;\n  const lp = (loadPlace || '').trim();\n  if (!lp) {\n    // 空欄 → 全荷下ろし先を復元\n    const savedNames = new Set(places.map(p => p.name));\n    const all = [...savedNames, ...schedules.map(s => s.unload_place).filter(p => p && p.trim() && !savedNames.has(p))];\n    dl.innerHTML = [...new Set(all)].sort().map(p => `<option value=\"${p}\">`).join('');\n    return;\n  }\n  // この積み地で過去に使われた荷下ろし先だけ\n  const related = [...new Set(\n    schedules\n      .filter(s => s.load_place === lp && s.unload_place && s.unload_place.trim())\n      .map(s => s.unload_place.trim())\n  )].sort();\n  dl.innerHTML = related.map(p => `<option value=\"${p}\">`).join('');\n}\n\n// ── 下ろし先注意事項 ──────────────────────────────────────\nfunction onUnloadPlaceInput() {\n  const name = document.getElementById('s-unload-place').value.trim();\n  const box  = document.getElementById('s-caution-box');\n  const txt  = document.getElementById('s-caution-text');\n  const p = places.find(p => p.name === name);\n  if (p && p.caution) {\n    txt.textContent = p.caution;\n    box.classList.add('show');\n  } else {\n    box.classList.remove('show');\n  }\n}\n\nfunction openPlaceEdit() {\n  const name = document.getElementById('s-unload-place').value.trim();\n  document.getElementById('place-name').setAttribute('readonly', true);\n  document.getElementById('place-name').value    = name;\n  const p = places.find(p => p.name === name);\n  document.getElementById('place-caution').value = p ? (p.caution || '') : '';\n  openModal('place');\n}\n\nfunction showPlaceCaution(name) {\n  const p = places.find(p => p.name === name);\n  if (!p || !p.caution) return;\n  alert(`【${name}】注意事項\\n\\n${p.caution}`);\n}\n\nasync function savePlace() {\n  const name    = document.getElementById('place-name').value.trim();\n  const caution = document.getElementById('place-caution').value.trim();\n  if (!name) return;\n  await fetch('/api/places', {\n    method: 'POST',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify({ name, caution })\n  });\n  // ローカルも更新\n  const idx = places.findIndex(p => p.name === name);\n  if (idx >= 0) places[idx].caution = caution;\n  else places.push({ name, caution });\n  // 注意事項ボックス更新\n  onUnloadPlaceInput();\n  closeModal('place');\n  renderSchedules();\n  renderPlaces();\n}\n\n// ── ルートパターン提案 ────────────────────────────────────\nfunction onRouteInput() {\n  const lp = document.getElementById('s-load-place').value.trim();\n  const up = document.getElementById('s-unload-place').value.trim();\n  const box  = document.getElementById('suggest-box');\n  const list = document.getElementById('suggest-list');\n\n  if (!lp || !up) { box.classList.remove('show'); return; }\n\n  // 同じルートの過去スケジュールを集計\n  const matched = schedules.filter(s =>\n    s.load_place === lp && s.unload_place === up &&\n    (s.driver_id || s.vehicle_id)\n  );\n  if (!matched.length) { box.classList.remove('show'); return; }\n\n  // ドライバー×車両の組み合わせをカウント\n  const countMap = {};\n  matched.forEach(s => {\n    const dk = s.driver_id  || '';\n    const vk = s.vehicle_id || '';\n    const key = `${dk}|${vk}`;\n    countMap[key] = (countMap[key] || 0) + 1;\n  });\n\n  // 多い順に最大3件\n  const suggestions = Object.entries(countMap)\n    .sort((a, b) => b[1] - a[1])\n    .slice(0, 3)\n    .map(([key, cnt]) => {\n      const [dk, vk] = key.split('|');\n      return { dk, vk, cnt };\n    });\n\n  list.innerHTML = suggestions.map(({ dk, vk, cnt }) => {\n    const dn = dk ? dLabel(dk) : '（未設定）';\n    const vn = vk ? vLabel(vk) : '（未設定）';\n    return `<div class=\"suggest-item\" onclick=\"applySuggestion('${dk}','${vk}')\">\n      <div class=\"s-info\">👤 ${dn}　🚛 ${vn}</div>\n      <div class=\"s-count\">${cnt}回</div>\n    </div>`;\n  }).join('');\n\n  box.classList.add('show');\n}\n\nfunction applySuggestion(dk, vk) {\n  if (vk) document.getElementById('s-vehicle').value = vk;\n  if (dk) document.getElementById('s-driver').value  = dk;\n  document.getElementById('suggest-box').classList.remove('show');\n}\n\n// ── ページ切り替え ─────────────────────────────────────────\nfunction switchPage(name) {\n  document.querySelectorAll('.page').forEach(el => el.classList.remove('active'));\n  document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));\n  document.getElementById('page-' + name).classList.add('active');\n  const idx = ['dashboard','schedules','vehicles','drivers','places','haisha'].indexOf(name);\n  document.querySelectorAll('.nav-item')[idx].classList.add('active');\n  loadAll();\n  if (name === 'haisha') renderHaisha();\n}\n\n// ── データ ────────────────────────────────────────────────\nasync function loadAll() {\n  try {\n    const results = await Promise.all([\n      fetch('/api/vehicles').then(r => r.json()).catch(() => []),\n      fetch('/api/drivers').then(r => r.json()).catch(() => []),\n      fetch('/api/schedules').then(r => r.json()).catch(() => []),\n      fetch('/api/places').then(r => r.json()).catch(() => []),\n      fetch('/api/youshas').then(r => r.json()).catch(() => []),\n      fetch('/api/load_places').then(r => r.json()).catch(() => []),\n      fetch('/api/day_off').then(r => r.json()).catch(() => ({})),\n      fetch('/api/spot_visible').then(r => r.json()).catch(() => ({})),\n    ]);\n    vehicles = Array.isArray(results[0]) ? results[0] : [];\n    drivers = Array.isArray(results[1]) ? results[1] : [];\n    schedules = Array.isArray(results[2]) ? results[2] : [];\n    places = Array.isArray(results[3]) ? results[3] : [];\n    youshas = Array.isArray(results[4]) ? results[4] : [];\n    loadPlaces = Array.isArray(results[5]) ? results[5] : [];\n    dayOffData = (results[6] && typeof results[6] === 'object' && !Array.isArray(results[6])) ? results[6] : {};\n    spotVisibleData = (results[7] && typeof results[7] === 'object' && !Array.isArray(results[7])) ? results[7] : {};\n    await autoSetDefaultVehicles();\n  } catch(e) { console.warn('loadAll error:', e); }\n  renderAll();\n  initPlaceAutocompletes();\n}\n\nasync function autoSetDefaultVehicles() {\n  try {\n    const recentMap = {};\n    [...schedules].sort((a,b) => (b.load_date||'') < (a.load_date||'') ? -1 : 1).forEach(s => {\n      const did = String(s.driver_id || '');\n      const vid = String(s.vehicle_id || '');\n      if (did && vid && !recentMap[did]) recentMap[did] = vid;\n    });\n    for (const d of drivers) {\n      if (!d.default_vehicle_id && recentMap[String(d.id)]) {\n        const vid = recentMap[String(d.id)];\n        const updated = { ...d, default_vehicle_id: vid };\n        const res = await fetch(`/api/drivers/${d.id}`, {\n          method: 'PUT',\n          headers: { 'Content-Type': 'application/json' },\n          body: JSON.stringify(updated),\n        });\n        if (res.ok) {\n          const saved = await res.json();\n          const idx = drivers.findIndex(x => x.id === d.id);\n          if (idx !== -1) drivers[idx] = saved;\n        }\n      }\n    }\n  } catch(e) { console.warn('autoSetDefaultVehicles:', e); }\n}\n\nfunction renderAll() {\n  try { renderVehicles(); } catch(e) { console.error('renderVehicles:', e); }\n  try { renderDrivers(); } catch(e) { console.error('renderDrivers:', e); }\n  try { renderSchedules(); } catch(e) { console.error('renderSchedules:', e); }\n  try { renderDashboard(); } catch(e) { console.error('renderDashboard:', e); }\n  try { renderPlaces(); } catch(e) { console.error('renderPlaces:', e); }\n  try { renderLoadPlaces(); } catch(e) { console.error('renderLoadPlaces:', e); }\n  try { updatePlaceDatalist(); } catch(e) { console.error('updatePlaceDatalist:', e); }\n}\n\n// ── 積み地 ───────────────────────────────────────────────────\nfunction renderLoadPlaces() {\n  const tb = document.getElementById('load-places-tbody');\n  if (!tb) return;\n  tb.innerHTML = loadPlaces.length\n    ? loadPlaces.map(p => `\n      <tr>\n        <td><strong>${p.name}</strong></td>\n        <td><div class=\"col-actions\">\n          <button class=\"btn btn-danger btn-sm\" onclick=\"delLoadPlace('${p.id}')\">削除</button>\n        </div></td>\n      </tr>`).join('')\n    : '<tr class=\"empty-row\"><td colspan=\"2\">登録された積み地がありません</td></tr>';\n}\n\nfunction openAddLoadPlace() {\n  const name = prompt('積み地の名前を入力してください');\n  if (!name || !name.trim()) return;\n  addLoadPlace(name.trim());\n}\n\nasync function addLoadPlace(name) {\n  await fetch('/api/load_places', {\n    method: 'POST',\n    headers: {'Content-Type': 'application/json'},\n    body: JSON.stringify({ name }),\n  });\n  await loadAll();\n}\n\nasync function delLoadPlace(id) {\n  if (!confirm('この積み地を削除しますか？')) return;\n  await fetch(`/api/load_places/${id}`, { method: 'DELETE' });\n  await loadAll();\n}\n\n// ── 場所・注意事項 ─────────────────────────────────────────\nfunction renderPlaces() {\n  const tb = document.getElementById('places-tbody');\n  if (!tb) return;\n  tb.innerHTML = places.length\n    ? places.map(p => `\n      <tr>\n        <td><strong>${p.name}</strong></td>\n        <td style=\"white-space:pre-wrap;max-width:400px;font-size:13px\">${p.caution ? `<span style=\"color:#c2410c\">⚠️ ${p.caution}</span>` : '<span style=\"color:#aaa\">なし</span>'}</td>\n        <td><div class=\"col-actions\">\n          <button class=\"btn btn-ghost btn-sm\" onclick=\"openPlaceEditById('${p.id}')\">編集</button>\n          <button class=\"btn btn-danger btn-sm\" onclick=\"delPlace('${p.id}')\">削除</button>\n        </div></td>\n      </tr>`).join('')\n    : '<tr class=\"empty-row\"><td colspan=\"3\">登録された場所がありません</td></tr>';\n\n  // スケジュール登録済みでまだ注意事項なしの場所\n  const registeredNames = new Set(places.map(p => p.name));\n  const schedPlaces = [...new Set([\n    ...schedules.map(s => s.unload_place),\n  ].filter(p => p && p.trim() && !registeredNames.has(p)))].sort();\n\n  const box = document.getElementById('places-from-schedules');\n  if (box) {\n    box.innerHTML = schedPlaces.length\n      ? schedPlaces.map(name =>\n          `<button class=\"btn btn-ghost btn-sm\" onclick=\"openNewPlaceModalWithName('${name.replace(/'/g,\"\\\\'\")}')\">📍 ${name}</button>`\n        ).join('')\n      : '<span style=\"color:var(--text-sub);font-size:13px\">すべての場所に注意事項が登録されています</span>';\n  }\n}\n\nfunction openNewPlaceModal() {\n  document.getElementById('place-name').removeAttribute('readonly');\n  document.getElementById('place-name').value = '';\n  document.getElementById('place-caution').value = '';\n  openModal('place');\n}\n\nfunction openNewPlaceModalWithName(name) {\n  document.getElementById('place-name').removeAttribute('readonly');\n  document.getElementById('place-name').value = name;\n  document.getElementById('place-caution').value = '';\n  openModal('place');\n}\n\nfunction openPlaceEditById(id) {\n  const p = places.find(p => p.id === id);\n  if (!p) return;\n  document.getElementById('place-name').setAttribute('readonly', true);\n  document.getElementById('place-name').value    = p.name;\n  document.getElementById('place-caution').value = p.caution || '';\n  openModal('place');\n}\n\nasync function delPlace(id) {\n  if (!confirm('この場所情報を削除しますか？')) return;\n  await fetch(`/api/places/${id}`, { method: 'DELETE' });\n  await loadAll();\n}\n\n// ── ヘルパー ──────────────────────────────────────────────\nfunction vLabel(id) {\n  const v = vehicles.find(v => v.id == id);\n  if (!v) return '-';\n  return v.kind === 'トレーラー' ? `[T] ${v.head_number}` : v.number;\n}\nfunction dLabel(id) {\n  if (!id || id === '') return '-';\n  const sid = String(id);\n  if (sid.startsWith('y_')) {\n    const yid = sid.slice(2);\n    const y = youshas.find(y => String(y.id) === yid || y.id == yid);\n    return y ? (y.display_name || y.name || sid) : sid;\n  }\n  const d = drivers.find(d => String(d.id) == String(id));\n  return d ? d.name : '-';\n}\nfunction payloadKg(v) { return parseFloat(v.payload) || 0; }\n\nfunction busyVehicleIds(loadDate, unloadDate) {\n  return new Set(schedules.filter(s => s.load_date <= unloadDate && s.unload_date >= loadDate && s.vehicle_id).map(s => String(s.vehicle_id)));\n}\nfunction busyDriverIds(loadDate, unloadDate) {\n  return new Set(schedules.filter(s => s.load_date <= unloadDate && s.unload_date >= loadDate && s.driver_id).map(s => String(s.driver_id)));\n}\nfunction availVehicles(ld, ud) { const b = busyVehicleIds(ld, ud); return vehicles.filter(v => !b.has(String(v.id))); }\nfunction availDrivers(ld, ud)  { const b = busyDriverIds(ld, ud);  return drivers.filter(d => d.status === '稼働中' && !b.has(String(d.id))); }\n\nfunction badge(text, cls) { return `<span class=\"badge ${cls}\">${text}</span>`; }\nfunction statusBadge(s) {\n  return badge(s, { '稼働中': 'badge-green', '休暇中': 'badge-orange', '退職': 'badge-red' }[s] || 'badge-gray');\n}\n\n// ── 車両種別切り替え ──────────────────────────────────────\nfunction onVehicleKindChange() {\n  const t = document.getElementById('v-kind').value === 'トレーラー';\n  document.getElementById('v-number-group').style.display  = t ? 'none' : '';\n  document.getElementById('v-head-group').style.display    = t ? '' : 'none';\n  document.getElementById('v-trailer-group').style.display = t ? '' : 'none';\n}\n\n// ── モーダル ──────────────────────────────────────────────\nfunction openModal(type) {\n  editId[type] = null;\n  const today = new Date().toISOString().split('T')[0];\n  if (type === 'vehicle') {\n    document.getElementById('v-modal-title').textContent = '車両を追加';\n    document.getElementById('v-kind').value = 'トラック';\n    ['v-number','v-head','v-trailer','v-note'].forEach(i => document.getElementById(i).value = '');\n    document.getElementById('v-payload').value = '';\n    onVehicleKindChange();\n  }\n  if (type === 'driver') {\n    document.getElementById('d-modal-title').textContent = 'ドライバーを追加';\n    ['d-name','d-phone','d-note'].forEach(i => document.getElementById(i).value = '');\n    document.getElementById('d-status').value = '稼働中';\n  }\n  if (type === 'schedule') {\n    document.getElementById('s-modal-title').textContent = '配車を追加';\n    ['s-load-date','s-unload-date'].forEach(i => document.getElementById(i).value = today);\n    ['s-client-name','s-load-place','s-unload-place','s-note'].forEach(i => document.getElementById(i).value = '');\n    document.getElementById('s-weight').value = '';\n    document.getElementById('avail-wrap').style.display = 'none';\n    document.getElementById('suggest-box').classList.remove('show');\n    // 注意事項ボックスをリセット\n    document.getElementById('s-caution-box').classList.remove('show');\n    document.getElementById('s-caution-text').textContent = '';\n    resetSCargoSection();\n    fillSchedSelects();\n  }\n  if (type === 'bulk') {\n    ['b-load-date','b-unload-date'].forEach(i => document.getElementById(i).value = today);\n    ['b-load-place','b-unload-place','b-note'].forEach(i => document.getElementById(i).value = '');\n    document.getElementById('b-total').value = '';\n    document.getElementById('bulk-v-wrap').style.display = 'none';\n    document.getElementById('bulk-preview-wrap').style.display = 'none';\n    bulkSelected = new Set(); bulkAlloc = [];\n    resetCargoSection();\n  }\n  document.getElementById('modal-' + type).classList.add('open');\n}\n\nfunction closeModal(type) {\n  document.getElementById('modal-' + type).classList.remove('open');\n  // 相積みモードをリセット\n  if (type === 'schedule' && _aitsuMode) {\n    _aitsuMode = false;\n    document.getElementById('s-normal-mode').style.display = '';\n    document.getElementById('s-aitsu-mode').style.display  = 'none';\n    document.getElementById('at-rows').innerHTML = '';\n    _aitsuRowCount = 0;\n    const btn = document.getElementById('aitsu-toggle-btn');\n    if (btn) { btn.style.background='#1a1a1a'; btn.style.borderColor='#555'; btn.style.color='#888'; }\n    document.getElementById('s-modal-title').textContent = '配車を追加';\n  }\n}\n\n// ── 車両 ──────────────────────────────────────────────────\nfunction renderVehicles() {\n  const tb = document.getElementById('vehicle-tbody');\n  if (!vehicles.length) { tb.innerHTML = '<tr class=\"empty-row\"><td colspan=\"6\">データがありません</td></tr>'; return; }\n  tb.innerHTML = vehicles.map(v => {\n    const k = v.kind === 'トレーラー' ? badge('トレーラー','badge-blue') : badge('トラック','badge-gray');\n    const num = v.kind === 'トレーラー' ? `<strong>${v.head_number}</strong>` : `<strong>${v.number}</strong>`;\n    return `<tr>\n      <td>${k}</td><td>${num}</td>\n      <td>${v.kind === 'トレーラー' ? v.trailer_number : '-'}</td>\n      <td>${v.payload ? v.payload + 'kg' : '-'}</td>\n      <td>${v.note || '-'}</td>\n      <td><div class=\"col-actions\">\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"editVehicle('${v.id}')\">編集</button>\n        <button class=\"btn btn-danger btn-sm\" onclick=\"delVehicle('${v.id}')\">削除</button>\n      </div></td>\n    </tr>`;\n  }).join('');\n}\n\nfunction editVehicle(id) {\n  const v = vehicles.find(v => v.id === id);\n  editId.vehicle = id;\n  document.getElementById('v-modal-title').textContent = '車両を編集';\n  document.getElementById('v-kind').value = v.kind || 'トラック';\n  document.getElementById('v-number').value = v.number || '';\n  document.getElementById('v-head').value = v.head_number || '';\n  document.getElementById('v-trailer').value = v.trailer_number || '';\n  document.getElementById('v-payload').value = v.payload || '';\n  document.getElementById('v-note').value = v.note || '';\n  onVehicleKindChange();\n  document.getElementById('modal-vehicle').classList.add('open');\n}\n\nasync function saveVehicle() {\n  const kind = document.getElementById('v-kind').value;\n  const trailer = kind === 'トレーラー';\n  const data = {\n    kind,\n    number: trailer ? '' : document.getElementById('v-number').value.trim(),\n    head_number: trailer ? document.getElementById('v-head').value.trim() : '',\n    trailer_number: trailer ? document.getElementById('v-trailer').value.trim() : '',\n    payload: document.getElementById('v-payload').value,\n    note: document.getElementById('v-note').value.trim(),\n  };\n  if (trailer && !data.head_number) { alert('ヘッドナンバーは必須です'); return; }\n  if (!trailer && !data.number) { alert('ナンバープレートは必須です'); return; }\n  const id = editId.vehicle;\n  await fetch(id ? `/api/vehicles/${id}` : '/api/vehicles', {\n    method: id ? 'PUT' : 'POST',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify(data)\n  });\n  closeModal('vehicle'); await loadAll();\n}\n\nasync function delVehicle(id) {\n  if (!confirm('削除しますか？')) return;\n  await fetch(`/api/vehicles/${id}`, { method: 'DELETE' });\n  await loadAll();\n}\n\n// ── ドライバー ────────────────────────────────────────────\nfunction renderDrivers() {\n  const tb = document.getElementById('driver-tbody');\n  if (!drivers.length) { tb.innerHTML = '<tr class=\"empty-row\"><td colspan=\"7\">データがありません</td></tr>'; return; }\n  tb.innerHTML = drivers.map(d => {\n    const on = d.haisha_visible !== false; // デフォルトtrue\n    return `<tr>\n      <td><strong>${d.name}</strong></td>\n      <td>${d.phone || '-'}</td>\n      <td>${statusBadge(d.status)}</td>\n      <td style=\"text-align:center\">\n        <button onclick=\"toggleHaishaVisible('${d.id}')\"\n          style=\"border:none;border-radius:20px;padding:4px 14px;font-size:12px;font-weight:700;cursor:pointer;\n            background:${on ? '#22c55e' : '#333'};color:${on ? '#fff' : '#888'}\">\n          ${on ? '表示' : '非表示'}\n        </button>\n      </td>\n      <td>${d.note || '-'}</td>\n      <td><div class=\"col-actions\">\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"editDriver('${d.id}')\">編集</button>\n        <button class=\"btn btn-danger btn-sm\" onclick=\"delDriver('${d.id}')\">削除</button>\n      </div></td>\n    </tr>`;\n  }).join('');\n}\n\nasync function toggleHaishaVisible(id) {\n  const d = drivers.find(x => x.id === id);\n  if (!d) return;\n  const updated = { ...d, haisha_visible: d.haisha_visible === false ? true : false };\n  await fetch(`/api/drivers/${id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify(updated),\n  });\n  await loadAll();\n}\n\nfunction editDriver(id) {\n  const d = drivers.find(d => d.id === id);\n  editId.driver = id;\n  document.getElementById('d-modal-title').textContent = 'ドライバーを編集';\n  document.getElementById('d-name').value = d.name;\n  document.getElementById('d-phone').value = d.phone || '';\n  document.getElementById('d-status').value = d.status;\n  document.getElementById('d-note').value = d.note || '';\n  document.getElementById('modal-driver').classList.add('open');\n}\n\nasync function saveDriver() {\n  const data = {\n    name: document.getElementById('d-name').value.trim(),\n    phone: document.getElementById('d-phone').value.trim(),\n    status: document.getElementById('d-status').value,\n    note: document.getElementById('d-note').value.trim(),\n  };\n  if (!data.name) { alert('氏名は必須です'); return; }\n  const id = editId.driver;\n  await fetch(id ? `/api/drivers/${id}` : '/api/drivers', {\n    method: id ? 'PUT' : 'POST',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify(data)\n  });\n  closeModal('driver'); await loadAll();\n}\n\nasync function delDriver(id) {\n  if (!confirm('削除しますか？')) return;\n  await fetch(`/api/drivers/${id}`, { method: 'DELETE' });\n  await loadAll();\n}\n\n// ── スケジュール ──────────────────────────────────────────\nfunction fillSchedSelects(vid, did) {\n  const vOpts = '<option value=\"\">-- 選択 --</option>' +\n    vehicles.map(v => {\n      const l = v.kind === 'トレーラー' ? `[T] ${v.head_number} / ${v.trailer_number}` : v.number;\n      return `<option value=\"${v.id}\" ${v.id==vid?'selected':''}>${l}${v.payload?' ('+v.payload+'kg)':''}</option>`;\n    }).join('');\n  const dOpts = '<option value=\"\">-- 選択 --</option>' +\n    drivers.map(d => `<option value=\"${d.id}\" ${d.id==did?'selected':''}>${d.name}</option>`).join('') +\n    (youshas.length ? '<option disabled>── 傭車 ──</option>' : '') +\n    youshas.map(y => {\n      const yid = `y_${y.id}`;\n      return `<option value=\"${yid}\" ${yid==did?'selected':''}>${y.display_name || y.name}（傭車）</option>`;\n    }).join('');\n  document.getElementById('s-vehicle').innerHTML = vOpts;\n  document.getElementById('s-driver').innerHTML  = dOpts;\n  // 相積みモード用にも同期\n  document.getElementById('at-vehicle').innerHTML = vOpts;\n  document.getElementById('at-driver').innerHTML  = dOpts;\n}\n\nfunction checkAvail() {\n  const ld = document.getElementById('s-load-date').value;\n  const ud = document.getElementById('s-unload-date').value;\n  if (!ld || !ud) { alert('先に日付を入力してください'); return; }\n\n  const av = availVehicles(ld, ud);\n  const ad = availDrivers(ld, ud);\n\n  document.getElementById('avail-v-list').innerHTML = av.length\n    ? av.map(v => {\n        const l = v.kind === 'トレーラー' ? `[T] ${v.head_number} / ${v.trailer_number}` : v.number;\n        return `<div class=\"candidate-item\">\n          <label style=\"display:flex;align-items:center;gap:10px;flex:1;cursor:pointer\">\n            <input type=\"radio\" name=\"av\" value=\"${v.id}\" onchange=\"document.getElementById('s-vehicle').value='${v.id}'\">\n            <div><div class=\"c-name\">${l}</div><div class=\"c-sub\">${v.kind}　最大 ${v.payload||'?'}kg</div></div>\n          </label>\n        </div>`;\n      }).join('')\n    : '<div class=\"no-candidate\">空き車両がありません</div>';\n\n  document.getElementById('avail-d-list').innerHTML = ad.length\n    ? ad.map(d => `<div class=\"candidate-item\">\n        <label style=\"display:flex;align-items:center;gap:10px;flex:1;cursor:pointer\">\n          <input type=\"radio\" name=\"ad\" value=\"${d.id}\" onchange=\"document.getElementById('s-driver').value='${d.id}'\">\n          <div><div class=\"c-name\">${d.name}</div><div class=\"c-sub\">${d.phone||''}</div></div>\n        </label>\n      </div>`).join('')\n    : '<div class=\"no-candidate\">空きドライバーがありません</div>';\n\n  document.getElementById('avail-wrap').style.display = 'block';\n}\n\nfunction renderSchedules() {\n  const filterDate = (document.getElementById('filter-date') || {}).value || '';\n  const sorted = [...schedules]\n    .filter(s => !filterDate || s.load_date === filterDate || s.unload_date === filterDate)\n    .sort((a,b) => {\n      const da = a.unload_date || a.load_date || '';\n      const db = b.unload_date || b.load_date || '';\n      if (da !== db) return da < db ? -1 : 1;\n      return (a.load_date || '') < (b.load_date || '') ? -1 : 1;\n    });\n  const active    = sorted.filter(s => !s.done);\n  const completed = sorted.filter(s =>  s.done);\n\n  const vOpts = '<option value=\"\">-- 未割当 --</option>' +\n    vehicles.map(v => {\n      const l = v.kind === 'トレーラー' ? `[T] ${v.head_number}` : v.number;\n      return `<option value=\"${v.id}\">${l}</option>`;\n    }).join('');\n  const dOpts = '<option value=\"\">-- 未割当 --</option>' +\n    drivers.filter(d => d.status === '稼働中').map(d =>\n      `<option value=\"${d.id}\">${d.name}</option>`\n    ).join('') +\n    (youshas.length ? '<option disabled>── 傭車 ──</option>' : '') +\n    youshas.map(y => `<option value=\"y_${y.id}\">${y.display_name || y.name}（傭車）</option>`).join('');\n\n  const buildRow = (s) => {\n    const hasDriver  = s.driver_id  && s.driver_id  !== '';\n    const isYousha   = hasDriver && String(s.driver_id).startsWith('y_');\n    const hasVehicle = isYousha || (s.vehicle_id && s.vehicle_id !== '');\n    const isDone = !!s.done;\n    const st = s.load_status || '';\n\n    // 傭車の場合は車番をyoushas.jsonから取得して表示（セレクト不要）\n    let vCell;\n    if (isYousha) {\n      const y = youshas.find(y => `y_${y.id}` === String(s.driver_id));\n      const vnum = y ? ((y.vehicle_number || y.vehicle_info || '') || '—') : '—';\n      vCell = `<td class=\"assign-cell\"><span style=\"font-size:13px;color:var(--text-sub)\">${vnum}</span></td>`;\n    } else {\n      vCell = `<td class=\"assign-cell\"><select class=\"assign-select${hasVehicle ? '' : ' unassigned'}\" ${isDone ? 'disabled' : ''}\n        onchange=\"assignField(${s.id},'vehicle_id',this.value,this)\">\n        ${vOpts.replace(`value=\"${s.vehicle_id}\"`, `value=\"${s.vehicle_id}\" selected`)}\n      </select></td>`;\n    }\n\n    const dSelect = `<select class=\"assign-select${hasDriver ? '' : ' unassigned'}\" ${isDone ? 'disabled' : ''}\n      onchange=\"assignField(${s.id},'driver_id',this.value,this)\">\n      ${dOpts.replace(`value=\"${s.driver_id}\"`, `value=\"${s.driver_id}\" selected`)}\n    </select>`;\n\n    const unassignedBadge = (!isDone && (!hasDriver || !hasVehicle))\n      ? `<span class=\"badge badge-unassigned\" style=\"margin-left:4px;font-size:11px;\">未割当</span>` : '';\n\n    const doneBtn = `<button class=\"done-toggle ${isDone ? 'done' : 'undone'}\"\n      onclick=\"toggleDone('${s.id}',${isDone})\">\n      ${isDone ? '✅ 完了' : '○ 未完了'}\n    </button>`;\n\n    const stLabel = st === 'loaded' ? '積込完了' : st === 'delivered' ? '荷下ろし完了' : '未積み込み';\n    const stBadgeCls = st === 'loaded' ? 'st-loaded' : st === 'delivered' ? 'st-delivered' : 'st-none';\n    const statusBadge = `<button class=\"c-status ${stBadgeCls}\" title=\"クリックでステータス変更\"\n      onclick=\"toggleLoadStatus('${s.id}')\" style=\"border:none;cursor:pointer;font-size:11px;padding:3px 7px;border-radius:5px;display:block;width:100%;margin-bottom:4px\">\n      ${stLabel}</button>`;\n\n    const rowBg = st === 'loaded' ? 'sched-row-loaded' : st === 'delivered' ? 'sched-row-delivered' : '';\n\n    return `<tr class=\"${isDone ? 'done-row' : ''} ${rowBg}\">\n      <td style=\"min-width:90px\">${statusBadge}${doneBtn}</td>\n      <td style=\"font-size:12px;color:var(--text-sub)\">${s.client_name || ''}</td>\n      <td>${s.load_date}${unassignedBadge}</td>\n      <td><strong>${s.load_place}</strong></td>\n      <td>${s.unload_date}</td>\n      <td><strong>${s.unload_place}</strong>${(() => { const pl = places.find(p => p.name === s.unload_place); return pl && pl.caution ? `<span class=\"caution-badge\" onclick=\"showPlaceCaution('${s.unload_place.replace(/'/g,\"\\\\'\")}')\">⚠️ 注意</span>` : ''; })()}</td>\n      <td>${s.weight ? s.weight + 'kg' : '-'}</td>\n      ${vCell}\n      <td class=\"assign-cell\">${dSelect}</td>\n      <td>\n        ${s.cargo_note ? `<span style=\"color:#0891b2;font-weight:600\">${s.cargo_note}</span>` : ''}\n        ${s.cargo_note && s.note ? '<br>' : ''}\n        ${s.note || (!s.cargo_note ? '-' : '')}\n      </td>\n      <td><div class=\"col-actions\">\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"editSched('${s.id}')\">編集</button>\n        <button class=\"btn btn-danger btn-sm\" onclick=\"delSched('${s.id}')\">削除</button>\n      </div></td>\n    </tr>`;\n  };\n\n  // 相積みグループ行（複数スケジュールを1行にまとめ）\n  const buildGroupRow = (grp) => {\n    const first = grp[0];\n    const isDone = grp.every(s => !!s.done);\n    const hasDriver = first.driver_id && first.driver_id !== '';\n    const isYousha = hasDriver && String(first.driver_id).startsWith('y_');\n    const hasVehicle = isYousha || (first.vehicle_id && first.vehicle_id !== '');\n    const st = first.load_status || '';\n    const totalWeight = grp.reduce((sum, s) => sum + (parseFloat(s.weight) || 0), 0);\n\n    const stLabel = st === 'loaded' ? '積込完了' : st === 'delivered' ? '荷下ろし完了' : '未積み込み';\n    const stBadgeCls = st === 'loaded' ? 'st-loaded' : st === 'delivered' ? 'st-delivered' : 'st-none';\n    const statusBadge = `<button class=\"c-status ${stBadgeCls}\" onclick=\"toggleGroupStatus('${first.ai_tsumi_group}')\"\n      style=\"border:none;cursor:pointer;font-size:11px;padding:3px 7px;border-radius:5px;display:block;width:100%;margin-bottom:4px\">${stLabel}</button>`;\n    const doneBtn = `<button class=\"done-toggle ${isDone ? 'done' : 'undone'}\"\n      onclick=\"toggleGroupDone('${first.ai_tsumi_group}',${isDone})\">${isDone ? '✅ 完了' : '○ 未完了'}</button>`;\n    const unassignedBadge = (!isDone && (!hasDriver || !hasVehicle))\n      ? `<span class=\"badge badge-unassigned\" style=\"margin-left:4px;font-size:11px;\">未割当</span>` : '';\n    const rowBg = st === 'loaded' ? 'sched-row-loaded' : st === 'delivered' ? 'sched-row-delivered' : '';\n\n    let vCell;\n    if (isYousha) {\n      const y = youshas.find(y => `y_${y.id}` === String(first.driver_id));\n      vCell = `<td class=\"assign-cell\"><span style=\"font-size:13px;color:var(--text-sub)\">${y ? ((y.vehicle_number || y.vehicle_info || '')||'—') : '—'}</span></td>`;\n    } else {\n      vCell = `<td class=\"assign-cell\"><select class=\"assign-select${hasVehicle ? '' : ' unassigned'}\" ${isDone ? 'disabled' : ''}\n        onchange=\"assignGroupField('${first.ai_tsumi_group}','vehicle_id',this.value)\">\n        ${vOpts.replace(`value=\"${first.vehicle_id}\"`, `value=\"${first.vehicle_id}\" selected`)}\n      </select></td>`;\n    }\n    const dSelect = `<select class=\"assign-select${hasDriver ? '' : ' unassigned'}\" ${isDone ? 'disabled' : ''}\n      onchange=\"assignGroupField('${first.ai_tsumi_group}','driver_id',this.value)\">\n      ${dOpts.replace(`value=\"${first.driver_id}\"`, `value=\"${first.driver_id}\" selected`)}\n    </select>`;\n\n    const routeList = grp.map(s =>\n      `<div style=\"display:flex;align-items:center;gap:6px;font-size:12px;white-space:nowrap;margin-bottom:2px\">\n        <strong>${s.load_place}</strong> → <strong>${s.unload_place}</strong>${s.weight ? ` <span style=\"color:#999\">${s.weight}kg</span>` : ''}\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"editSched('${s.id}')\" style=\"font-size:11px;padding:1px 6px;flex-shrink:0\">編集</button>\n      </div>`\n    ).join('');\n\n    return `<tr class=\"${isDone ? 'done-row' : ''} ${rowBg}\">\n      <td style=\"min-width:90px\">${statusBadge}${doneBtn}</td>\n      <td>${first.load_date}${unassignedBadge}<br><span style=\"font-size:11px;background:rgba(79,126,248,0.2);color:#93b5ff;border-radius:4px;padding:1px 6px\">🔀 相積み×${grp.length}</span></td>\n      <td colspan=\"2\">${routeList}</td>\n      <td style=\"text-align:right\">${totalWeight ? Math.round(totalWeight).toLocaleString('ja-JP') + 'kg' : '-'}</td>\n      ${vCell}\n      <td class=\"assign-cell\">${dSelect}</td>\n      <td>${first.note || '-'}</td>\n      <td><div class=\"col-actions\">\n        <button class=\"btn btn-danger btn-sm\" onclick=\"delGroup('${first.ai_tsumi_group}')\">削除</button>\n      </div></td>\n    </tr>`;\n  };\n\n  // 相積みグループをまとめ、それ以外は個別行として構築\n  function buildRows(list) {\n    const rendered = new Set();\n    const html = [];\n    for (const s of list) {\n      if (rendered.has(s.id)) continue;\n      if (s.ai_tsumi_group) {\n        const grp = list.filter(x => x.ai_tsumi_group === s.ai_tsumi_group);\n        grp.forEach(x => rendered.add(x.id));\n        html.push(buildGroupRow(grp));\n      } else {\n        rendered.add(s.id);\n        html.push(buildRow(s));\n      }\n    }\n    return html.join('') || '<tr class=\"empty-row\"><td colspan=\"10\">データがありません</td></tr>';\n  }\n\n  const tb = document.getElementById('sched-tbody');\n  tb.innerHTML = buildRows(active);\n\n  const ctb = document.getElementById('completed-tbody');\n  ctb.innerHTML = buildRows(completed);\n\n  const cnt = document.getElementById('completed-count');\n  if (cnt) cnt.textContent = completed.length ? `（${completed.length}件）` : '';\n}\n\n// ── 相積みグループ操作 ──────────────────────────────────\nfunction getGroup(groupId) {\n  return schedules.filter(s => s.ai_tsumi_group === groupId);\n}\nasync function assignGroupField(groupId, field, value) {\n  const grp = getGroup(groupId);\n  for (const s of grp) {\n    await fetch(`/api/schedules/${s.id}`, {\n      method: 'PUT', headers: {'Content-Type':'application/json'},\n      body: JSON.stringify({ ...s, [field]: value }),\n    });\n  }\n  await loadAll();\n}\nasync function toggleGroupDone(groupId, currentDone) {\n  const grp = getGroup(groupId);\n  for (const s of grp) {\n    await fetch(`/api/schedules/${s.id}`, {\n      method: 'PUT', headers: {'Content-Type':'application/json'},\n      body: JSON.stringify({ ...s, done: !currentDone }),\n    });\n  }\n  await loadAll();\n}\nasync function toggleGroupStatus(groupId) {\n  const grp = getGroup(groupId);\n  if (!grp.length) return;\n  const cycle = { '': 'loaded', 'none': 'loaded', 'loaded': 'delivered', 'delivered': 'none' };\n  const next = cycle[grp[0].load_status || ''] || 'loaded';\n  for (const s of grp) {\n    await fetch(`/api/schedules/${s.id}`, {\n      method: 'PUT', headers: {'Content-Type':'application/json'},\n      body: JSON.stringify({ load_status: next }),\n    });\n  }\n  await loadAll(); renderHaisha();\n}\nasync function delGroup(groupId) {\n  if (!confirm('相積みグループをまとめて削除しますか？')) return;\n  const grp = getGroup(groupId);\n  for (const s of grp) {\n    await fetch(`/api/schedules/${s.id}`, { method: 'DELETE' });\n  }\n  await loadAll();\n}\n\nasync function toggleDone(sid, currentDone) {\n  const s = schedules.find(s => s.id === sid);\n  if (!s) return;\n  s.done = !currentDone;\n  await fetch(`/api/schedules/${sid}`, {\n    method: 'PUT',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify(s)\n  });\n  renderSchedules();\n  renderDashboard();\n}\n\nfunction toggleCompleted(header) {\n  const body = document.getElementById('completed-body');\n  const isOpen = body.style.display !== 'none';\n  body.style.display = isOpen ? 'none' : 'block';\n  header.classList.toggle('open', !isOpen);\n}\n\nasync function assignField(sid, field, value, selectEl) {\n  const s = schedules.find(s => s.id === sid);\n  if (!s) return;\n  const data = { ...s, [field]: value };\n  await fetch(`/api/schedules/${sid}`, {\n    method: 'PUT',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify(data)\n  });\n  // スタイルだけ即時反映（再レンダリングなし）\n  selectEl.classList.toggle('unassigned', !value);\n  // ローカルデータも更新\n  s[field] = value;\n  // 未割当バッジを更新\n  const row = selectEl.closest('tr');\n  const hasDriver  = s.driver_id  && s.driver_id  !== '';\n  const hasVehicle = s.vehicle_id && s.vehicle_id !== '';\n  const badge = row.querySelector('.badge-unassigned');\n  if (hasDriver && hasVehicle) { if (badge) badge.remove(); }\n  else if (!badge) {\n    const td = row.querySelector('td');\n    td.insertAdjacentHTML('beforeend', `<span class=\"badge badge-unassigned\" style=\"margin-left:4px;font-size:11px;\">未割当</span>`);\n  }\n}\n\nfunction editSched(id) {\n  const s = schedules.find(s => s.id === id);\n  editId.schedule = id;\n  // まず全フィールドをリセット（前回の入力が残らないように）\n  resetSCargoSection();\n  document.getElementById('s-modal-title').textContent = '配車を編集';\n  document.getElementById('s-client-name').value = s.client_name || '';\n  document.getElementById('s-load-date').value = s.load_date;\n  document.getElementById('s-load-place').value = s.load_place || '';\n  document.getElementById('s-unload-date').value = s.unload_date;\n  document.getElementById('s-unload-place').value = s.unload_place || '';\n  document.getElementById('s-weight').value = s.weight || '';\n  document.getElementById('s-note').value = s.note || '';\n  document.getElementById('avail-wrap').style.display = 'none';\n  // cargo_note からカーゴタイプを復元（あれば）\n  if (s.cargo_note) {\n    document.getElementById('s-cargo-type').value = s.cargo_note.split(' ')[0] || '';\n    onSCargoTypeChange();\n  }\n  fillSchedSelects(s.vehicle_id, s.driver_id);\n  document.getElementById('modal-schedule').classList.add('open');\n}\n\n// ── 相積みモード ────────────────────────────────────────\nlet _aitsuMode = false;\nlet _aitsuRowCount = 0;\n\nfunction toggleAitsumi() {\n  _aitsuMode = !_aitsuMode;\n  document.getElementById('s-normal-mode').style.display = _aitsuMode ? 'none' : '';\n  document.getElementById('s-aitsu-mode').style.display  = _aitsuMode ? '' : 'none';\n  const btn = document.getElementById('aitsu-toggle-btn');\n  btn.style.background = _aitsuMode ? 'rgba(79,126,248,0.15)' : '#1a1a1a';\n  btn.style.borderColor = _aitsuMode ? 'var(--accent)' : '#555';\n  btn.style.color = _aitsuMode ? 'var(--accent)' : '#666';\n  document.getElementById('s-modal-title').textContent = _aitsuMode ? '相積み追加' : '配車を追加';\n  if (_aitsuMode && document.getElementById('at-rows').children.length === 0) {\n    addAitsuRow(); addAitsuRow(); // 最初から2行\n  }\n  // 日付を共通欄にコピー\n  if (_aitsuMode) {\n    document.getElementById('at-load-date').value   = document.getElementById('s-load-date').value;\n    document.getElementById('at-unload-date').value = document.getElementById('s-unload-date').value;\n  }\n}\n\nfunction addAitsuRow() {\n  _aitsuRowCount++;\n  const n = _aitsuRowCount;\n  const div = document.createElement('div');\n  div.id = `at-row-${n}`;\n  div.style.cssText = 'display:grid;grid-template-columns:1fr 1fr 1fr auto auto;gap:8px;align-items:center;margin-bottom:8px;padding:10px;background:#1a1a1a;border-radius:8px;border:1px solid #444';\n  div.innerHTML = `\n    <input class=\"form-input\" placeholder=\"積み込み場所\" list=\"dl-load-places\" autocomplete=\"off\"\n           id=\"at-load-${n}\" oninput=\"filterUnloadByLoadPlace(this.value)\" style=\"font-size:13px;padding:7px 10px;border:1px solid var(--border);border-radius:6px;outline:none\">\n    <input class=\"form-input\" placeholder=\"下ろし場所\" list=\"dl-unload-places\" autocomplete=\"off\"\n           id=\"at-unload-${n}\" style=\"font-size:13px;padding:7px 10px;border:1px solid var(--border);border-radius:6px;outline:none\">\n    <input type=\"text\" list=\"dl-cargo-types\" placeholder=\"荷物の種類（任意）\" autocomplete=\"off\"\n           id=\"at-cargo-${n}\" style=\"font-size:13px;padding:7px 10px;border:1px solid var(--border);border-radius:6px;outline:none\">\n    <input type=\"number\" step=\"1\" placeholder=\"重量(kg)\"\n           id=\"at-weight-${n}\" style=\"width:80px;font-size:13px;padding:7px 8px;border:1px solid var(--border);border-radius:6px;outline:none\">\n    <button onclick=\"document.getElementById('at-row-${n}').remove()\"\n            style=\"background:none;border:none;color:#555;font-size:18px;cursor:pointer;padding:0 4px\">×</button>`;\n  document.getElementById('at-rows').appendChild(div);\n}\n\nasync function saveSchedule() {\n  // 相積みモードの場合\n  if (_aitsuMode) {\n    const loadDate   = document.getElementById('at-load-date').value;\n    const unloadDate = document.getElementById('at-unload-date').value;\n    const vehicleId  = document.getElementById('at-vehicle').value;\n    const driverId   = document.getElementById('at-driver').value;\n    const clientName = document.getElementById('at-client-name')?.value.trim() || '';\n    if (!loadDate) { alert('積み込み日は必須です'); return; }\n\n    const rows = [...document.getElementById('at-rows').children];\n    const entries = rows.map(row => {\n      const n = row.id.replace('at-row-', '');\n      const cargoType = document.getElementById(`at-cargo-${n}`)?.value.trim() || '';\n      return {\n        load_place:   document.getElementById(`at-load-${n}`)?.value.trim(),\n        unload_place: document.getElementById(`at-unload-${n}`)?.value.trim(),\n        weight:       document.getElementById(`at-weight-${n}`)?.value,\n        cargo_type:   cargoType,\n      };\n    }).filter(e => e.load_place || e.unload_place);\n\n    if (!entries.length) { alert('積み込み・下ろし場所を1行以上入力してください'); return; }\n\n    // 編集モード: 既存グループを削除\n    if (window._editAitsuGroupId) {\n      const oldGrp = schedules.filter(s => s.ai_tsumi_group === window._editAitsuGroupId);\n      for (const s of oldGrp) {\n        await fetch(`/api/schedules/${s.id}`, { method: 'DELETE' });\n      }\n      window._editAitsuGroupId = null;\n    }\n\n    const groupId = `aitsu_${Date.now()}`;\n    for (const e of entries) {\n      const aitsuRes = await fetch('/api/schedules', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({\n          load_date: loadDate, load_place: e.load_place,\n          unload_date: unloadDate || loadDate, unload_place: e.unload_place,\n          weight: e.weight, vehicle_id: vehicleId || null, driver_id: driverId,\n          note: '', cargo_note: e.cargo_type || '',\n          ai_tsumi: true, ai_tsumi_group: groupId, client_name: clientName,\n        }),\n      });\n      if (!aitsuRes.ok) { const err = await aitsuRes.text(); alert('相積み保存エラー: ' + err); return; }\n    }\n    closeModal('schedule'); await loadAll();\n    return;\n  }\n\n  // 通常モード\n  const { note: cargoNote, items: cargoItems } = buildSCargoResult();\n  const data = {\n    client_name:  document.getElementById('s-client-name').value.trim(),\n    load_date:    document.getElementById('s-load-date').value,\n    load_place:   document.getElementById('s-load-place').value.trim(),\n    unload_date:  document.getElementById('s-unload-date').value,\n    unload_place: document.getElementById('s-unload-place').value.trim(),\n    weight:       document.getElementById('s-weight').value,\n    vehicle_id:   document.getElementById('s-vehicle').value,\n    driver_id:    document.getElementById('s-driver').value,\n    note:         document.getElementById('s-note').value.trim(),\n    cargo_note:   cargoNote,\n  };\n  if (cargoItems) data.items = cargoItems;\n  if (!data.load_date || !data.load_place) { alert('積み込み日と積み込み場所は必須です'); return; }\n  const id = editId.schedule;\n  // 編集時：相積み情報・ステータス・分割情報など管理フィールドを保持\n  if (id) {\n    const existing = schedules.find(s => s.id === id);\n    if (existing) {\n      if (existing.ai_tsumi)       data.ai_tsumi       = existing.ai_tsumi;\n      if (existing.ai_tsumi_group) data.ai_tsumi_group = existing.ai_tsumi_group;\n      if (existing.load_status)    data.load_status    = existing.load_status;\n      if (existing.items)          data.items          = existing.items;\n      // cargo_note：フォームで未入力なら既存を保持\n      if (!cargoNote && existing.cargo_note) data.cargo_note = existing.cargo_note;\n    }\n  }\n  const saveUrl = id ? `/api/schedules/${id}` : '/api/schedules';\n  const saveMethod = id ? 'PUT' : 'POST';\n  try {\n    const saveRes = await fetch(saveUrl, {\n      method: saveMethod,\n      headers: {'Content-Type':'application/json'},\n      body: JSON.stringify(data)\n    });\n    if (!saveRes.ok) {\n      const errBody = await saveRes.text();\n      alert(`保存エラー (${saveRes.status}): ${errBody}`);\n      return;\n    }\n  } catch(e) {\n    alert('通信エラー: ' + e.message);\n    return;\n  }\n\n  // 荷主入力時、積み地＋下ろし先が完全一致する未設定スケジュールに自動反映\n  if (data.client_name && data.load_place && data.unload_place) {\n    const toUpdate = schedules.filter(s =>\n      s.id !== id &&\n      !s.client_name &&\n      s.load_place === data.load_place &&\n      s.unload_place === data.unload_place\n    );\n    for (const s of toUpdate) {\n      await fetch(`/api/schedules/${s.id}`, {\n        method: 'PUT',\n        headers: {'Content-Type':'application/json'},\n        body: JSON.stringify({ client_name: data.client_name })\n      });\n    }\n  }\n\n  closeModal('schedule'); await loadAll();\n}\n\nasync function delSched(id) {\n  if (!confirm('削除しますか？')) return;\n  await fetch(`/api/schedules/${id}`, { method: 'DELETE' });\n  await loadAll();\n  renderSchedules();\n}\n\nasync function delSchedFromHaisha(id) {\n  if (!confirm('削除しますか？')) return;\n  await fetch(`/api/schedules/${id}`, { method: 'DELETE' });\n  await loadAll();\n  renderHaisha();\n}\n\nasync function toggleDayOff(driverId, date) {\n  const current = (dayOffData[date] || []).includes(driverId);\n  if (!current) {\n    // 休みにする → 当日に割り当て済みの仕事があれば警告\n    const hasWork = schedules.some(s =>\n      String(s.driver_id) === driverId && (s.load_date === date || s.unload_date === date)\n    );\n    if (hasWork) {\n      const ok = confirm('このドライバーには当日の配車が割り当て済みです。\\n休みにしてもスケジュールは残ります。よろしいですか？');\n      if (!ok) return;\n    }\n    await fetch('/api/day_off', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ date, driver_id: driverId }),\n    });\n  } else {\n    await fetch('/api/day_off', {\n      method: 'DELETE',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ date, driver_id: driverId }),\n    });\n  }\n  dayOffData = await fetch('/api/day_off').then(r => r.json());\n  renderHaisha();\n}\n\n// ── スポット表示 ────────────────────────────────────────\nfunction openSpotModal() {\n  const date = document.getElementById('haisha-date').value;\n  if (!date) { alert('対象日を選択してください。'); return; }\n\n  // 非表示ドライバーのうち、まだスポット追加されていないもの\n  const spotIds = spotVisibleData[date] || [];\n  const hidden = drivers.filter(d =>\n    d.haisha_visible === false && !spotIds.includes(String(d.id))\n  ).sort((a, b) => (a.display_order ?? 999) - (b.display_order ?? 999));\n\n  if (!hidden.length) {\n    alert('追加できる非表示ドライバーはいません。');\n    return;\n  }\n\n  // 既存モーダルがあれば削除\n  document.getElementById('spot-modal')?.remove();\n\n  const listHtml = hidden.map(d => `\n    <button onclick=\"addSpotVisible('${d.id}','${date}')\"\n      style=\"display:block;width:100%;text-align:left;padding:10px 14px;margin-bottom:6px;border:1px solid #444;border-radius:8px;background:#222;color:#f5f5f5;cursor:pointer;font-size:14px;font-weight:600;\">\n      👤 ${d.name}\n    </button>`).join('');\n\n  const modal = document.createElement('div');\n  modal.id = 'spot-modal';\n  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:9999;display:flex;align-items:center;justify-content:center';\n  modal.innerHTML = `\n    <div style=\"background:#1a1a1a;border-radius:12px;padding:24px;min-width:280px;max-width:360px;box-shadow:0 8px 32px rgba(0,0,0,.2)\">\n      <div style=\"font-weight:700;font-size:15px;margin-bottom:4px\">📍 スポット追加</div>\n      <div style=\"font-size:12px;color:var(--text-sub);margin-bottom:16px\">${date} のみ表示するドライバーを選択</div>\n      ${listHtml}\n      <button onclick=\"document.getElementById('spot-modal').remove()\"\n        style=\"margin-top:8px;width:100%;padding:8px;border:1px solid #444;border-radius:8px;background:#1a1a1a;color:#888;cursor:pointer;font-size:13px;\">\n        キャンセル\n      </button>\n    </div>`;\n  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });\n  document.body.appendChild(modal);\n}\n\nasync function addSpotVisible(driverId, date) {\n  await fetch('/api/spot_visible', {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ date, driver_id: driverId }),\n  });\n  document.getElementById('spot-modal')?.remove();\n  spotVisibleData = await fetch('/api/spot_visible').then(r => r.json());\n  renderHaisha();\n}\n\nasync function removeSpotVisible(driverId, date) {\n  await fetch('/api/spot_visible', {\n    method: 'DELETE',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ date, driver_id: driverId }),\n  });\n  spotVisibleData = await fetch('/api/spot_visible').then(r => r.json());\n  renderHaisha();\n}\n\n// ── 荷物リスト（一件追加用） ─────────────────────────────\nlet sCoilCount = 0;\nlet sOtherCargoCount = 0;\n\nfunction onSCargoTypeChange() {\n  const type = document.getElementById('s-cargo-type').value.trim();\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  document.getElementById('s-coil-section').style.display        = isCoilType ? 'block' : 'none';\n  document.getElementById('s-other-cargo-section').style.display = (!isCoilType && type) ? 'block' : 'none';\n  if (isCoilType && document.getElementById('s-coil-list').children.length === 0) addSCoil();\n  if (!isCoilType && type && document.getElementById('s-other-cargo-list').children.length === 0) addSOtherCargo();\n}\n\nfunction addSCoil() {\n  sCoilCount++;\n  const id = `s-coil-${sCoilCount}`;\n  const div = document.createElement('div');\n  div.className = 'cargo-item';\n  div.id = id;\n  div.innerHTML = `\n    <span class=\"cargo-num\">#${sCoilCount}</span>\n    <input class=\"inp-weight\" placeholder=\"重量(kg)\" type=\"number\" step=\"1\" min=\"0\" oninput=\"calcSCargoTotal()\">\n    <button class=\"cargo-del\" onclick=\"removeSCargo('${id}','coil')\" title=\"削除\">×</button>`;\n  document.getElementById('s-coil-list').appendChild(div);\n}\n\nfunction addSOtherCargo() {\n  sOtherCargoCount++;\n  const id = `s-othercargo-${sOtherCargoCount}`;\n  const div = document.createElement('div');\n  div.className = 'cargo-item';\n  div.id = id;\n  div.innerHTML = `\n    <span class=\"cargo-num\">#${sOtherCargoCount}</span>\n    <input class=\"inp-weight\" placeholder=\"重量(kg)\" type=\"number\" step=\"1\" min=\"0\" oninput=\"calcSCargoTotal()\">\n    <button class=\"cargo-del\" onclick=\"removeSCargo('${id}','other')\" title=\"削除\">×</button>`;\n  document.getElementById('s-other-cargo-list').appendChild(div);\n}\n\nfunction removeSCargo(id, type) {\n  document.getElementById(id)?.remove();\n  calcSCargoTotal();\n}\n\nfunction calcSCargoTotal() {\n  const type = document.getElementById('s-cargo-type').value;\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  const listId  = isCoilType ? 's-coil-list' : 's-other-cargo-list';\n  const totalId = isCoilType ? 's-coil-total' : 's-other-cargo-total';\n  const items = document.querySelectorAll(`#${listId} .inp-weight`);\n  let sum = 0;\n  items.forEach(el => { sum += parseFloat(el.value) || 0; });\n  sum = Math.round(sum * 10) / 10;\n  document.getElementById(totalId).textContent = sum;\n  document.getElementById('s-weight').value = sum || '';\n}\n\nfunction resetSCargoSection() {\n  sCoilCount = 0; sOtherCargoCount = 0;\n  document.getElementById('s-cargo-type').value = '';\n  document.getElementById('s-coil-list').innerHTML = '';\n  document.getElementById('s-other-cargo-list').innerHTML = '';\n  document.getElementById('s-coil-section').style.display = 'none';\n  document.getElementById('s-other-cargo-section').style.display = 'none';\n  document.getElementById('s-coil-total').textContent = '0';\n  document.getElementById('s-other-cargo-total').textContent = '0';\n}\n\n// 荷物情報をnote用テキストとitemsオブジェクト配列に変換\nfunction buildSCargoResult() {\n  const type = document.getElementById('s-cargo-type').value.trim();\n  if (!type) return { note: '', items: null };\n  const label = type;\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  const listId = isCoilType ? 's-coil-list' : 's-other-cargo-list';\n  const rows = document.querySelectorAll(`#${listId} .cargo-item`);\n  const items = [];\n  const lines = [];\n  rows.forEach((row, i) => {\n    const w = row.querySelector('.inp-weight').value;\n    items.push({ name: `${label}${i+1}`, weight: w || '' });\n    if (w) lines.push(`${label}${i+1}：${w}kg`);\n  });\n  return { note: lines.join(' / '), items: items.length ? items : null };\n}\n\n// ── 荷物リスト（まとめて配車用） ──────────────────────────\nlet coilCount = 0;\nlet otherCargoCount = 0;\n\nfunction onCargoTypeChange() {\n  const type = document.getElementById('b-cargo-type').value.trim();\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  document.getElementById('coil-section').style.display        = isCoilType ? 'block' : 'none';\n  document.getElementById('other-cargo-section').style.display = (!isCoilType && type) ? 'block' : 'none';\n  if (isCoilType && document.getElementById('coil-list').children.length === 0) addCoil();\n  if (!isCoilType && type && document.getElementById('other-cargo-list').children.length === 0) addOtherCargo();\n}\n\nfunction addCoil() {\n  coilCount++;\n  const id = `coil-${coilCount}`;\n  const div = document.createElement('div');\n  div.className = 'cargo-item';\n  div.id = id;\n  div.innerHTML = `\n    <span class=\"cargo-num\">#${coilCount}</span>\n    <input class=\"inp-weight\" placeholder=\"重量(kg)\" type=\"number\" step=\"1\" min=\"0\" oninput=\"calcCargoTotal()\">\n    <button class=\"cargo-del\" onclick=\"removeCargo('${id}','coil')\" title=\"削除\">×</button>`;\n  document.getElementById('coil-list').appendChild(div);\n}\n\nfunction addOtherCargo() {\n  otherCargoCount++;\n  const id = `othercargo-${otherCargoCount}`;\n  const div = document.createElement('div');\n  div.className = 'cargo-item';\n  div.id = id;\n  div.innerHTML = `\n    <span class=\"cargo-num\">#${otherCargoCount}</span>\n    <input class=\"inp-weight\" placeholder=\"重量(kg)\" type=\"number\" step=\"1\" min=\"0\" oninput=\"calcCargoTotal()\">\n    <button class=\"cargo-del\" onclick=\"removeCargo('${id}','other')\" title=\"削除\">×</button>`;\n  document.getElementById('other-cargo-list').appendChild(div);\n}\n\nfunction removeCargo(id, type) {\n  document.getElementById(id)?.remove();\n  calcCargoTotal();\n}\n\nfunction calcCargoTotal() {\n  const type = document.getElementById('b-cargo-type').value;\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  const listId  = isCoilType ? 'coil-list'  : 'other-cargo-list';\n  const totalId = isCoilType ? 'coil-total' : 'other-cargo-total';\n  const items = document.querySelectorAll(`#${listId} .inp-weight`);\n  let sum = 0;\n  items.forEach(el => { sum += parseFloat(el.value) || 0; });\n  sum = Math.round(sum * 10) / 10;\n  document.getElementById(totalId).textContent = sum;\n  // 合計重量フィールドに自動反映\n  document.getElementById('b-total').value = sum || '';\n  updateBulkPreview();\n}\n\nfunction resetCargoSection() {\n  coilCount = 0; otherCargoCount = 0;\n  document.getElementById('b-cargo-type').value = '';\n  document.getElementById('coil-list').innerHTML = '';\n  document.getElementById('other-cargo-list').innerHTML = '';\n  document.getElementById('coil-section').style.display = 'none';\n  document.getElementById('other-cargo-section').style.display = 'none';\n  document.getElementById('coil-total').textContent = '0';\n  document.getElementById('other-cargo-total').textContent = '0';\n}\n\n// 荷物の内容をメモ用テキストに変換\nfunction buildCargoNote() {\n  const { cargoNote, note } = buildBulkCargoResult();\n  return [cargoNote, note].filter(Boolean).join('　');\n}\nfunction buildBulkCargoResult() {\n  const type = document.getElementById('b-cargo-type').value.trim();\n  const noteBase = document.getElementById('b-note').value.trim();\n  if (!type) return { cargoNote: '', note: noteBase };\n  const isCoilType = ['コイル','亜鉛コイル'].includes(type);\n  const listId = isCoilType ? 'coil-list' : 'other-cargo-list';\n  const items = document.querySelectorAll(`#${listId} .cargo-item`);\n  const lines = [];\n  items.forEach((item, i) => {\n    const w = item.querySelector('.inp-weight').value;\n    if (w) lines.push(`${type}${i+1}：${w}kg`);\n  });\n  return { cargoNote: lines.join(' / '), note: noteBase };\n}\n\n// ── まとめて配車 ──────────────────────────────────────────\nfunction checkBulkAvail() {\n  const ld = document.getElementById('b-load-date').value;\n  const ud = document.getElementById('b-unload-date').value;\n  if (!ld || !ud) { alert('先に日付を入力してください'); return; }\n\n  // 相積み前提なので全車両を表示（既存積載量も表示）\n  const av = vehicles;\n  bulkSelected = new Set();\n\n  const ld2 = document.getElementById('b-load-date').value;\n  const ud2 = document.getElementById('b-unload-date').value;\n\n  document.getElementById('bulk-v-list').innerHTML = av.length\n    ? av.map(v => {\n        const l = v.kind === 'トレーラー' ? `[T] ${v.head_number} / ${v.trailer_number}` : v.number;\n        const existW = schedules\n          .filter(s => String(s.vehicle_id) === String(v.id) && s.load_date <= ud2 && s.unload_date >= ld2)\n          .reduce((acc, s) => acc + (parseFloat(s.weight) || 0), 0);\n        const existStr = existW > 0\n          ? `<span style=\"color:var(--accent);font-weight:600\">${Math.round(existW*10)/10}t積み済み</span>`\n          : '空き';\n        return `<div class=\"candidate-item\" id=\"bv-${v.id}\">\n          <input type=\"checkbox\" value=\"${v.id}\" onchange=\"onBulkCheck(this,${v.id})\">\n          <div>\n            <div class=\"c-name\">${l}</div>\n            <div class=\"c-sub\">${v.kind}　最大 ${v.payload||'?'}kg　${existStr}</div>\n          </div>\n        </div>`;\n      }).join('')\n    : '<div class=\"no-candidate\">車両が登録されていません</div>';\n\n  document.getElementById('bulk-v-wrap').style.display = 'block';\n  document.getElementById('bulk-preview-wrap').style.display = 'none';\n}\n\nfunction onBulkCheck(cb, vid) {\n  const el = document.getElementById(`bv-${vid}`);\n  if (cb.checked) { bulkSelected.add(vid); el.classList.add('selected'); }\n  else            { bulkSelected.delete(vid); el.classList.remove('selected'); }\n  updateBulkPreview();\n}\n\nfunction updateBulkPreview() {\n  const total = parseFloat(document.getElementById('b-total').value) || 0;\n  const sel   = vehicles.filter(v => bulkSelected.has(v.id));\n  if (!sel.length || !total) { document.getElementById('bulk-preview-wrap').style.display = 'none'; return; }\n\n  const ld = document.getElementById('b-load-date').value;\n  const ud = document.getElementById('b-unload-date').value;\n\n  // 各車両の既存積載量（同期間の割当済みスケジュールの合計）\n  const existing = sel.map(v => {\n    const sum = schedules\n      .filter(s =>\n        String(s.vehicle_id) === String(v.id) &&\n        s.load_date <= ud && s.unload_date >= ld\n      )\n      .reduce((acc, s) => acc + (parseFloat(s.weight) || 0), 0);\n    return Math.round(sum * 10) / 10;\n  });\n\n  const totalExisting = existing.reduce((a, b) => a + b, 0);\n  // 目標：全車両が均等になるよう平均を取る\n  const target = Math.round((totalExisting + total) / sel.length * 10) / 10;\n\n  // 各車への追加分 = target - existing（マイナスになる場合は 0）\n  let alloc = sel.map((v, i) => ({\n    v,\n    existing: existing[i],\n    w: Math.max(0, Math.round((target - existing[i]) * 10) / 10),\n  }));\n\n  // 端数調整（追加合計が total と合うように最後の車両に乗せる）\n  const allocSum = alloc.reduce((s, a) => s + a.w, 0);\n  const diff = Math.round((total - allocSum) * 10) / 10;\n  // diff を受け取れる車両（既存≤target）の最後に加える\n  const adj = [...alloc].reverse().find(a => a.w > 0 || a.existing < target);\n  if (adj) adj.w = Math.round((adj.w + diff) * 10) / 10;\n\n  // バー表示用の最大値（既存＋追加の合計）\n  const maxTotal = Math.max(...alloc.map(a => a.existing + a.w), 0.1);\n\n  document.getElementById('bulk-preview').innerHTML = alloc.map(a => {\n    const l    = a.v.kind === 'トレーラー' ? `[T] ${a.v.head_number}` : a.v.number;\n    const p    = payloadKg(a.v);\n    const afterTotal = Math.round((a.existing + a.w) * 10) / 10;\n    const over = p > 0 && afterTotal > p;\n    const existPct = Math.round(a.existing / maxTotal * 100);\n    const newPct   = Math.round(a.w        / maxTotal * 100);\n\n    const existBar = a.existing > 0\n      ? `<div style=\"width:${existPct}%;background:#666;height:7px;border-radius:6px 0 0 6px;display:inline-block\"></div>`\n      : '';\n    const newBar = a.w > 0\n      ? `<div style=\"width:${newPct}%;background:var(--accent);height:7px;${a.existing>0?'border-radius:0 6px 6px 0':'border-radius:6px'};display:inline-block\"></div>`\n      : '';\n\n    return `<div class=\"alloc-item\">\n      <div class=\"alloc-name\">\n        ${l}\n        ${a.existing > 0 ? `<span style=\"font-size:11px;color:#64748b;font-weight:400;margin-left:6px\">既存 ${a.existing}kg</span>` : ''}\n      </div>\n      <div class=\"alloc-bar-wrap\" style=\"display:flex;align-items:center\">${existBar}${newBar}</div>\n      <div class=\"alloc-weight ${over ? 'alloc-warn' : ''}\">\n        +${a.w}kg\n        <span style=\"font-size:11px;color:#64748b;font-weight:400\"> → 計${afterTotal}kg</span>\n        ${over ? ' ⚠️' : ''}\n      </div>\n    </div>`;\n  }).join('');\n\n  const hasWarn = alloc.some(a => { const p = payloadKg(a.v); return p > 0 && (a.existing + a.w) > p; });\n  document.getElementById('bulk-warn').textContent = hasWarn ? '⚠️ 最大積載量を超えている車両があります。' : '';\n  document.getElementById('bulk-preview-wrap').style.display = 'block';\n  bulkAlloc = alloc;\n}\n\nasync function saveBulk(cargoOnly = false) {\n  const ld = document.getElementById('b-load-date').value;\n  const lp = document.getElementById('b-load-place').value.trim();\n  const ud = document.getElementById('b-unload-date').value;\n  const up = document.getElementById('b-unload-place').value.trim();\n  const { cargoNote: bulkCargoNote, note: bulkNote } = buildBulkCargoResult();\n  const total = parseFloat(document.getElementById('b-total').value) || 0;\n\n  if (!ld || !lp) { alert('積み込み日と積み込み場所は必須です'); return; }\n\n  if (cargoOnly) {\n    // 車両なしで1件まとめて登録\n    await fetch('/api/schedules', {\n      method: 'POST',\n      headers: {'Content-Type':'application/json'},\n      body: JSON.stringify({ load_date:ld, load_place:lp, unload_date:ud, unload_place:up, weight:String(total), vehicle_id:'', driver_id:'', note:bulkNote, cargo_note:bulkCargoNote })\n    });\n  } else {\n    if (!bulkAlloc.length) { alert('車両を選択してください'); return; }\n    for (const a of bulkAlloc) {\n      await fetch('/api/schedules', {\n        method: 'POST',\n        headers: {'Content-Type':'application/json'},\n        body: JSON.stringify({ load_date:ld, load_place:lp, unload_date:ud, unload_place:up, weight:String(a.w), vehicle_id:String(a.v.id), driver_id:'', note:bulkNote, cargo_note:bulkCargoNote })\n      });\n    }\n  }\n  closeModal('bulk'); await loadAll(); switchPage('schedules');\n}\n\n// ── ダッシュボード（週間カレンダー）──────────────────────────\nlet dashWeekOffset = 0;\n\nfunction renderDashboard() {\n  const today = new Date();\n  today.setHours(0, 0, 0, 0);\n\n  // 今週の月曜日を基点にoffset週分ずらす\n  const dayOfWeek = today.getDay(); // 0=日\n  const diffToMon = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;\n  const monday = new Date(today);\n  monday.setDate(today.getDate() + diffToMon + dashWeekOffset * 7);\n\n  const days = Array.from({ length: 7 }, (_, i) => {\n    const d = new Date(monday);\n    d.setDate(monday.getDate() + i);\n    return d;\n  });\n\n  const fmt = d => {\n    const y = d.getFullYear();\n    const m = String(d.getMonth() + 1).padStart(2, '0');\n    const day = String(d.getDate()).padStart(2, '0');\n    return `${y}-${m}-${day}`;\n  };\n  const todayStr = fmt(today);\n  const dayNames = ['月', '火', '水', '木', '金', '土', '日'];\n\n  const startStr = fmt(days[0]);\n  const endStr   = fmt(days[6]);\n  document.getElementById('dash-week-label').textContent =\n    `${startStr} 〜 ${endStr}`;\n\n  const cal = document.getElementById('dash-calendar');\n  cal.innerHTML = days.map((d, wi) => {\n    const dateStr = fmt(d);\n    const isToday = dateStr === todayStr;\n    const isPast  = dateStr < todayStr;\n    const isSat   = wi === 5;\n    const isSun   = wi === 6;\n\n    // その日に関係するスケジュール（下ろし日が当日）— 完了・未完了両方\n    const dayScheds   = schedules.filter(s => s.unload_date === dateStr);\n    const active      = dayScheds.filter(s => !s.done);\n    const done        = dayScheds.filter(s =>  s.done);\n    const unassigned  = active.filter(s => !s.driver_id || s.driver_id === '');\n    const assigned    = active.filter(s =>  s.driver_id && s.driver_id !== '');\n\n    const headerBg = isToday ? '#3b62c9' : isSun ? '#1a1212' : isSat ? '#121218' : '#1a1a1a';\n    const headerColor = isToday ? '#fff' : isSun ? '#d32f2f' : isSat ? '#3b62c9' : 'var(--text-sub)';\n    const borderColor = isToday ? '#3b62c9' : 'var(--border)';\n\n    const chips = assigned.map(s => {\n      const dname = dLabel(s.driver_id).replace(/\\s+/g, '');\n      const place = s.unload_place || '?';\n      const weight = s.weight ? `${Number(s.weight).toLocaleString('ja-JP')}kg` : '';\n      const hasVio = (() => {\n        const v = vehicles.find(vv => String(vv.id) === String(s.vehicle_id));\n        const w = parseFloat(s.weight), p = parseFloat(v?.payload);\n        return !isNaN(w) && !isNaN(p) && w > p;\n      })();\n      return `<div style=\"background:${hasVio?'rgba(239,68,68,0.12)':'rgba(79,126,248,0.12)'};border:1px solid ${hasVio?'rgba(239,68,68,0.3)':'rgba(79,126,248,0.3)'};border-radius:5px;padding:3px 7px;margin-bottom:3px;font-size:11px;line-height:1.4;cursor:pointer\"\n        onclick=\"switchPage('haisha');document.getElementById('haisha-date').value='${dateStr}';renderHaisha()\"\n        title=\"${place} ${weight}\">\n        <span style=\"font-weight:700;color:${hasVio?'#dc2626':'#3b62c9'}\">${dname}</span>\n        <span style=\"color:#777;margin-left:3px\">${place}</span>\n        ${weight ? `<span style=\"color:#aaa;margin-left:2px;font-size:10px\">${weight}</span>` : ''}\n        ${hasVio ? '<span style=\"color:#dc2626;font-weight:700\"> ⚠️</span>' : ''}\n      </div>`;\n    }).join('');\n\n    // 完了済みチップ\n    const doneChips = done.map(s => {\n      const dname = dLabel(s.driver_id).replace(/\\s+/g, '');\n      const place = s.unload_place || '?';\n      const weight = s.weight ? `${Number(s.weight).toLocaleString('ja-JP')}kg` : '';\n      return `<div style=\"background:rgba(136,136,136,0.1);border:1px solid #555;border-radius:5px;padding:3px 7px;margin-bottom:3px;font-size:11px;line-height:1.4;opacity:0.7\">\n        <span style=\"color:#aaa\">✅</span>\n        <span style=\"font-weight:700;color:#aaa;margin-left:2px\">${dname}</span>\n        <span style=\"color:#777;margin-left:3px\">${place}</span>\n        ${weight ? `<span style=\"color:#bbb;margin-left:2px;font-size:10px\">${weight}</span>` : ''}\n      </div>`;\n    }).join('');\n\n    const unassignedTag = unassigned.length\n      ? unassigned.map(s => {\n          const place = s.unload_place || '?';\n          const weight = s.weight ? `${Number(s.weight).toLocaleString('ja-JP')}kg` : '';\n          const cargo = s.cargo_note || '';\n          return `<div style=\"background:rgba(245,158,11,0.12);border:1px solid rgba(245,158,11,0.3);border-radius:5px;padding:3px 7px;margin-bottom:3px;font-size:11px;line-height:1.4;cursor:pointer\"\n            onclick=\"switchPage('haisha');document.getElementById('haisha-date').value='${dateStr}';renderHaisha()\"\n            title=\"${place} ${weight}\">\n            <span style=\"font-weight:700;color:#856404\">⚠️ 未割当</span>\n            <span style=\"color:#5c4300;margin-left:3px\">${place}</span>\n            ${weight ? `<span style=\"color:#aaa;margin-left:2px;font-size:10px\">${weight}</span>` : ''}\n            ${cargo ? `<span style=\"color:#0891b2;margin-left:2px;font-size:10px\">${cargo}</span>` : ''}\n          </div>`;\n        }).join('')\n      : '';\n\n    const emptyMsg = !dayScheds.length\n      ? `<div style=\"font-size:11px;color:#555;text-align:center;padding:8px 0\">予定なし</div>`\n      : '';\n\n    return `<div style=\"border:1.5px solid ${borderColor};border-radius:8px;overflow:hidden;${isPast?'opacity:0.6':''}\">\n      <div style=\"background:${headerBg};color:${headerColor};padding:6px 10px;font-weight:700;font-size:13px;display:flex;align-items:center;justify-content:space-between\">\n        <span>${dayNames[wi]}  ${d.getMonth()+1}/${d.getDate()}</span>\n        ${dayScheds.length ? `<span style=\"background:${isToday?'rgba(255,255,255,0.25)':'rgba(0,0,0,0.08)'};border-radius:10px;padding:1px 7px;font-size:11px\">${dayScheds.length}件</span>` : ''}\n      </div>\n      <div style=\"padding:6px 8px;min-height:60px\">\n        ${chips}\n        ${unassignedTag}\n        ${doneChips ? `<div style=\"margin-top:${(chips||unassignedTag)?'6px':'0'};padding-top:${(chips||unassignedTag)?'5px':'0'};${(chips||unassignedTag)?'border-top:1px solid #e8e8e8':''}\">${doneChips}</div>` : ''}\n        ${emptyMsg}\n      </div>\n    </div>`;\n  }).join('');\n}\n\n// モーダル外クリックで閉じる\ndocument.querySelectorAll('.modal-overlay').forEach(el => {\n  el.addEventListener('click', e => { if (e.target === el) el.classList.remove('open'); });\n});\n\n// ── 配車予定表 ─────────────────────────────────────────────\nlet haishaDateVal = '';\nlet dragSchedId = null;\nlet dragGroupId = null;  // 相積みグループドラッグ用\nlet haishaVehicleMap = {}; // { driverId: vehicleId } — その日の車両割当\nlet haishaDriverMap  = {}; // { uid: driverId } — 空き行のドライバー割当\nlet haishaTextMap    = {}; // { uid: {name, vehicleNum, payload} } — 手打ち入力の保持\n\n// 初期日付：明日\n(function initHaishaDate() {\n  const d = new Date();\n  d.setDate(d.getDate() + 1);\n  const s = d.toISOString().split('T')[0];\n  document.getElementById('haisha-date').value = s;\n  haishaDateVal = s;\n})();\n\n// 車番を短い形式に変換（セル内表示用・2行）\nfunction haishaVnumShort(v) {\n  if (!v) return '—';\n  if (v.kind === 'トレーラー') {\n    const h = (v.head_number   || '').match(/(\\d+)\\s*$/)?.[1] || '';\n    const t = (v.trailer_number|| '').match(/(\\d+)\\s*$/)?.[1] || '';\n    if (h && t) return `<span style=\"display:block;font-weight:700\">${h}</span><span style=\"display:block;color:var(--text-sub)\">${t}</span>`;\n    return h || t || '—';\n  }\n  const n = (v.number || '').match(/(\\d+)\\s*$/)?.[1] || v.number || '—';\n  return `<span style=\"font-weight:700\">${n}</span>`;\n}\n\n// セレクト用ラベル（1行）\nfunction haishaVnumLabel(v) {\n  if (!v) return '—';\n  if (v.kind === 'トレーラー') {\n    const h = (v.head_number   || '').match(/(\\d+)\\s*$/)?.[1] || '';\n    const t = (v.trailer_number|| '').match(/(\\d+)\\s*$/)?.[1] || '';\n    return (h && t) ? `${h}/${t}` : h || t || '—';\n  }\n  return (v.number || '').match(/(\\d+)\\s*$/)?.[1] || v.number || '—';\n}\n\n// 車両セレクトのHTML\nfunction haishaVehicleSelect(driverId, currentVid) {\n  const opts = vehicles.map(v => {\n    const label = `${haishaVnumLabel(v)}（${v.payload}kg）`;\n    const sel = String(currentVid) === String(v.id) ? 'selected' : '';\n    return `<option value=\"${v.id}\" ${sel}>${label}</option>`;\n  }).join('');\n  return `<select class=\"haisha-vsel\" onchange=\"haishaSetVehicle('${driverId}',this.value)\">\n    <option value=\"\">— 未選択 —</option>\n    ${opts}\n  </select>`;\n}\n\nasync function haishaSetVehicle(driverId, vehicleId) {\n  haishaVehicleMap[driverId] = vehicleId;\n  renderHaisha();\n  // ドライバーのデフォルト車両として保存（y_傭車は除く）\n  if (!String(driverId).startsWith('y_')) {\n    const d = drivers.find(x => String(x.id) === String(driverId));\n    if (d) {\n      const updated = { ...d, default_vehicle_id: vehicleId || null };\n      const res = await fetch(`/api/drivers/${d.id}`, {\n        method: 'PUT',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify(updated),\n      });\n      if (res.ok) {\n        const saved = await res.json();\n        const idx = drivers.findIndex(x => x.id === d.id);\n        if (idx !== -1) drivers[idx] = saved;\n      }\n    }\n  }\n}\n\nfunction haishaTextSave(uid, field, value) {\n  if (!haishaTextMap[uid]) haishaTextMap[uid] = {};\n  haishaTextMap[uid][field] = value;\n  // 再レンダリングはしない（入力中にフォーカスが外れるのを防ぐ）\n}\n\n// ── ✂️ 配達分割 ───────────────────────────────────────────\nlet splitSchedId = null;\nlet splitGroups  = []; // [{items:[{name,weight}]}]\nlet splitPool    = []; // 未割当アイテム\nlet splitDragItem = null;\nlet splitDragFrom = null; // 'pool' | groupIndex\n\n// cargo_note / noteから荷物リストを解析（kg表記対応）\nfunction parseSplitItems(s) {\n  const src = s.cargo_note || s.note || '';\n  // 「荷物名N：Wkg」または旧形式「荷物名N：Wt」形式\n  const coilMatches = [...src.matchAll(/([^\\s/　]+\\d+)[：:]\\s*([\\d.]+)(kg|t)/g)];\n  if (coilMatches.length > 0) {\n    return coilMatches.map(m => ({\n      name: m[1].trim(),\n      weight: m[3] === 't' ? parseFloat(m[2]) * 1000 : parseFloat(m[2]),\n    }));\n  }\n  // 解析できない場合は単一アイテム\n  return [{ name: s.unload_place, weight: parseFloat(s.weight) || 0 }];\n}\n\nfunction openSplit(schedId) {\n  splitSchedId = schedId;\n  const s = schedules.find(x => x.id === schedId);\n  if (!s) return;\n\n  const items = parseSplitItems(s);\n  splitPool   = items.map((it, i) => ({ id: i, ...it }));\n  splitGroups = [];\n\n  document.getElementById('split-origin-info').innerHTML =\n    `<strong>${s.unload_place}</strong>　合計 ${s.weight}kg\n     <span style=\"color:var(--text-sub)\">${s.load_date} 積込 → ${s.unload_date} 下ろし</span>`;\n\n  renderSplitModal();\n  document.getElementById('split-overlay').style.display = 'flex';\n}\nfunction closeSplit() {\n  document.getElementById('split-overlay').style.display = 'none';\n  splitSchedId = null;\n}\n\nfunction renderSplitModal() {\n  // プール\n  const poolEl = document.getElementById('split-items-pool');\n  poolEl.innerHTML = splitPool.length\n    ? splitPool.map(it => splitChipHTML(it, 'pool')).join('')\n    : '<span style=\"font-size:12px;color:#bbb\">すべてグループに割り当て済み</span>';\n\n  // グループ\n  const groupsEl = document.getElementById('split-groups');\n  const slotLabels = ['配達①','配達②','配達③','配達④','配達⑤','配達⑥'];\n  groupsEl.innerHTML = splitGroups.map((g, gi) => {\n    const total = g.items.reduce((s, it) => s + (it.weight || 0), 0);\n    const items = g.items.map(it => splitChipHTML(it, gi)).join('');\n    return `<div class=\"split-group-box\">\n      <div class=\"split-group-header\">\n        <span class=\"split-group-label\">${slotLabels[gi] || `配達${gi+1}`}</span>\n        <span class=\"split-group-total\">${Math.round(total).toLocaleString('ja-JP')}kg</span>\n        <button onclick=\"removeSplitGroup(${gi})\" style=\"margin-left:auto;background:none;border:none;color:#bbb;cursor:pointer;font-size:16px\">×</button>\n      </div>\n      <div class=\"split-group-drop\"\n           ondragover=\"event.preventDefault();this.classList.add('split-drag-over')\"\n           ondragleave=\"this.classList.remove('split-drag-over')\"\n           ondrop=\"splitDropToGroup(event,${gi})\">\n        ${items || '<span style=\"font-size:12px;color:#bbb\">ここにドロップ</span>'}\n      </div>\n    </div>`;\n  }).join('');\n}\n\nfunction splitChipHTML(it, from) {\n  const fromStr = from === 'pool' ? 'pool' : String(from);\n  return `<span class=\"split-chip\" draggable=\"true\"\n    ondragstart=\"splitDragStart(event,${it.id},'${fromStr}')\"\n    ondragend=\"this.classList.remove('dragging')\">\n    <span class=\"chip-name\">${it.name}</span>\n    <span class=\"chip-weight\">${it.weight}kg</span>\n  </span>`;\n}\n\nfunction splitDragStart(event, itemId, from) {\n  splitDragItem = itemId;\n  splitDragFrom = from === 'pool' ? 'pool' : parseInt(from);\n  event.dataTransfer.effectAllowed = 'move';\n  setTimeout(() => event.target.classList.add('dragging'), 0);\n}\n\nfunction splitDropToGroup(event, groupIndex) {\n  event.preventDefault();\n  event.currentTarget.classList.remove('split-drag-over');\n  if (splitDragItem === null) return;\n\n  const item = _removeSplitItem(splitDragItem, splitDragFrom);\n  if (!item) return;\n  splitGroups[groupIndex].items.push(item);\n  splitDragItem = null;\n  renderSplitModal();\n}\n\nfunction splitDropToPool(event) {\n  event.preventDefault();\n  document.getElementById('split-items-pool').classList.remove('split-drag-over');\n  if (splitDragItem === null) return;\n\n  const item = _removeSplitItem(splitDragItem, splitDragFrom);\n  if (!item) return;\n  splitPool.push(item);\n  splitDragItem = null;\n  renderSplitModal();\n}\n\nfunction _removeSplitItem(itemId, from) {\n  if (from === 'pool') {\n    const idx = splitPool.findIndex(x => x.id === itemId);\n    if (idx < 0) return null;\n    return splitPool.splice(idx, 1)[0];\n  } else {\n    const g = splitGroups[from];\n    if (!g) return null;\n    const idx = g.items.findIndex(x => x.id === itemId);\n    if (idx < 0) return null;\n    return g.items.splice(idx, 1)[0];\n  }\n}\n\nfunction addSplitGroup() {\n  if (splitGroups.length >= 6) return;\n  splitGroups.push({ items: [] });\n  // プールの未割当をすべて新グループに振り分けるヒント\n  renderSplitModal();\n}\n\nfunction removeSplitGroup(gi) {\n  const g = splitGroups.splice(gi, 1)[0];\n  splitPool.push(...g.items);\n  renderSplitModal();\n}\n\nasync function confirmSplit() {\n  if (!splitSchedId) return;\n  const s = schedules.find(x => x.id === splitSchedId);\n  if (!s) return;\n\n  // 未割当アイテムがあれば警告\n  if (splitPool.length > 0) {\n    if (!confirm(`${splitPool.length}個の荷物がグループに入っていません。残りは元のスケジュールの重量から省かれます。続けますか？`)) return;\n  }\n\n  // 空グループを除外\n  const validGroups = splitGroups.filter(g => g.items.length > 0);\n  if (!validGroups.length) {\n    alert('グループを1つ以上作ってください');\n    return;\n  }\n\n  // 元スケジュールを削除して、グループ数分の新スケジュールを作成\n  await fetch(`/api/schedules/${s.id}`, { method: 'DELETE' });\n\n  for (const g of validGroups) {\n    const totalW = g.items.reduce((acc, it) => acc + (it.weight || 0), 0);\n    const noteStr = g.items.map(it => `${it.name}：${it.weight}kg`).join(' / ');\n    const newSched = {\n      ...s,\n      weight: String(Math.round(totalW)),\n      note: noteStr,\n    };\n    delete newSched.id;\n    await fetch('/api/schedules', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify(newSched),\n    });\n  }\n\n  closeSplit();\n  await loadAll();\n  renderHaisha();\n}\n\n// ── 配車予定表 保存・履歴 ─────────────────────────────────\nasync function saveDispatchPlan() {\n  const date = haishaDateVal;\n  if (!date) { alert('日付を選択してください'); return; }\n\n  const preloaded  = schedules.filter(s => s.unload_date === date && s.load_date < date);\n  const deliveries = schedules.filter(s => s.load_date === date && s.unload_date === date);\n\n  // ドライバー行スナップショット\n  const activeDidSet = new Set([\n    ...preloaded.filter(s=>s.driver_id).map(s=>String(s.driver_id)),\n    ...deliveries.filter(s=>s.driver_id).map(s=>String(s.driver_id)),\n  ]);\n  const driverRows = drivers\n    .filter(d => activeDidSet.has(String(d.id)))\n    .sort((a,b) => (a.display_order??999)-(b.display_order??999))\n    .map(d => {\n      const did = String(d.id);\n      const vid = haishaVehicleMap[did] || (deliveries.find(s=>s.driver_id===did)||preloaded.find(s=>s.driver_id===did))?.vehicle_id || '';\n      const v = vehicles.find(v=>String(v.id)===String(vid));\n      return {\n        type: 'driver',\n        driver_id: d.id,\n        driver_name: d.name.replace(/\\s+/g,''),\n        vehicle_number: v ? haishaVnumLabel(v) : '',\n        payload_kg: v ? Number(parseFloat(v.payload) || 0) : null,\n        preloaded: preloaded.filter(s=>s.driver_id===did).map(s=>({place:s.unload_place,weight:s.weight,cargo_note:s.cargo_note||'',note:s.note})),\n        deliveries: deliveries.filter(s=>s.driver_id===did).map(s=>({place:s.unload_place,weight:s.weight,cargo_note:s.cargo_note||'',note:s.note})),\n      };\n    });\n\n  // 傭車行スナップショット\n  const youshaRows = youshas.sort((a,b)=>(a.display_order??999)-(b.display_order??999)).map(y => {\n    const ykey = `y_${y.id}`;\n    return {\n      type: 'yousha',\n      name: y.display_name,\n      vehicle_number: (y.vehicle_number || y.vehicle_info || ''),\n      payload_kg: Number(parseFloat(y.payload || '0') || 0),\n      preloaded: preloaded.filter(s=>s.driver_id===ykey).map(s=>({place:s.unload_place,weight:s.weight,cargo_note:s.cargo_note||'',note:s.note||''})),\n      deliveries: deliveries.filter(s=>s.driver_id===ykey).map(s=>({place:s.unload_place,weight:s.weight,cargo_note:s.cargo_note||'',note:s.note||''})),\n    };\n  });\n\n  // 空き行スナップショット\n  const customRows = [0,1,2].map(i => {\n    const uid = `__empty_${i}`;\n    const t = haishaTextMap[uid] || {};\n    if (!t.name && !t.vehicleNum) return null;\n    return { type:'custom', driver_name:t.name||'', vehicle_number:t.vehicleNum||'', payload_kg:t.payload||'', deliveries:[] };\n  }).filter(Boolean);\n\n  const plan = {\n    date,\n    label: `${date} 配車予定表`,\n    rows: [...driverRows, ...youshaRows, ...customRows],\n  };\n\n  const res = await fetch('/api/dispatch_plans', {\n    method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(plan),\n  });\n  const saved = await res.json();\n  alert(`保存しました（ID: ${saved.id}）`);\n}\n\nlet dispatchPlans = [];\nasync function openPlanHistory() {\n  dispatchPlans = await fetch('/api/dispatch_plans').then(r=>r.json());\n  const list = document.getElementById('plan-history-list');\n  if (!dispatchPlans.length) {\n    list.innerHTML = '<p style=\"color:var(--text-sub);text-align:center;padding:24px\">保存された配車予定表はありません</p>';\n  } else {\n    list.innerHTML = [...dispatchPlans].sort((a, b) => {\n      const da = a.label.match(/\\d{4}-\\d{2}-\\d{2}/)?.[0] || a.saved_at;\n      const db = b.label.match(/\\d{4}-\\d{2}-\\d{2}/)?.[0] || b.saved_at;\n      return db < da ? -1 : db > da ? 1 : 0; // 新しい日付順\n    }).map(p => `\n      <div style=\"display:flex;align-items:center;gap:12px;padding:14px 16px;border:1px solid var(--border);border-radius:10px;margin-bottom:10px\">\n        <div style=\"flex:1\">\n          <div style=\"font-weight:700;font-size:14px\">${p.label}</div>\n          <div style=\"font-size:12px;color:var(--text-sub);margin-top:3px\">保存日時: ${p.saved_at ? new Date(p.saved_at).toLocaleString('ja-JP',{timeZone:'Asia/Tokyo'}) : ''}</div>\n        </div>\n        <button class=\"btn btn-ghost btn-sm\" onclick=\"viewPlanDetail('${p.id}')\">詳細</button>\n        <button class=\"btn btn-danger btn-sm\" onclick=\"deletePlan('${p.id}')\">削除</button>\n      </div>`).join('');\n  }\n  document.getElementById('plan-history-overlay').style.display = 'flex';\n}\nfunction closePlanHistory() { document.getElementById('plan-history-overlay').style.display='none'; }\n\n// ── 履歴 詳細・編集 ──────────────────────────────────────\nlet editingPlan = null;\nlet hdDragItem = null;   // { rowIndex, area:'pre'|'del', itemIndex }\n\nfunction viewPlanDetail(id) {\n  const p = dispatchPlans.find(x => x.id === id);\n  if (!p) return;\n  editingPlan = JSON.parse(JSON.stringify(p)); // deep copy\n  renderEditDetail();\n  document.getElementById('plan-detail-overlay').style.display = 'flex';\n}\nfunction closePlanDetail() {\n  document.getElementById('plan-detail-overlay').style.display = 'none';\n  editingPlan = null;\n}\n\nfunction renderEditDetail() {\n  if (!editingPlan) return;\n  document.getElementById('plan-detail-title').textContent = editingPlan.label;\n  const slotNames = ['配達①','配達②','配達③','配達④','配達⑤'];\n\n  const rows = editingPlan.rows.map((row, ri) => {\n    const badge = row.type === 'yousha'\n      ? '<span style=\"font-size:10px;background:rgba(245,158,11,0.15);color:#fbbf24;border-radius:4px;padding:1px 5px;margin-left:4px\">傭車</span>' : '';\n\n    // 積置き分セル（ドロップ可）\n    const preCards = (row.preloaded || []).map((d, di) =>\n      hdCardHTML(d, ri, 'pre', di)\n    ).join('');\n\n    // 配達スロット（ドロップ可）\n    const delCells = [0,1,2,3,4].map(i => {\n      const d = (row.deliveries || [])[i];\n      return `<td style=\"padding:6px;border-bottom:1px solid #333;min-width:110px;vertical-align:top\"\n                  ondragover=\"event.preventDefault();this.classList.add('drag-over')\"\n                  ondragleave=\"this.classList.remove('drag-over')\"\n                  ondrop=\"hdDrop(event,${ri},'del',${i})\">\n        <span style=\"font-size:10px;color:#bbb;display:block;margin-bottom:3px\">${slotNames[i]}</span>\n        ${d ? hdCardHTML(d, ri, 'del', i) : ''}\n      </td>`;\n    }).join('');\n\n    return `<tr>\n      <td style=\"padding:8px;border-bottom:1px solid #333;vertical-align:top;white-space:nowrap\">\n        <input class=\"hd-inp\" value=\"${(row.driver_name||row.name||'').replace(/\"/g,'&quot;')}\"\n               oninput=\"hdSet(${ri},'driver_name',this.value)\" style=\"font-weight:700\">${badge}\n      </td>\n      <td style=\"padding:8px;border-bottom:1px solid #333;vertical-align:top\">\n        <input class=\"hd-inp\" value=\"${(row.vehicle_number||'').replace(/\"/g,'&quot;')}\"\n               oninput=\"hdSet(${ri},'vehicle_number',this.value)\">\n      </td>\n      <td style=\"padding:8px;border-bottom:1px solid #333;vertical-align:top;text-align:right;min-width:80px\">\n        <input class=\"hd-inp\" value=\"${row.payload_kg||''}\" type=\"number\"\n               oninput=\"hdSet(${ri},'payload_kg',this.value)\" style=\"text-align:right;width:80px\">\n      </td>\n      <td style=\"padding:6px;border-bottom:1px solid #333;vertical-align:top;min-width:110px\"\n          ondragover=\"event.preventDefault();this.classList.add('drag-over')\"\n          ondragleave=\"this.classList.remove('drag-over')\"\n          ondrop=\"hdDrop(event,${ri},'pre',0)\">\n        <span style=\"font-size:10px;color:#bbb;display:block;margin-bottom:3px\">積置き分</span>\n        ${preCards}\n      </td>\n      ${delCells}\n      <td style=\"padding:8px;border-bottom:1px solid #333;vertical-align:top;min-width:80px\">\n        <input class=\"hd-inp\" value=\"${(row.note||'').replace(/\"/g,'&quot;')}\"\n               oninput=\"hdSet(${ri},'note',this.value)\" placeholder=\"備考\">\n      </td>\n    </tr>`;\n  }).join('');\n\n  document.getElementById('plan-detail-content').innerHTML = `\n    <div style=\"overflow-x:auto\">\n      <table style=\"width:100%;border-collapse:collapse;font-size:13px\">\n        <thead><tr style=\"background:#1a1a1a\">\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">運転手</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">車番</th>\n          <th style=\"padding:10px;text-align:right;font-size:11px;color:var(--text-sub)\">積載量(kg)</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">積置き分</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">配達①</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">配達②</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">配達③</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">配達④</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">配達⑤</th>\n          <th style=\"padding:10px;text-align:left;font-size:11px;color:var(--text-sub)\">備考</th>\n        </tr></thead>\n        <tbody>${rows}</tbody>\n      </table>\n    </div>\n    <div style=\"display:flex;justify-content:flex-end;gap:10px;margin-top:20px;padding-top:16px;border-top:1px solid var(--border)\">\n      <button class=\"btn btn-ghost\" onclick=\"closePlanDetail()\">閉じる</button>\n      <button class=\"btn btn-primary\" onclick=\"savePlanEdits()\">💾 変更を保存</button>\n    </div>`;\n}\n\n// 配達カードHTML（履歴編集用）\nfunction hdCardHTML(d, ri, area, idx) {\n  return `<div class=\"hd-card\" draggable=\"true\"\n    ondragstart=\"hdDragStart(event,${ri},'${area}',${idx})\"\n    ondragend=\"this.classList.remove('dragging')\">\n    <input class=\"hd-card-inp\" value=\"${(d.place||'').replace(/\"/g,'&quot;')}\"\n           oninput=\"hdSetItem(${ri},'${area}',${idx},'place',this.value)\" placeholder=\"場所\">\n    ${d.cargo_note ? `<span style=\"font-size:10px;color:#0891b2;font-weight:600\">${d.cargo_note}</span>` : ''}\n    <input class=\"hd-card-inp\" value=\"${d.weight||''}\" type=\"number\" step=\"1\"\n           oninput=\"hdSetItem(${ri},'${area}',${idx},'weight',this.value)\"\n           placeholder=\"\" style=\"width:60px;text-align:right\">\n    <span style=\"font-size:11px;color:#bbb\">kg</span>\n    <button onclick=\"hdRemoveItem(${ri},'${area}',${idx})\"\n            style=\"background:none;border:none;color:#555;cursor:pointer;font-size:14px;line-height:1;padding:0 0 0 2px\">×</button>\n  </div>`;\n}\n\n// フィールド更新\nfunction hdSet(ri, field, val) {\n  if (!editingPlan) return;\n  editingPlan.rows[ri][field] = val;\n}\nfunction hdSetItem(ri, area, idx, field, val) {\n  if (!editingPlan) return;\n  const arr = area === 'pre' ? editingPlan.rows[ri].preloaded : editingPlan.rows[ri].deliveries;\n  if (arr[idx]) arr[idx][field] = val;\n}\nfunction hdRemoveItem(ri, area, idx) {\n  if (!editingPlan) return;\n  const key = area === 'pre' ? 'preloaded' : 'deliveries';\n  editingPlan.rows[ri][key].splice(idx, 1);\n  renderEditDetail();\n}\n\n// ドラッグ＆ドロップ（履歴内）\nfunction hdDragStart(event, ri, area, idx) {\n  hdDragItem = { ri, area, idx };\n  event.dataTransfer.effectAllowed = 'move';\n  setTimeout(() => event.target.classList.add('dragging'), 0);\n}\nfunction hdDrop(event, toRi, toArea, toIdx) {\n  event.preventDefault();\n  event.currentTarget.classList.remove('drag-over');\n  if (!hdDragItem || !editingPlan) return;\n\n  const fromKey = hdDragItem.area === 'pre' ? 'preloaded' : 'deliveries';\n  const toKey   = toArea === 'pre' ? 'preloaded' : 'deliveries';\n\n  const fromArr = editingPlan.rows[hdDragItem.ri][fromKey];\n  const [item]  = fromArr.splice(hdDragItem.idx, 1);\n\n  const toArr = editingPlan.rows[toRi][toKey];\n  // toIdxが既存アイテムの位置なら入れ替え、なければ末尾に追加\n  if (toArr[toIdx]) {\n    toArr.splice(toIdx, 0, item);\n  } else {\n    toArr.push(item);\n  }\n\n  hdDragItem = null;\n  renderEditDetail();\n}\n\nasync function savePlanEdits() {\n  if (!editingPlan) return;\n  const res = await fetch(`/api/dispatch_plans/${editingPlan.id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify(editingPlan),\n  });\n  if (res.ok) {\n    dispatchPlans = await fetch('/api/dispatch_plans').then(r => r.json());\n    alert('保存しました');\n  } else {\n    alert('保存に失敗しました');\n  }\n}\n\nasync function deletePlan(id) {\n  if (!confirm('この履歴を削除しますか？')) return;\n  await fetch(`/api/dispatch_plans/${id}`, {method:'DELETE'});\n  openPlanHistory();\n}\n\n// ── 空き行へのドロップ ────────────────────────────────────\nasync function hDropEmpty(event, uid) {\n  event.preventDefault();\n  event.currentTarget.classList.remove('drag-over');\n  if (!dragSchedId) return;\n  const sched = schedules.find(s => s.id === dragSchedId);\n  if (!sched) return;\n\n  // 手打ち名がある場合は uid をそのままドライバーIDとして使う\n  const driverId = haishaDriverMap[uid] || uid;\n  const vehicleId = haishaVehicleMap[uid] || '';\n\n  await fetch(`/api/schedules/${sched.id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ ...sched, driver_id: driverId, vehicle_id: vehicleId }),\n  });\n  await loadAll();\n  renderHaisha();\n}\n\n// ── ドライバーピッカー ────────────────────────────────────\nlet _dpickerUid = null;\nfunction openDriverPicker(uid, currentDid) {\n  _dpickerUid = uid;\n  const sel = document.getElementById('dpicker-select');\n  sel.innerHTML = '<option value=\"\">— 未選択 —</option>' +\n    drivers\n      .filter(d => d.status === '稼働中')\n      .sort((a, b) => (a.display_order ?? 999) - (b.display_order ?? 999))\n      .map(d => {\n        const selected = String(currentDid) === String(d.id) ? 'selected' : '';\n        return `<option value=\"${d.id}\" ${selected}>${d.name.replace(/\\s+/g,'')}</option>`;\n      }).join('');\n  document.getElementById('dpicker-overlay').style.display = 'flex';\n}\nfunction closeDriverPicker() {\n  document.getElementById('dpicker-overlay').style.display = 'none';\n  _dpickerUid = null;\n}\nfunction applyDriverPicker() {\n  const did = document.getElementById('dpicker-select').value;\n  if (_dpickerUid !== null) {\n    haishaDriverMap[_dpickerUid] = did;\n  }\n  closeDriverPicker();\n  renderHaisha();\n}\n\n// ── 車両ピッカー ──────────────────────────────────────────\nlet _vpickerDriverId = null;\nfunction openVehiclePicker(driverId, currentVid) {\n  _vpickerDriverId = driverId;\n  const sel = document.getElementById('vpicker-select');\n  sel.innerHTML = '<option value=\"\">— 未選択 —</option>' +\n    vehicles.map(v => {\n      const lbl = `${haishaVnumLabel(v)}　${v.payload}kg`;\n      const selected = String(currentVid) === String(v.id) ? 'selected' : '';\n      return `<option value=\"${v.id}\" ${selected}>${lbl}</option>`;\n    }).join('');\n  const ov = document.getElementById('vpicker-overlay');\n  ov.style.display = 'flex';\n}\nfunction closeVehiclePicker() {\n  document.getElementById('vpicker-overlay').style.display = 'none';\n  _vpickerDriverId = null;\n}\nfunction applyVehiclePicker() {\n  const vid = document.getElementById('vpicker-select').value;\n  if (_vpickerDriverId !== null) haishaSetVehicle(_vpickerDriverId, vid);\n  closeVehiclePicker();\n}\n\nfunction renderHaisha() {\n  try { _renderHaishaInner(); } catch(e) {\n    console.error('renderHaisha error:', e);\n    const tbody = document.getElementById('haisha-tbody');\n    if (tbody) tbody.innerHTML = `<tr><td colspan=\"10\" style=\"color:red;padding:20px\">エラー: ${e.message}</td></tr>`;\n  }\n}\nfunction _renderHaishaInner() {\n  const date = document.getElementById('haisha-date').value;\n  if (!date) return;\n\n  // 日付が変わったらvehicleMapをリセット（古い日付の割当が残らないように）\n  if (haishaDateVal !== date) {\n    haishaVehicleMap = {};\n  }\n  haishaDateVal = date;\n\n  // 積置き分：前日以前に積んで当日下ろし\n  const preloaded = schedules.filter(s => s.unload_date === date && s.load_date < date);\n  // 配達：当日積み込み＆当日下ろし（翌日以降に下ろすものは明日以降の積置き分扱い）\n  const deliveries = schedules.filter(s => s.load_date === date && s.unload_date === date);\n\n  // 車両割当を初期化：① スケジュール実績 → ② ドライバーのデフォルト車両 の優先順\n  drivers.forEach(d => {\n    const did = String(d.id);\n    if (!haishaVehicleMap[did]) {\n      // まずそのドライバーのスケジュール実績から\n      const fromSched = [...preloaded, ...deliveries].find(s => String(s.driver_id) === did && s.vehicle_id);\n      if (fromSched) {\n        haishaVehicleMap[did] = String(fromSched.vehicle_id);\n      } else if (d.default_vehicle_id) {\n        // なければドライバーに登録されたデフォルト車両\n        haishaVehicleMap[did] = String(d.default_vehicle_id);\n      }\n    }\n  });\n\n  // 未割当（当日関係の仕事でドライバー未設定）\n  // 配車表で表示されているドライバーIDのセット（haisha_visible かつ 休みでない）\n  const visibleDriverIds = new Set(\n    drivers\n      .filter(d => {\n        const sid = String(d.id);\n        const isSpot = (spotVisibleData[date] || []).includes(sid);\n        const isVisible = d.haisha_visible !== false || isSpot;\n        const isDayOff = (dayOffData[date] || []).includes(sid);\n        return isVisible && !isDayOff;\n      })\n      .map(d => String(d.id))\n  );\n  // 傭車IDのセット\n  const youshaKeys = new Set(youshas.map(y => `y_${y.id}`));\n\n  // 未割当：① driver_idが空、または ② 配車表に表示されないドライバーに割り当てられている\n  const unassigned = [...deliveries, ...preloaded].filter(s => {\n    if (!s.driver_id || s.driver_id === '') return true;\n    const did = String(s.driver_id);\n    // 傭車は傭車行で表示されるので除外\n    if (youshaKeys.has(did)) return false;\n    // 配車表に出ていないドライバー（非表示 or 休み）はプールへ\n    return !visibleDriverIds.has(did);\n  });\n\n  // 未割当プール（相積みグループはまとめて表示）\n  const uWrap = document.getElementById('haisha-unassigned-wrap');\n  const uPool = document.getElementById('haisha-pool');\n  uWrap.style.display = '';\n  if (unassigned.length) {\n    const aitsuGroups = {};\n    const normalPool = [];\n    for (const s of unassigned) {\n      if (s.ai_tsumi && s.ai_tsumi_group) {\n        if (!aitsuGroups[s.ai_tsumi_group]) aitsuGroups[s.ai_tsumi_group] = [];\n        aitsuGroups[s.ai_tsumi_group].push(s);\n      } else {\n        normalPool.push(s);\n      }\n    }\n    const normalHtml = normalPool.map(s => haishaCardHTML(s, 'pool')).join('');\n    const aitsuHtml  = Object.values(aitsuGroups).map(grp => haishaAitsumiCardHTML(grp)).join('');\n    uPool.innerHTML = normalHtml + aitsuHtml;\n  } else {\n    uPool.innerHTML = '<span class=\"haisha-pool-empty\">ここにドロップして未割当に戻す</span>';\n  }\n\n  // haisha_visible=true のドライバー、または当日スポット表示中のドライバーを display_order 順で表示\n  const spotIds = spotVisibleData[date] || [];\n  const seenDriverIds = drivers\n    .filter(d => d.haisha_visible !== false || spotIds.includes(String(d.id)))\n    .sort((a, b) => (a.display_order ?? 999) - (b.display_order ?? 999))\n    .map(d => String(d.id));\n\n  const tbody = document.getElementById('haisha-tbody');\n\n  // ドライバー行（display_order 順）\n  const driverRowsHtml = seenDriverIds.map(did => {\n    const driver = drivers.find(d => String(d.id) === did);\n    if (!driver) return '';\n    const dPre = preloaded.filter(s => String(s.driver_id) === did);\n    const dDel = deliveries.filter(s => String(s.driver_id) === did);\n\n    // 休みチェック\n    const isDayOff = (dayOffData[date] || []).includes(did);\n    // スポット表示チェック（通常は非表示のドライバーが当日だけ表示）\n    const isSpot = (spotVisibleData[date] || []).includes(did);\n\n    const currentVid = haishaVehicleMap[did] || (dDel[0] || dPre[0])?.vehicle_id || '';\n    const vehicle = vehicles.find(v => String(v.id) === String(currentVid));\n    const payload = vehicle\n      ? Number(parseFloat(vehicle.payload) || 0).toLocaleString('ja-JP')\n      : '—';\n    const vnumHtml = vehicle ? haishaVnumShort(vehicle) : `<span style=\"color:#555\">—</span>`;\n    const name = driver.name.replace(/\\s+/g, '');\n\n    // スポットドライバーにはスポットバッジ＋解除ボタン、通常ドライバーには休みボタン\n    const dayOffBtn = isSpot\n      ? `<span style=\"margin-left:6px;font-size:10px;padding:2px 6px;border-radius:4px;border:1px solid #7c3aed;background:rgba(124,58,237,0.15);color:#a78bfa;font-weight:700;\">📍スポット</span>\n         <button style=\"margin-left:4px;font-size:10px;padding:2px 6px;border-radius:4px;border:1px solid #555;background:#1a1a1a;color:#888;cursor:pointer;\"\n           onclick=\"removeSpotVisible('${did}','${date}')\" title=\"スポット表示を解除\">✕</button>`\n      : `<button\n          style=\"margin-left:6px;font-size:10px;padding:2px 6px;border-radius:4px;border:1px solid ${isDayOff ? '#dc2626' : '#555'};background:${isDayOff ? 'rgba(239,68,68,0.12)' : '#1a1a1a'};color:${isDayOff ? '#dc2626' : '#888'};cursor:pointer;font-weight:700;\"\n          onclick=\"toggleDayOff('${did}','${date}')\"\n          title=\"${isDayOff ? '休みを解除' : '休みにする'}\"\n        >${isDayOff ? '✕ 休み中' : '休み'}</button>`;\n\n    // 積置き分も相積みグルーピング\n    const dPreAitsu  = dPre.filter(s => s.ai_tsumi);\n    const dPreNormal = dPre.filter(s => !s.ai_tsumi);\n    let preInner = isDayOff ? '' : dPreNormal.map(s => haishaCardHTML(s, 'preloaded')).join('');\n    if (!isDayOff && dPreAitsu.length) preInner += haishaAitsumiCardHTML(dPreAitsu, 'preloaded');\n\n    // 相積み分は1枠にまとめ、通常分は個別スロットへ\n    const dDelAitsu  = dDel.filter(s => s.ai_tsumi);\n    const dDelNormal = dDel.filter(s => !s.ai_tsumi);\n\n    const slotLabels = ['配達①','配達②','配達③','配達④','配達⑤'];\n    // slot_index が付いているものを優先配置、ないものは左から埋める\n    const slotMap = Array.from({length: 5}, () => []);\n    const unslotted = [];\n    if (!isDayOff) {\n      for (const s of dDelNormal) {\n        const si = s.slot_index;\n        if (si != null && si >= 0 && si < 5) slotMap[si].push(s);\n        else unslotted.push(s);\n      }\n      let ui = 0;\n      for (const s of unslotted) {\n        slotMap[Math.min(ui++, 4)].push(s);\n      }\n      if (dDelAitsu.length) {\n        const emptyIdx = slotMap.findIndex(arr => arr.length === 0);\n        if (emptyIdx >= 0) slotMap[emptyIdx] = [{ _aitsu: dDelAitsu }];\n        else slotMap[4].push({ _aitsu: dDelAitsu });\n      }\n    }\n\n    const rowStyle = isDayOff ? 'opacity:0.45;background:#1a1a1a;' : '';\n\n    const delCells = [0,1,2,3,4].map(i => {\n      let inner = '';\n      if (!isDayOff) {\n        inner = slotMap[i].map(item => {\n          if (item._aitsu) return haishaAitsumiCardHTML(item._aitsu);\n          return haishaCardHTML(item, 'delivery');\n        }).join('');\n      }\n      return `<td class=\"haisha-drop-cell\" style=\"${isDayOff ? 'pointer-events:none;' : ''}\"\n                ${isDayOff ? '' : `ondragover=\"hDragOver(event)\" ondragleave=\"hDragLeave(event)\" ondrop=\"hDrop(event,'${did}',${i})\"`}>\n                <span class=\"slot-label\">${slotLabels[i]}</span>\n                ${inner}\n              </td>`;\n    }).join('');\n\n    const cargoNotes = [...dPre, ...dDel].map(s => s.cargo_note).filter(Boolean).join(' / ');\n    const noteText   = [...dPre, ...dDel].map(s => s.note).filter(Boolean).join(' / ');\n    const note = [cargoNotes ? `<span style=\"color:#0891b2;font-weight:600\">${cargoNotes}</span>` : '', noteText].filter(Boolean).join('<br>');\n\n    return `<tr style=\"${rowStyle}\">\n      <td style=\"font-weight:700;white-space:nowrap;padding:10px 12px\">\n        ${name}${dayOffBtn}\n      </td>\n      <td style=\"white-space:nowrap;padding:10px 12px;font-size:13px;${isDayOff ? '' : 'cursor:pointer'}\"\n          ${isDayOff ? '' : `title=\"クリックで車両変更\" onclick=\"openVehiclePicker('${did}','${currentVid}')\"`}>\n        ${isDayOff ? '<span style=\"color:#555\">—</span>' : vnumHtml}\n      </td>\n      <td style=\"text-align:right;font-weight:600;white-space:nowrap;padding:10px 12px\">${isDayOff ? '—' : (payload ? payload+'kg' : '—')}</td>\n      <td class=\"haisha-drop-cell\" style=\"${isDayOff ? 'pointer-events:none;' : ''}\"\n          ${isDayOff ? '' : `ondragover=\"hDragOver(event)\" ondragleave=\"hDragLeave(event)\" ondrop=\"hDropToPreloaded(event,'${did}')\"`}>\n        <span class=\"slot-label\">積置き分</span>\n        ${preInner}\n      </td>\n      ${delCells}\n      <td style=\"padding:8px 12px;font-size:12px;color:var(--text-sub)\">${isDayOff ? '' : note}</td>\n    </tr>`;\n  }).join('');\n\n  // 傭車行（display_order に従い挿入）\n  const youshaRowsHtml = youshas\n    .sort((a, b) => (a.display_order ?? 999) - (b.display_order ?? 999))\n    .map(y => {\n      const ykey = `y_${y.id}`;\n      const yPre = preloaded.filter(s => s.driver_id === ykey);\n      const yDel = deliveries.filter(s => s.driver_id === ykey);\n      const payloadKg = Number(parseFloat(y.payload || '0') || 0).toLocaleString('ja-JP');\n\n      // 積置き分も相積みグルーピング\n      const yPreAitsu  = yPre.filter(s => s.ai_tsumi);\n      const yPreNormal = yPre.filter(s => !s.ai_tsumi);\n      let preHtml = yPreNormal.map(s => haishaCardHTML(s, 'preloaded')).join('');\n      if (yPreAitsu.length) preHtml += haishaAitsumiCardHTML(yPreAitsu, 'preloaded');\n\n      // 通常ドライバーと同じ相積みグルーピング\n      const yDelAitsu  = yDel.filter(s => s.ai_tsumi);\n      const yDelNormal = yDel.filter(s => !s.ai_tsumi);\n      const ySlotMap = Array.from({length: 5}, () => []);\n      const yUnslotted = [];\n      for (const s of yDelNormal) {\n        const si = s.slot_index;\n        if (si != null && si >= 0 && si < 5) ySlotMap[si].push(s);\n        else yUnslotted.push(s);\n      }\n      let yui = 0;\n      for (const s of yUnslotted) {\n        ySlotMap[Math.min(yui++, 4)].push(s);\n      }\n      if (yDelAitsu.length) {\n        const emptyIdx = ySlotMap.findIndex(arr => arr.length === 0);\n        if (emptyIdx >= 0) ySlotMap[emptyIdx] = [{ _aitsu: yDelAitsu }];\n        else ySlotMap[4].push({ _aitsu: yDelAitsu });\n      }\n\n      const slotLabels = ['配達①','配達②','配達③','配達④','配達⑤'];\n      const delCells = [0,1,2,3,4].map(i => {\n        const inner = ySlotMap[i].map(item => {\n          if (item._aitsu) return haishaAitsumiCardHTML(item._aitsu);\n          return haishaCardHTML(item, 'delivery');\n        }).join('');\n        return `<td class=\"haisha-drop-cell\"\n                  ondragover=\"hDragOver(event)\"\n                  ondragleave=\"hDragLeave(event)\"\n                  ondrop=\"hDrop(event,'${ykey}',${i})\">\n                  <span class=\"slot-label\">${slotLabels[i]}</span>\n                  ${inner}\n                </td>`;\n      }).join('');\n\n      const yCargoNotes = [...yPre, ...yDel].map(s => s.cargo_note).filter(Boolean).join(' / ');\n      const yNoteText   = [...yPre, ...yDel].map(s => s.note).filter(Boolean).join(' / ');\n      const note = [yCargoNotes ? `<span style=\"color:#0891b2;font-weight:600\">${yCargoNotes}</span>` : '', yNoteText].filter(Boolean).join('<br>');\n      const vnumLines = (y.vehicle_number || y.vehicle_info || '').includes('/')\n        ? (y.vehicle_number || y.vehicle_info || '').split('/').map((n,i) =>\n            `<span style=\"display:block;${i===0?'font-weight:700':'color:var(--text-sub)'}\">${n.trim()}</span>`\n          ).join('')\n        : `<span style=\"font-weight:700\">${(y.vehicle_number || y.vehicle_info || '')}</span>`;\n\n      return `<tr style=\"background:#1a1a0a\">\n        <td style=\"font-weight:700;white-space:nowrap;padding:10px 12px;font-size:13px\">\n          ${y.display_name}<br><span style=\"font-size:11px;font-weight:400;color:var(--text-sub)\">傭車</span>\n        </td>\n        <td style=\"white-space:nowrap;padding:10px 12px;font-size:13px\">${vnumLines}</td>\n        <td style=\"text-align:right;font-weight:600;white-space:nowrap;padding:10px 12px\">${payloadKg ? payloadKg+'kg' : '—'}</td>\n        <td class=\"haisha-drop-cell\"\n            ondragover=\"hDragOver(event)\"\n            ondragleave=\"hDragLeave(event)\"\n            ondrop=\"hDropToPreloaded(event,'${ykey}')\">\n          <span class=\"slot-label\">積置き分</span>\n          ${preHtml}\n        </td>\n        ${delCells}\n        <td style=\"padding:8px 12px;font-size:12px;color:var(--text-sub)\">${note}</td>\n      </tr>`;\n    }).join('');\n\n  // 空き行3行（手打ち入力）\n  const emptyRowsHtml = [0,1,2].map(i => {\n    const uid = `__empty_${i}`;\n    const t = haishaTextMap[uid] || {};\n    const delCells = [0,1,2,3].map(() =>\n      `<td class=\"haisha-drop-cell\"\n           ondragover=\"hDragOver(event)\"\n           ondragleave=\"hDragLeave(event)\"\n           ondrop=\"hDropEmpty(event,'${uid}')\"></td>`\n    ).join('');\n    return `<tr style=\"background:#111\">\n      <td style=\"padding:6px 8px;min-width:80px\">\n        <input class=\"haisha-inp\" type=\"text\" placeholder=\"ドライバー名\"\n               value=\"${t.name || ''}\"\n               oninput=\"haishaTextSave('${uid}','name',this.value)\">\n      </td>\n      <td style=\"padding:6px 8px;min-width:90px\">\n        <input class=\"haisha-inp\" type=\"text\" placeholder=\"車番\"\n               value=\"${t.vehicleNum || ''}\"\n               oninput=\"haishaTextSave('${uid}','vehicleNum',this.value)\">\n      </td>\n      <td style=\"padding:6px 8px;min-width:70px\">\n        <input class=\"haisha-inp\" type=\"text\" placeholder=\"積載量(kg)\"\n               value=\"${t.payload || ''}\"\n               oninput=\"haishaTextSave('${uid}','payload',this.value)\"\n               style=\"text-align:right\">\n      </td>\n      <td style=\"padding:6px 8px\"></td>\n      ${delCells}\n      <td style=\"padding:8px 12px\"></td>\n    </tr>`;\n  }).join('');\n\n  tbody.innerHTML = driverRowsHtml + youshaRowsHtml + emptyRowsHtml;\n}\n\n// 相積みカード（複数スケジュールを1枚にまとめて表示）\nfunction haishaAitsumiCardHTML(schedList, type='delivery') {\n  const groupId = schedList[0]?.ai_tsumi_group || '';\n  const ids = JSON.stringify(schedList.map(s=>s.id));\n  // 積置き分タイプは黄色ベース\n  const isPreloadedType = type === 'preloaded' || schedList.some(s => s.load_date < s.unload_date);\n  const st = schedList[0]?.load_status || '';\n  const stLabel = st === 'loaded' ? '積込完了' : st === 'delivered' ? '荷下ろし完了' : '未積み込み';\n  const stBadgeCls = st === 'loaded' ? 'st-loaded' : st === 'delivered' ? 'st-delivered' : 'st-none';\n  // カード全体の背景色：ステータスが優先（黄色ベースの上にst-loaded/deliveredが重なる）\n  const baseCls = isPreloadedType ? 'haisha-card preloaded' : 'haisha-card';\n  const stCardCls = st === 'loaded' ? ' st-loaded' : st === 'delivered' ? ' st-delivered' : '';\n  const cardCls = baseCls + stCardCls;\n\n  const totalWeight = schedList.reduce((sum, s) => sum + (parseFloat(s.weight) || 0), 0);\n  const totalStr = totalWeight > 0 ? (Math.round(totalWeight * 10) / 10) + 'kg' : '';\n\n  // 積載量オーバーチェック（グループ合計 vs 車両上限）\n  const aitsuVehicle = vehicles.find(v => String(v.id) === String(schedList[0]?.vehicle_id));\n  const aitsuPayload = parseFloat(aitsuVehicle?.payload);\n  const aitsuOver = totalWeight > 0 && !isNaN(aitsuPayload) && totalWeight > aitsuPayload;\n\n  const rows = schedList.map(s =>\n    `<div style=\"padding:2px 0;border-bottom:1px solid #e8ecf4\">\n      <div style=\"display:flex;align-items:center;gap:4px\">\n        <span style=\"font-size:11px;color:#888;min-width:14px\">▸</span>\n        <span style=\"font-weight:600;font-size:12px;flex:1\">${s.load_place||'?'} → ${s.unload_place||'?'}</span>\n        ${s.weight ? `<span style=\"font-size:11px;color:#666;font-weight:600\">${s.weight}kg</span>` : '<span style=\"font-size:11px;color:#555\">—</span>'}\n      </div>\n      ${s.cargo_note ? `<div style=\"font-size:10px;color:#0891b2;font-weight:600;padding-left:18px\">${s.cargo_note}</div>` : ''}\n    </div>`\n  ).join('');\n\n  const totalRow = totalStr\n    ? `<div style=\"display:flex;justify-content:flex-end;align-items:center;gap:6px;padding-top:3px;\">\n        ${aitsuOver ? `<span style=\"font-size:10px;font-weight:700;color:#dc2626\">⚠️ 積載量オーバー</span>` : ''}\n        <span style=\"font-size:11px;font-weight:700;color:${aitsuOver ? '#dc2626' : '#3730a3'}\">合計 ${totalStr}</span>\n       </div>`\n    : '';\n\n  return `<div class=\"${cardCls}\" draggable=\"true\"\n    style=\"flex-direction:column;align-items:stretch;gap:0;padding:6px 10px;cursor:grab;min-width:160px;${aitsuOver ? 'border-color:#dc2626 !important;background:rgba(239,68,68,0.15) !important;' : ''}\"\n    ondragstart=\"hDragStartGroup(event,'${groupId}')\"\n    ondragend=\"hDragEnd(event);this._dragged=true;setTimeout(()=>{this._dragged=false},200)\"\n    onclick=\"if(!this._dragged)openAitsumiDetail(JSON.parse(this.dataset.ids));else this._dragged=false;\"\n    data-ids='${ids}'>\n    <div style=\"display:flex;align-items:center;gap:6px;margin-bottom:4px\">\n      <span style=\"font-size:10px;font-weight:700;background:rgba(79,126,248,0.2);color:#93b5ff;padding:2px 6px;border-radius:4px\">🔀 相積み</span>\n      <span style=\"font-size:11px;color:#999\">${schedList.length}件</span>\n      <span class=\"c-status ${stBadgeCls}\" title=\"クリックでステータス変更\"\n        onclick=\"event.stopPropagation();toggleGroupStatus('${groupId}')\"\n        ondragstart=\"event.stopPropagation()\">${stLabel}</span>\n    </div>\n    ${rows}\n    ${totalRow}\n  </div>`;\n}\n\nfunction openAitsumiDetail(ids) {\n  const list = ids.map(id => schedules.find(s => s.id === id)).filter(Boolean);\n  if (!list.length) return;\n  const totalWeight = list.reduce((sum, s) => sum + (parseFloat(s.weight) || 0), 0);\n  const totalStr = totalWeight > 0 ? (Math.round(totalWeight * 10) / 10) + 'kg' : null;\n\n  const rows = list.map(s => {\n    const unloadPlace = places.find(p => p.name === s.unload_place);\n    const caution = unloadPlace?.caution\n      ? `<div style=\"font-size:11px;color:#b45309;background:rgba(245,158,11,0.12);border-radius:4px;padding:2px 6px;margin-top:2px\">⚠️ ${unloadPlace.caution}</div>`\n      : '';\n    const cargoNoteStr = s.cargo_note ? `<div style=\"font-size:11px;color:#0891b2;font-weight:600;margin-top:2px\">📦 ${s.cargo_note}</div>` : '';\n    const noteStr = s.note ? `<div style=\"font-size:11px;color:#888;margin-top:2px\">📝 ${s.note}</div>` : '';\n    return `<div style=\"padding:8px 0;border-bottom:1px solid #333\">\n      <div style=\"display:flex;align-items:center;gap:8px;font-size:13px;font-weight:600\">\n        <span style=\"color:#bbb\">${s.load_place||'?'}</span>\n        <span style=\"color:#666\">→</span>\n        <span style=\"flex:1\">${s.unload_place||'?'}</span>\n        <span style=\"font-size:14px;font-weight:700;color:#93b5ff;white-space:nowrap\">${s.weight ? s.weight + 'kg' : '<span style=\"color:#555;font-weight:400\">—</span>'}</span>\n        <button style=\"font-size:11px;padding:2px 8px;border-radius:4px;border:1px solid #555;background:#1a1a1a;color:#aaa;cursor:pointer\"\n          onclick=\"document.getElementById('card-detail-overlay').style.display='none';editSched('${s.id}')\">編集</button>\n      </div>\n      ${cargoNoteStr}\n      ${noteStr}\n      ${caution}\n    </div>`;\n  }).join('');\n\n  const groupId = list[0]?.ai_tsumi_group || '';\n  const st = list[0]?.load_status || '';\n  const stLabel = st === 'loaded' ? '積込完了' : st === 'delivered' ? '荷下ろし完了' : '未積み込み';\n  const stBadgeCls = st === 'loaded' ? 'st-loaded' : st === 'delivered' ? 'st-delivered' : 'st-none';\n  const statusBtn = groupId\n    ? `<span class=\"c-status ${stBadgeCls}\" style=\"cursor:pointer;font-size:13px;padding:4px 12px\"\n         title=\"クリックでステータス変更\"\n         onclick=\"toggleGroupStatus('${groupId}').then(()=>{ document.getElementById('card-detail-overlay').style.display='none'; })\">\n         ${stLabel} 🔄</span>`\n    : '';\n\n  document.getElementById('card-detail-content').innerHTML = `\n    <div style=\"display:flex;align-items:center;gap:8px;margin-bottom:18px\">\n      <h3 style=\"font-size:17px;font-weight:700;margin:0\">🔀 相積み</h3>\n      <span style=\"font-size:12px;color:#888\">${list.length}件</span>\n      ${totalStr ? `<span style=\"margin-left:auto;font-size:15px;font-weight:700;color:#3730a3\">合計 ${totalStr}</span>` : ''}\n    </div>\n    ${rows}\n    ${totalStr ? `<div style=\"display:flex;justify-content:flex-end;padding:10px 0 2px;font-size:14px;font-weight:700;color:#93b5ff;border-top:2px solid rgba(79,126,248,0.3);margin-top:2px\">合計重量：${totalStr}</div>` : ''}\n    <div style=\"margin-top:14px;padding-top:14px;border-top:1px solid #333;display:flex;align-items:center;gap:12px;flex-wrap:wrap\">\n      <div>\n        <div style=\"font-size:12px;color:#888;margin-bottom:8px\">ステータス（クリックで変更）</div>\n        ${statusBtn}\n      </div>\n      <button class=\"btn btn-primary btn-sm\" style=\"margin-left:auto\"\n        onclick=\"document.getElementById('card-detail-overlay').style.display='none';editAitsumiGroup('${groupId}')\">\n        🔀 相積み全体を編集\n      </button>\n    </div>`;\n  document.getElementById('card-detail-overlay').style.display = 'flex';\n}\n\nfunction editAitsumiGroup(groupId) {\n  const grp = schedules.filter(s => s.ai_tsumi_group === groupId);\n  if (!grp.length) return;\n  const first = grp[0];\n  // まずモーダルを通常オープン（車両/ドライバー選択肢を初期化）\n  openModal('schedule');\n  // 相積みモードに切り替え\n  if (!_aitsuMode) toggleAitsumi();\n  // フィールドをセット\n  setTimeout(() => {\n    document.getElementById('at-client-name').value = first.client_name || '';\n    document.getElementById('at-load-date').value = first.load_date || '';\n    document.getElementById('at-unload-date').value = first.unload_date || '';\n    document.getElementById('at-vehicle').value = first.vehicle_id || '';\n    document.getElementById('at-driver').value = first.driver_id || '';\n    // 既存行をセット\n    const rowsDiv = document.getElementById('at-rows');\n    rowsDiv.innerHTML = '';\n    grp.forEach(s => {\n      addAitsuRow();\n      const el = rowsDiv.lastElementChild;\n      const idx = el.id.replace('at-row-', '');\n      if (document.getElementById(`at-load-${idx}`)) document.getElementById(`at-load-${idx}`).value = s.load_place || '';\n      if (document.getElementById(`at-unload-${idx}`)) document.getElementById(`at-unload-${idx}`).value = s.unload_place || '';\n      if (document.getElementById(`at-weight-${idx}`)) document.getElementById(`at-weight-${idx}`).value = s.weight || '';\n      if (document.getElementById(`at-cargo-${idx}`)) document.getElementById(`at-cargo-${idx}`).value = s.cargo_note || '';\n    });\n    editId.schedule = '__aitsu_edit__';\n    window._editAitsuGroupId = groupId;\n    document.getElementById('s-modal-title').textContent = '相積み編集';\n  }, 50);\n}\n\n// saveScheduleの相積みモードを拡張: 編集時は既存グループを削除してから再作成\nconst _origSaveSchedule = saveSchedule;\n\nfunction haishaCardHTML(s, type) {\n  const st = s.load_status || '';\n  // 積置き分タイプ（前日積み）は場所に関わらず常に黄色ベース\n  const isPreloadedType = s.load_date < s.unload_date;\n  const baseCls = (type === 'preloaded' || isPreloadedType) ? 'haisha-card preloaded' : 'haisha-card';\n  const stCls = st === 'loaded' ? ' st-loaded' : st === 'delivered' ? ' st-delivered' : '';\n  const cls = baseCls + stCls;\n\n  const stLabel = st === 'loaded' ? '積込完了' : st === 'delivered' ? '荷下ろし完了' : '未積み込み';\n  const stBadgeCls = st === 'loaded' ? 'st-loaded' : st === 'delivered' ? 'st-delivered' : 'st-none';\n  const statusBadge = `<span class=\"c-status ${stBadgeCls}\"\n    title=\"クリックでステータス変更\"\n    onclick=\"event.stopPropagation();toggleLoadStatus('${s.id}')\"\n    ondragstart=\"event.stopPropagation()\">${stLabel}</span>`;\n\n  // 複数荷物があれば分割ボタンを表示\n  const items = parseSplitItems(s);\n  const splitBtn = items.length > 1\n    ? `<button title=\"配達を分割\" onclick=\"event.stopPropagation();openSplit('${s.id}')\"\n         style=\"background:none;border:none;cursor:pointer;font-size:13px;padding:0 0 0 4px;line-height:1;color:#666\"\n         ondragstart=\"event.stopPropagation()\">✂️</button>`\n    : '';\n  const cargoTag = s.cargo_note\n    ? `<span style=\"display:block;font-size:10px;color:#0891b2;font-weight:600;margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:100%\">${s.cargo_note}</span>`\n    : '';\n  // 積載量オーバーチェック（この1件の重量 vs 車両の最大積載量）\n  const cardVehicle = vehicles.find(v => String(v.id) === String(s.vehicle_id));\n  const cardWeight  = parseFloat(s.weight);\n  const cardPayload = parseFloat(cardVehicle?.payload);\n  const overweight  = !isNaN(cardWeight) && !isNaN(cardPayload) && cardWeight > cardPayload;\n  const overTag = overweight\n    ? `<span style=\"display:block;font-size:10px;font-weight:700;color:#dc2626;margin-top:1px\">⚠️ 積載量オーバー ${Math.round(cardWeight).toLocaleString('ja-JP')}kg</span>`\n    : '';\n  return `<div class=\"${cls}\" draggable=\"true\" data-id=\"${s.id}\"\n    style=\"${overweight ? 'border-color:#dc2626 !important;background:rgba(239,68,68,0.15) !important;' : ''}\"\n    ondragstart=\"hDragStart(event,'${s.id}')\"\n    ondragend=\"hDragEnd(event);this._dragged=true;setTimeout(()=>{this._dragged=false},200)\"\n    onclick=\"if(!this._dragged)openCardDetail('${s.id}');else this._dragged=false;\">\n    <span class=\"c-place\">${s.unload_place}</span>\n    ${s.weight ? `<span class=\"c-weight\">${s.weight}kg</span>` : ''}\n    ${statusBadge}\n    ${splitBtn}\n    ${cargoTag}\n    ${overTag}\n  </div>`;\n}\n\n// ステータスを 未積み込み → 積み込み完了 → 荷下ろし完了 → 未積み込み で循環\nasync function toggleLoadStatus(id) {\n  const s = schedules.find(x => x.id === id);\n  if (!s) return;\n  const cycle = { '': 'loaded', 'none': 'loaded', 'loaded': 'delivered', 'delivered': 'none' };\n  const next = cycle[s.load_status || ''] || 'loaded';\n  const res = await fetch(`/api/schedules/${id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ load_status: next }),\n  });\n  if (res.ok) {\n    const saved = await res.json();\n    const idx = schedules.findIndex(x => x.id === id);\n    if (idx !== -1) schedules[idx] = saved;\n    renderHaisha();\n    renderSchedules();\n  }\n}\n\n// ── 荷物詳細ポップアップ ────────────────────────────────────\nfunction openCardDetail(id) {\n  const s = schedules.find(x => x.id === id);\n  if (!s) return;\n\n  const driver  = drivers.find(d => String(d.id) === String(s.driver_id));\n  const yousha  = !driver && String(s.driver_id || '').startsWith('y_')\n    ? youshas.find(y => `y_${y.id}` === String(s.driver_id)) : null;\n  const dName   = driver ? driver.name : yousha ? (yousha.display_name || yousha.name) + '（傭車）' : '未割当';\n  const vehicle = vehicles.find(v => String(v.id) === String(s.vehicle_id));\n  const vNum    = vehicle\n    ? (vehicle.kind === 'トレーラー' ? `${vehicle.head_number} / ${vehicle.trailer_number}` : vehicle.number)\n    : '未割当';\n\n  const stMap    = { '': '未積み込み', 'none': '未積み込み', 'loaded': '積込完了', 'delivered': '荷下ろし完了' };\n  const stColors = { '': '#93b5ff', 'none': '#93b5ff', 'loaded': '#4ade80', 'delivered': '#aaa' };\n  const stBg     = { '': 'rgba(79,126,248,0.2)', 'none': 'rgba(79,126,248,0.2)', 'loaded': 'rgba(34,197,94,0.2)', 'delivered': 'rgba(136,136,136,0.2)' };\n  const st = s.load_status || '';\n\n  // 下ろし場所・積み込み場所の注意事項\n  const unloadPlace = places.find(p => p.name === s.unload_place);\n  const loadPlace   = places.find(p => p.name === s.load_place);\n  const unloadCaution = unloadPlace?.caution || '';\n  const loadCaution   = loadPlace?.caution   || '';\n\n  const row = (label, val) => val\n    ? `<div style=\"display:flex;gap:8px;padding:8px 0;border-bottom:1px solid #333;font-size:14px\">\n        <span style=\"color:#888;min-width:90px;flex-shrink:0\">${label}</span>\n        <span style=\"font-weight:500\">${val}</span>\n       </div>` : '';\n\n  const cautionBox = (label, text) => text\n    ? `<div style=\"background:rgba(245,158,11,0.12);border:1px solid rgba(245,158,11,0.3);border-radius:8px;padding:10px 14px;margin-top:10px;font-size:13px\">\n        <div style=\"font-weight:700;color:#b45309;margin-bottom:4px\">⚠️ ${label}の注意事項</div>\n        <div style=\"color:#78350f;white-space:pre-wrap\">${text}</div>\n       </div>` : '';\n\n  document.getElementById('card-detail-content').innerHTML = `\n    <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:18px\">\n      <h3 style=\"font-size:18px;font-weight:700;margin:0\">${s.unload_place}</h3>\n      <span style=\"font-size:12px;font-weight:700;padding:3px 10px;border-radius:6px;\n        background:${stBg[st]};color:${stColors[st]}\">${stMap[st]}</span>\n    </div>\n    <div style=\"display:flex;gap:8px;padding:8px 0;border-bottom:1px solid #333;font-size:14px;align-items:center\">\n      <span style=\"color:#888;min-width:90px;flex-shrink:0\">荷主</span>\n      <input type=\"text\" value=\"${(s.client_name||'').replace(/\"/g,'&quot;')}\" placeholder=\"荷主名を入力\"\n        style=\"flex:1;background:transparent;border:none;border-bottom:1px dashed #555;color:#f5f5f5;font-size:14px;outline:none;padding:2px 4px\"\n        onblur=\"saveCardClientName('${s.id}',this.value)\" id=\"card-client-input\">\n    </div>\n    ${row('積み込み日', s.load_date)}\n    ${row('積み込み場所', s.load_place)}\n    ${row('下ろし日', s.unload_date)}\n    ${row('重量', s.weight ? s.weight + 'kg' : '')}\n    ${s.cargo_note ? `<div style=\"display:flex;gap:8px;padding:8px 0;border-bottom:1px solid #f3f3f3;font-size:14px\"><span style=\"color:#888;min-width:90px;flex-shrink:0\">荷物</span><span style=\"font-weight:600;color:#0891b2\">${s.cargo_note}</span></div>` : ''}\n    ${row('ドライバー', dName)}\n    ${row('車両', vNum)}\n    ${row('メモ', s.note)}\n    ${cautionBox(s.unload_place, unloadCaution)}\n    ${cautionBox(s.load_place, loadCaution)}\n    <div style=\"display:flex;justify-content:space-between;align-items:center;margin-top:18px;padding-top:14px;border-top:1px solid #333\">\n      <button class=\"btn btn-ghost btn-sm\" onclick=\"closeCardDetail();editSched('${s.id}')\">✏️ 編集</button>\n      <button class=\"btn btn-ghost btn-sm\" onclick=\"closeCardDetail();toggleLoadStatus('${s.id}')\">🔄 ステータス変更</button>\n      <button class=\"btn btn-danger btn-sm\" onclick=\"closeCardDetail();delSchedFromHaisha('${s.id}')\">🗑️ 削除</button>\n    </div>`;\n\n  document.getElementById('card-detail-overlay').style.display = 'flex';\n}\nasync function saveCardClientName(id, value) {\n  const cn = value.trim();\n  const s = schedules.find(x => x.id === id);\n  if (!s || cn === (s.client_name || '')) return;\n  await fetch(`/api/schedules/${id}`, {\n    method: 'PUT', headers: {'Content-Type':'application/json'},\n    body: JSON.stringify({ client_name: cn || null }),\n  });\n  // 同じルートの未設定スケジュールにも反映\n  if (cn && s.load_place && s.unload_place) {\n    const toUpdate = schedules.filter(x => x.id !== id && !x.client_name && x.load_place === s.load_place && x.unload_place === s.unload_place);\n    for (const x of toUpdate) {\n      await fetch(`/api/schedules/${x.id}`, { method: 'PUT', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ client_name: cn }) });\n    }\n  }\n  await loadAll();\n}\nfunction closeCardDetail() {\n  document.getElementById('card-detail-overlay').style.display = 'none';\n}\n\n// ── 車両制限チェック ──────────────────────────────────────\n// 大型車判定：トレーラー、または積載量8t以上のトラック\nfunction isLargeVehicle(vehicle) {\n  if (!vehicle) return false;\n  if (vehicle.kind === 'トレーラー') return true;\n  const p = parseFloat(vehicle.payload);\n  return !isNaN(p) && p >= 8000;\n}\n\n/**\n * スケジュールと車両の組み合わせで制限違反を返す\n * @param {object} sched - スケジュール（unload_place, weight）\n * @param {object|null} vehicle - 車両（kind, payload）\n * @returns {string[]} 違反メッセージ配列（空なら問題なし）\n */\nfunction checkVehicleViolations(sched, vehicle) {\n  const msgs = [];\n  if (!sched) return msgs;\n\n  const place = places.find(p => p.name === sched.unload_place);\n  const caution = place?.caution || '';\n\n  if (/トレーラー禁止/.test(caution) && vehicle?.kind === 'トレーラー') {\n    msgs.push(`「${sched.unload_place}」はトレーラー禁止`);\n  }\n  if (/大型禁止/.test(caution) && isLargeVehicle(vehicle)) {\n    msgs.push(`「${sched.unload_place}」は大型車禁止（${vehicle.kind} ${vehicle.payload}kg）`);\n  }\n\n  const weight  = parseFloat(sched.weight);\n  const payload = parseFloat(vehicle?.payload);\n  if (!isNaN(weight) && !isNaN(payload) && weight > payload) {\n    msgs.push(`積載量オーバー: 荷物 ${weight}kg > 車両上限 ${payload}kg`);\n  }\n\n  return msgs;\n}\n\n// ── ドラッグ＆ドロップ ──────────────────────────────────────\nfunction hDragStart(event, id) {\n  dragSchedId = id;\n  dragGroupId = null;\n  event.dataTransfer.effectAllowed = 'move';\n  // ドラッグ中はクリック詳細を抑制するフラグ\n  event.currentTarget._dragged = true;\n  setTimeout(() => { event.target.classList.add('dragging'); }, 0);\n}\nfunction hDragStartGroup(event, groupId) {\n  dragGroupId = groupId;\n  dragSchedId = null;\n  event.dataTransfer.effectAllowed = 'move';\n  event.currentTarget._dragged = true;\n  setTimeout(() => { event.target.classList.add('dragging'); }, 0);\n}\nfunction hDragEnd(event) {\n  event.target.classList.remove('dragging');\n  document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));\n}\nfunction hDragOver(event) {\n  event.preventDefault();\n  event.currentTarget.classList.add('drag-over');\n}\nfunction hDragLeave(event) {\n  event.currentTarget.classList.remove('drag-over');\n}\n\nasync function hDrop(event, driverId, slotIndex) {\n  event.preventDefault();\n  event.currentTarget.classList.remove('drag-over');\n\n  // 休みチェック\n  if ((dayOffData[haishaDateVal] || []).includes(String(driverId))) {\n    alert('このドライバーは休みです。配車できません。');\n    return;\n  }\n\n  const vehicleId = haishaVehicleMap[String(driverId)] || '';\n  // haishaVehicleMapにない場合はドライバーのdefault_vehicle_idをfallback\n  const driver    = drivers.find(d => String(d.id) === String(driverId));\n  const fallbackVid = vehicleId || String(driver?.default_vehicle_id || '');\n  const vehicle   = vehicles.find(v => String(v.id) === fallbackVid) || null;\n\n  // ── 相積みグループごと移動 ──────────────────────────────\n  if (dragGroupId) {\n    const grp = schedules.filter(s => s.ai_tsumi_group === dragGroupId);\n    // 制限チェック（グループ内全スケジュール）\n    const allMsgs = grp.flatMap(s => checkVehicleViolations(s, vehicle));\n    if (allMsgs.length) {\n      const ok = confirm('⚠️ 制限違反があります：\\n' + allMsgs.join('\\n') + '\\n\\nこのまま割り当てますか？');\n      if (!ok) return;\n    }\n    for (const s of grp) {\n      // 積置き分（load_date < 当日）を配達スロットへ移動する場合はload_dateを当日に修正\n      const grpFixedLoadDate = s.load_date < haishaDateVal ? haishaDateVal : s.load_date;\n      await fetch(`/api/schedules/${s.id}`, {\n        method: 'PUT', headers: {'Content-Type': 'application/json'},\n        body: JSON.stringify({ ...s, driver_id: String(driverId), vehicle_id: fallbackVid, load_date: grpFixedLoadDate }),\n      });\n    }\n    dragGroupId = null;\n    await loadAll(); renderHaisha();\n    return;\n  }\n\n  if (!dragSchedId) return;\n  const sched = schedules.find(s => s.id === dragSchedId);\n  if (!sched) return;\n\n  // 制限チェック（単体カード）\n  const singleMsgs = checkVehicleViolations(sched, vehicle);\n  if (singleMsgs.length) {\n    const ok = confirm('⚠️ 制限違反があります：\\n' + singleMsgs.join('\\n') + '\\n\\nこのまま割り当てますか？');\n    if (!ok) return;\n  } else if (vehicle && !sched.weight) {\n    // 重量未入力のため積載量チェック不能 → 注意喚起\n    const w = prompt(`「${sched.unload_place}」の重量が未入力です。\\n車両上限: ${Number(parseFloat(vehicle.payload)||0).toLocaleString('ja-JP')}kg\\n\\n重量(kg)を入力してください（スキップする場合は空欄のままOK）:`);\n    if (w !== null && w.trim() !== '') {\n      const updated = { ...sched, weight: w.trim() };\n      await fetch(`/api/schedules/${sched.id}`, {\n        method: 'PUT', headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify(updated),\n      });\n      schedules[schedules.findIndex(s => s.id === sched.id)] = updated;\n      // 入力後に再度チェック\n      const recheckMsgs = checkVehicleViolations({ ...sched, weight: w.trim() }, vehicle);\n      if (recheckMsgs.length) {\n        const ok = confirm('⚠️ 積載量オーバーです：\\n' + recheckMsgs.join('\\n') + '\\n\\nこのまま割り当てますか？');\n        if (!ok) return;\n      }\n    }\n  }\n\n  // 積置き分（load_date < haishaDateVal）→ 配達スロットに移動した場合、load_date を当日に修正\n  const fixedLoadDate = sched.load_date < haishaDateVal ? haishaDateVal : sched.load_date;\n\n  await fetch(`/api/schedules/${sched.id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ ...sched, driver_id: String(driverId), vehicle_id: fallbackVid, load_date: fixedLoadDate, slot_index: slotIndex ?? null }),\n  });\n  await loadAll();\n  renderHaisha();\n}\n\n// 配達 → 積置き分セルにドロップ（load_date を前日に修正）\nasync function hDropToPreloaded(event, driverId) {\n  event.preventDefault();\n  event.currentTarget.classList.remove('drag-over');\n\n  // 休みチェック\n  if ((dayOffData[haishaDateVal] || []).includes(String(driverId))) {\n    alert('このドライバーは休みです。配車できません。');\n    return;\n  }\n\n  const vehicleId = haishaVehicleMap[String(driverId)] || '';\n  const preDriver  = drivers.find(d => String(d.id) === String(driverId));\n  const preFallbackVid = vehicleId || String(preDriver?.default_vehicle_id || '');\n  const vehicle   = vehicles.find(v => String(v.id) === preFallbackVid) || null;\n  const d = new Date(haishaDateVal);\n  d.setDate(d.getDate() - 1);\n  const prevDay = d.toISOString().split('T')[0];\n\n  // ── 相積みグループごと積置きに移動（既存グループとマージ）──\n  if (dragGroupId) {\n    const grp = schedules.filter(s => s.ai_tsumi_group === dragGroupId);\n    // 制限チェック\n    const grpMsgs = grp.flatMap(s => checkVehicleViolations(s, vehicle));\n    if (grpMsgs.length) {\n      const ok = confirm('⚠️ 制限違反があります：\\n' + grpMsgs.join('\\n') + '\\n\\nこのまま割り当てますか？');\n      if (!ok) return;\n    }\n    // 既存の相積みと統合するか確認\n    const existingPre = schedules.filter(s =>\n      s.unload_date === haishaDateVal && s.load_date < haishaDateVal &&\n      String(s.driver_id) === String(driverId) && s.ai_tsumi &&\n      s.ai_tsumi_group !== dragGroupId\n    );\n    const masterGroupId = existingPre[0]?.ai_tsumi_group || dragGroupId;\n    // 既存グループを統合\n    for (const s of existingPre) {\n      if (s.ai_tsumi_group !== masterGroupId) {\n        await fetch(`/api/schedules/${s.id}`, {\n          method: 'PUT', headers: {'Content-Type': 'application/json'},\n          body: JSON.stringify({ ...s, ai_tsumi_group: masterGroupId }),\n        });\n      }\n    }\n    for (const s of grp) {\n      await fetch(`/api/schedules/${s.id}`, {\n        method: 'PUT', headers: {'Content-Type': 'application/json'},\n        body: JSON.stringify({ ...s, driver_id: String(driverId), vehicle_id: vehicleId, load_date: prevDay, unload_date: haishaDateVal, ai_tsumi_group: masterGroupId }),\n      });\n    }\n    dragGroupId = null;\n    await loadAll(); renderHaisha();\n    return;\n  }\n\n  if (!dragSchedId) return;\n  const sched = schedules.find(s => s.id === dragSchedId);\n  if (!sched) return;\n\n  // 制限チェック（単体）\n  const preSingleMsgs = checkVehicleViolations(sched, vehicle);\n  if (preSingleMsgs.length) {\n    const ok = confirm('⚠️ 制限違反があります：\\n' + preSingleMsgs.join('\\n') + '\\n\\nこのまま割り当てますか？');\n    if (!ok) return;\n  }\n\n  const vehicleIdSingle = vehicleId || sched.vehicle_id || '';\n\n  // 積置き分に既存の相積みカードがあれば自動マージ\n  const existingPreAitsu = schedules.filter(s =>\n    s.unload_date === haishaDateVal && s.load_date < haishaDateVal &&\n    String(s.driver_id) === String(driverId) && s.ai_tsumi && s.id !== sched.id\n  );\n  // 複数グループを1つに統合（異なるgroupIdが混在している場合も含む）\n  const allPreAitsu = [...existingPreAitsu];\n  if (sched.ai_tsumi) {\n    // ドロップカード自体も相積み → グループを統合\n    const masterGroupId = allPreAitsu[0]?.ai_tsumi_group || sched.ai_tsumi_group || `aitsu_${Date.now()}`;\n    for (const s of allPreAitsu) {\n      if (s.ai_tsumi_group !== masterGroupId) {\n        await fetch(`/api/schedules/${s.id}`, {\n          method: 'PUT', headers: {'Content-Type': 'application/json'},\n          body: JSON.stringify({ ...s, ai_tsumi_group: masterGroupId }),\n        });\n      }\n    }\n    await fetch(`/api/schedules/${sched.id}`, {\n      method: 'PUT', headers: {'Content-Type': 'application/json'},\n      body: JSON.stringify({ ...sched, driver_id: String(driverId), vehicle_id: vehicleIdSingle, load_date: prevDay, unload_date: haishaDateVal, ai_tsumi: true, ai_tsumi_group: masterGroupId }),\n    });\n    await loadAll(); renderHaisha();\n    return;\n  }\n\n  // 通常移動\n  await fetch(`/api/schedules/${sched.id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      ...sched,\n      driver_id: String(driverId),\n      vehicle_id: vehicleIdSingle,\n      load_date: prevDay,\n      unload_date: haishaDateVal,\n    }),\n  });\n  await loadAll();\n  renderHaisha();\n}\n\nasync function dropToPool(event) {\n  event.preventDefault();\n  document.getElementById('haisha-pool').classList.remove('drag-over');\n\n  // ── 相積みグループを未割り当てプールに戻す（グループは維持）──\n  if (dragGroupId) {\n    const grp = schedules.filter(s => s.ai_tsumi_group === dragGroupId);\n    for (const s of grp) {\n      await fetch(`/api/schedules/${s.id}`, {\n        method: 'PUT', headers: {'Content-Type': 'application/json'},\n        body: JSON.stringify({ ...s, driver_id: '', vehicle_id: '', slot_index: null }),\n      });\n    }\n    dragGroupId = null;\n    await loadAll(); renderHaisha();\n    return;\n  }\n\n  if (!dragSchedId) return;\n  const sched = schedules.find(s => s.id === dragSchedId);\n  if (!sched) return;\n  await fetch(`/api/schedules/${sched.id}`, {\n    method: 'PUT',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ ...sched, driver_id: '', vehicle_id: '', slot_index: null }),\n  });\n  await loadAll();\n  renderHaisha();\n}\n\n// ── 自動振り分け ──────────────────────────────────────────\nasync function autoAssignHaisha() {\n  const date = haishaDateVal;\n  if (!date) { alert('日付を選択してください'); return; }\n\n  const unassigned = schedules.filter(s =>\n    (!s.driver_id || s.driver_id === '') &&\n    (\n      (s.load_date === date && s.unload_date === date) ||   // 当日配達\n      (s.unload_date === date && s.load_date < date)        // 積置き分（前日以前に積んで当日下ろし）\n    )\n  );\n  if (!unassigned.length) { alert('未割当の仕事はありません'); return; }\n\n  // 当日すでに使われているドライバー・車両\n  const busyD = busyDriverIds(date, date);\n  const busyV = busyVehicleIds(date, date);\n  const dayOffIds = dayOffData[date] || [];\n  const freeDrivers = drivers.filter(d =>\n    d.status === '稼働中' &&\n    d.haisha_visible !== false &&\n    !dayOffIds.includes(String(d.id)) &&\n    !busyD.has(String(d.id))\n  );\n  const freeVehicles = vehicles.filter(v => !busyV.has(String(v.id)));\n\n  if (!freeDrivers.length) {\n    alert('空きドライバーがいません。手動で割り当ててください。');\n    return;\n  }\n\n  // ドライバーごとの車両を事前にマッピング\n  const driverVehicleMap = {};\n  for (const d of freeDrivers) {\n    const vid = haishaVehicleMap[String(d.id)] || '';\n    driverVehicleMap[d.id] = vehicles.find(v => String(v.id) === String(vid)) || null;\n  }\n\n  // 重量が大きい順にソート\n  const sorted = [...unassigned].sort((a, b) => parseFloat(b.weight || 0) - parseFloat(a.weight || 0));\n\n  const updates = [];\n  const failedItems = [];\n  const usedDriverIds = new Set();\n\n  for (const s of sorted) {\n    // 制限なし・積載量OK なドライバーを優先（積載量の大きい順）\n    const candidates = freeDrivers\n      .filter(d => !usedDriverIds.has(String(d.id)))\n      .map(d => ({ driver: d, vehicle: driverVehicleMap[d.id] }))\n      .filter(({ vehicle }) => checkVehicleViolations(s, vehicle).length === 0)\n      .sort((a, b) => parseFloat(b.vehicle?.payload || 0) - parseFloat(a.vehicle?.payload || 0));\n\n    if (candidates.length) {\n      const { driver, vehicle } = candidates[0];\n      updates.push({ ...s, driver_id: String(driver.id), vehicle_id: vehicle ? String(vehicle.id) : '' });\n      usedDriverIds.add(String(driver.id));\n    } else {\n      // 制限を満たすドライバーがいない → スキップして記録\n      failedItems.push(s);\n    }\n  }\n\n  if (!updates.length) {\n    alert('⚠️ 制限・積載量の条件を満たせるドライバーがいないため、自動振り分けできませんでした。\\n手動で割り当ててください。');\n    return;\n  }\n\n  await Promise.all(updates.map(u =>\n    fetch(`/api/schedules/${u.id}`, {\n      method: 'PUT',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify(u),\n    })\n  ));\n  await loadAll();\n  renderHaisha();\n\n  if (failedItems.length) {\n    const names = failedItems.map(s => `・${s.unload_place}（${s.weight || '?'}kg）`).join('\\n');\n    alert(`⚠️ 以下の仕事は制限・積載量の条件を満たせるドライバーがいないため、未割り当てのままです：\\n${names}\\n\\n手動で割り当ててください。`);\n  }\n}\n\nloadAll();\n</script></html>"

export async function GET() {
  const user = await getCurrentUser()
  if (!user) return new Response('Unauthorized', { status: 401 })
  return new Response(HTML, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
}
